def _bbox4(value):
    if not isinstance(value, list) or len(value) != 4:
        return None
    return [int(v) for v in value]


def _load_region_grow_module():
    module_path = TESTS_ROOT / "popelina_github" / "scripts" / "region_grow" / "region_grow" / "region_grow.py"
    module_name = "test_region_grow_runtime_contract"
    spec = importlib.util.spec_from_file_location(module_name, module_path)
    module = importlib.util.module_from_spec(spec)
    fake_paddleocr = types.SimpleNamespace(PaddleOCR=mock.Mock(name="PaddleOCR"))
    import numpy as _np

    def _fake_rect_kernel(_shape, ksize):
        return _np.ones((int(ksize[1]), int(ksize[0])), dtype=_np.uint8)

    def _fake_cvt_color(arr, _code):
        if getattr(arr, "ndim", 0) == 3:
            return arr.mean(axis=2).astype(_np.uint8)
        return arr

    def _fake_adaptive_threshold(gray, maxval, _adaptive, _thresh, _block, _c):
        return _np.where(gray < 200, maxval, 0).astype(_np.uint8)

    def _fake_find_contours(arr, _mode, _method):
        ys, xs = _np.where(arr > 0)
        if ys.size == 0 or xs.size == 0:
            return [], None
        x1, y1, x2, y2 = int(xs.min()), int(ys.min()), int(xs.max()), int(ys.max())
        contour = _np.array([[[x1, y1]], [[x2, y1]], [[x2, y2]], [[x1, y2]]], dtype=_np.int32)
        return [contour], None

    def _fake_bounding_rect(cnt):
        pts = _np.asarray(cnt).reshape(-1, 2)
        x1, y1 = pts.min(axis=0)
        x2, y2 = pts.max(axis=0)
        return int(x1), int(y1), int(x2 - x1), int(y2 - y1)

    def _fake_rectangle(img, pt1, pt2, color, thickness):
        x1, y1 = pt1
        x2, y2 = pt2
        if thickness == -1:
            img[y1:y2, x1:x2] = color
        return img

    fake_cv2 = types.SimpleNamespace(
        MORPH_RECT=0,
        COLOR_RGB2GRAY=0,
        ADAPTIVE_THRESH_MEAN_C=0,
        THRESH_BINARY_INV=0,
        THRESH_BINARY=0,
        THRESH_OTSU=0,
        NORM_MINMAX=0,
        INTER_CUBIC=0,
        RETR_EXTERNAL=0,
        CHAIN_APPROX_SIMPLE=0,
        getStructuringElement=_fake_rect_kernel,
        setUseOptimized=lambda *_a, **_k: None,
        setNumThreads=lambda *_a, **_k: None,
        cvtColor=_fake_cvt_color,
        GaussianBlur=lambda arr, *_a, **_k: arr,
        adaptiveThreshold=_fake_adaptive_threshold,
        dilate=lambda arr, *_a, **_k: arr,
        findContours=_fake_find_contours,
        boundingRect=_fake_bounding_rect,
        rectangle=_fake_rectangle,
        normalize=lambda arr, *_a, **_k: arr,
        threshold=lambda arr, *_a, **_k: (0, arr),
        resize=lambda arr, _size=None, fx=1, fy=1, interpolation=None: arr,
    )
    sys.modules[module_name] = module
    with mock.patch.dict(
        sys.modules,
        {
            "paddleocr": fake_paddleocr,
            "rapidocr_paddle": types.SimpleNamespace(RapidOCR=mock.Mock(name="RapidOCR")),
            "cv2": fake_cv2,
        },
        clear=False,
    ):
        with mock.patch.dict(os.environ, {"REGION_GROW_REQUIRE_GPU": "0", "REGION_GROW_USE_GPU": "0"}, clear=False):
            assert spec is not None and spec.loader is not None
            spec.loader.exec_module(module)
    return module


class RuntimeRefactorTests(unittest.TestCase):
    def test_ocr_runtime_config_from_env_reads_backend_chain(self) -> None:
        with mock.patch.dict(
            ocr_runtime_mod.os.environ,
            {
                "FULLBOT_OCR_BACKEND": "trt_int8",
                "FULLBOT_OCR_BACKEND_CHAIN": "trt_int8,gpu_fp32,cpu_fp32",
                "PADDLEOCR_LANG": "en",
                "PADDLEOCR_REC_BATCH": "8",
            },
            clear=False,
        ):
            cfg = ocr_runtime_mod.OcrRuntimeConfig.from_env()
        self.assertEqual(cfg.backend, "trt_int8")
        self.assertEqual(cfg.backend_chain, ("trt_int8", "gpu_fp32", "cpu_fp32"))
        self.assertEqual(cfg.lang, "en")
        self.assertEqual(cfg.rec_batch_num, 8)

    def test_ocr_runtime_init_is_lazy_until_ocr_call(self) -> None:
        cfg = ocr_runtime_mod.OcrRuntimeConfig(backend="cpu_fp32", warmup_runs=0)
        with mock.patch.object(ocr_runtime_mod.OcrRuntime, "_init_runtime") as init_mock:
            runtime = ocr_runtime_mod.OcrRuntime(cfg)
        self.assertFalse(runtime._runtime_ready)
        init_mock.assert_not_called()

    def test_ocr_runtime_backend_chain_prefers_explicit_config_chain(self) -> None:
        cfg = ocr_runtime_mod.OcrRuntimeConfig(
            backend="gpu_fp32",
            backend_chain=("cpu_fp32", "gpu_fp32", "cpu_fp32"),
            warmup_runs=0,
        )
        runtime = ocr_runtime_mod.OcrRuntime(cfg)
        self.assertEqual(runtime._backend_chain(), ["cpu_fp32", "gpu_fp32"])

    def test_ocr_runtime_ocr_triggers_lazy_init_once(self) -> None:
        cfg = ocr_runtime_mod.OcrRuntimeConfig(backend="cpu_fp32", warmup_runs=0)
        runtime = ocr_runtime_mod.OcrRuntime(cfg)
        runtime._pipeline_mode = "legacy"
        fake_reader = mock.Mock()
        fake_reader.ocr.return_value = [[("quad", ("txt", 0.9))]]

        def _fake_init() -> None:
            runtime._reader = fake_reader
            runtime.active_backend = "cpu_fp32"
            runtime.active_precision = "FP32"
            runtime._runtime_ready = True

        with mock.patch.object(runtime, "_init_runtime", side_effect=_fake_init) as init_mock:
            first = runtime.ocr("image", det=True, rec=True)
            second = runtime.ocr("image", det=True, rec=True)

        self.assertEqual(init_mock.call_count, 1)
        self.assertIsNotNone(first)
        self.assertIsNotNone(second)
        self.assertEqual(fake_reader.ocr.call_count, 2)

    def test_ocr_runtime_describe_reports_lazy_state_before_init(self) -> None:
        runtime = ocr_runtime_mod.OcrRuntime(
            ocr_runtime_mod.OcrRuntimeConfig(backend="trt_int8", warmup_runs=0, lang="pl")
        )
        desc = runtime.describe()
        self.assertIn("backend=trt_int8", desc)
        self.assertIn("state=lazy", desc)

    def test_benchmark_runtime_export_and_init_wrapper(self) -> None:
        runtime = mock.Mock()
        runtime.active_backend = "cpu_fp32"
        runtime.active_precision = "FP32"
        runtime.config.enable_cls = False
        runtime.ocr = mock.Mock(return_value=[])
        runtime._ensure_runtime = mock.Mock()

        result = exported_benchmark_runtime(runtime, images=[1, 2, 3])

        runtime._ensure_runtime.assert_called_once()
        self.assertEqual(result["samples"], 3)
        self.assertEqual(result["backend"], "cpu_fp32")

