    def test_element_role_classifier_build_explicit_model_selector_prefers_named_variant(self) -> None:
        with mock.patch.dict(
            os.environ,
            {
                "FULLBOT_ELEMENT_ROLE_MODEL_SELECTOR": "v1",
                "FULLBOT_ELEMENT_ROLE_MODEL_PATH": str(Path("custom_model.json")),
            },
            clear=False,
        ):
            selector = element_role_classifier_mod.build_explicit_model_selector()
        self.assertEqual(selector["selected_variant"], "v1")
        self.assertEqual(Path(selector["selected_path"]).name, "element_role_classifier_v1.json")
        self.assertEqual(selector["source"], "selector_env")
        self.assertTrue(selector["is_explicit"])

    def test_element_role_classifier_build_explicit_model_selector_uses_rollout_contract(self) -> None:
        tmp_dir = Path("tmp_test_element_role_rollout_selector")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            rollout_path = tmp_dir / "element_role_rollout.json"
            model_path = tmp_dir / "element_role_candidate.json"
            model_path.write_text("{}", encoding="utf-8")
            rollout_path.write_text(
                json.dumps({"release_family": "element_role_rollout", "selected_model_path": str(model_path)}, ensure_ascii=False),
                encoding="utf-8",
            )
            with mock.patch.dict(
                os.environ,
                {
                    "FULLBOT_ELEMENT_ROLE_MODEL_SELECTOR": "rollout",
                    "FULLBOT_ELEMENT_ROLE_MODEL_ROLLOUT_PATH": str(rollout_path),
                    "FULLBOT_ELEMENT_ROLE_MODEL_PATH": "",
                },
                clear=False,
            ):
                selector = element_role_classifier_mod.build_explicit_model_selector()
            self.assertEqual(selector["selected_variant"], "rollout")
            self.assertEqual(Path(selector["selected_path"]).resolve(), model_path.resolve())
            self.assertEqual(selector["source"], "selector_env")
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def test_train_element_role_classifier_v2_build_manifest_content_hash_depends_on_file_content(self) -> None:
        tmp_dir = Path("tmp_test_element_role_content_hash")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            torch_mod = types.ModuleType("torch")
            torch_mod.tensor = lambda *args, **kwargs: None
            torch_mod.float32 = "float32"
            torch_mod.no_grad = contextlib.nullcontext
            nn_mod = types.ModuleType("torch.nn")
            nn_mod.Module = object
            nn_mod.Linear = lambda *args, **kwargs: None
            fn_mod = types.ModuleType("torch.nn.functional")
            fn_mod.relu = lambda value: value
            torch_mod.nn = nn_mod
            first = tmp_dir / "a.jsonl"
            second = tmp_dir / "b.jsonl"
            first.write_text('{"view_id":"v1","role":"answer","text":"A","bbox":[0,0,10,10],"viewport":{"width":100,"height":100}}\n', encoding="utf-8")
            second.write_text('{"view_id":"v2","role":"question","text":"Q","bbox":[0,0,10,10],"viewport":{"width":100,"height":100}}\n', encoding="utf-8")
            with mock.patch.dict(
                sys.modules,
                {
                    "torch": torch_mod,
                    "torch.nn": nn_mod,
                    "torch.nn.functional": fn_mod,
                },
            ):
                spec = importlib.util.spec_from_file_location(
                    "test_train_element_role_classifier_v2_mod",
                    str((PACKAGE_ROOT / "scripts" / "brain" / "runtime" / "train_element_role_classifier_v2.py").resolve()),
                )
                module = importlib.util.module_from_spec(spec)
                assert spec is not None and spec.loader is not None
                sys.modules[spec.name] = module
                spec.loader.exec_module(module)
                baseline = module._build_manifest_content_hash([first, second])
            second.write_text('{"view_id":"v2","role":"question","text":"Q changed","bbox":[0,0,10,10],"viewport":{"width":100,"height":100}}\n', encoding="utf-8")
            changed = module._build_manifest_content_hash([first, second])
            self.assertNotEqual(baseline, changed)
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def test_train_element_role_classifier_v2_build_rollout_payload_points_runtime_to_model(self) -> None:
        torch_mod = types.ModuleType("torch")
        torch_mod.tensor = lambda *args, **kwargs: None
        torch_mod.float32 = "float32"
        torch_mod.no_grad = contextlib.nullcontext
