    def test_quiz_type_benchmark_report_includes_per_class_confusion_and_block_metrics(self) -> None:
        tmp_dir = Path("tmp_test_quiz_type_benchmark")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            sample_a = tmp_dir / "sample_a.region.json"
            sample_b = tmp_dir / "sample_b.region.json"
            sample_a.write_text(json.dumps({"sample_id": "a"}), encoding="utf-8")
            sample_b.write_text(json.dumps({"sample_id": "b"}), encoding="utf-8")
            manifest = tmp_dir / "manifest.jsonl"
            manifest.write_text(
                "\n".join(
                    [
                        json.dumps(
                            {
                                "id": "a",
                                "region_json": sample_a.name,
                                "expected_global_type": "single_choice",
                                "expected_block_types": ["single"],
                            }
                        ),
                        json.dumps(
                            {
                                "id": "b",
                                "region_json": sample_b.name,
                                "expected_global_type": "text_input",
                                "expected_block_types": ["text"],
                            }
                        ),
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            out_json = tmp_dir / "quiz_type_report.json"
            spec = importlib.util.spec_from_file_location(
                "test_quiz_type_benchmark_mod",
                str((PACKAGE_ROOT / "scripts" / "brain" / "runtime" / "quiz_type_benchmark.py").resolve()),
            )
            module = importlib.util.module_from_spec(spec)
            assert spec is not None and spec.loader is not None
            sys.modules[spec.name] = module
            spec.loader.exec_module(module)

            def _fake_parse_screen_quiz_state(*, region_payload, summary_data, page_data, rated_data):
                sample_id = str(region_payload.get("sample_id") or "")
                if sample_id == "a":
                    return {
                        "detected_quiz_type": "single_choice",
                        "questions": [{"block_type": "single"}],
                        "type_confidence": 0.97,
                        "decision_margin": 0.35,
                    }
                return {
                    "detected_quiz_type": "text_input",
                    "questions": [{"block_type": "text"}],
                    "type_confidence": 0.94,
                    "decision_margin": 0.28,
                }

            with mock.patch.object(module, "parse_screen_quiz_state", side_effect=_fake_parse_screen_quiz_state):
                with mock.patch.object(
                    sys,
                    "argv",
                    [
                        "quiz_type_benchmark.py",
                        "--manifest",
                        str(manifest),
                        "--out-json",
                        str(out_json),
                    ],
                ):
                    rc = module.main()
            self.assertEqual(rc, 0)
            report = json.loads(out_json.read_text(encoding="utf-8"))
            self.assertEqual(report["metrics"]["global_type_accuracy"], 1.0)
            self.assertEqual(report["metrics"]["block_type_accuracy_item"], 1.0)
            self.assertEqual(report["per_class"]["single_choice"]["accuracy"], 1.0)
            self.assertEqual(report["per_class"]["text_input"]["accuracy"], 1.0)
            self.assertEqual(report["confusion"]["single_choice"]["single_choice"], 1)
            self.assertEqual(report["confusion"]["text_input"]["text_input"], 1)
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

