    def test_action_planner_synthetic_choice_bbox_builds_fallback_from_prompt_and_next_spacing(self) -> None:
        bbox = action_planner._synthetic_choice_bbox(
            {
                "active_block": {
                    "bbox": [100, 100, 420, 160],
                    "cluster_bbox": [100, 100, 420, 160],
                    "prompt_bbox": [100, 100, 420, 160],
                },
                "next_bbox": [120, 420, 220, 460],
                "content_column": [90, 0, 500, 0],
                "options": [],
            },
            ResolvedQuizAnswer(
                matched=True,
                question_key="q1",
                question_type="single",
                correct_answers=["8"],
                option_indexes=[2],
                cache_item={"options_text": {"A": "3", "B": "7", "C": "8", "D": "9"}},
            ),
            "8",
        )
        self.assertIsNotNone(bbox)
        self.assertEqual(len(bbox), 4)
        self.assertGreater(bbox[0], 90.0)
