    def test_auto_main_copy_current_writes_immutable_iteration_archive(self) -> None:
        tmp_dir = Path("tmp_test_copy_current_archive")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            source_one = tmp_dir / "source_one.txt"
            source_two = tmp_dir / "source_two.txt"
            source_one.write_text("first", encoding="utf-8")
            source_two.write_text("second", encoding="utf-8")
            with mock.patch.object(auto_main, "CURRENT_RUN_DIR", tmp_dir / "current_run"):
                auto_main._copy_current(source_one, "page.png", archive_label="run_a/iter_001")
                auto_main._copy_current(source_two, "page.png", archive_label="run_a/iter_002")
            self.assertEqual((tmp_dir / "current_run" / "page.png").read_text(encoding="utf-8"), "second")
            self.assertEqual(
                (tmp_dir / "current_run" / "immutable_iteration_archive" / "run_a" / "iter_001" / "page.png").read_text(encoding="utf-8"),
                "first",
            )
            self.assertEqual(
                (tmp_dir / "current_run" / "immutable_iteration_archive" / "run_a" / "iter_002" / "page.png").read_text(encoding="utf-8"),
                "second",
            )
            latest_to_archive_link = json.loads(
                (tmp_dir / "current_run" / "latest_to_archive_link.json").read_text(encoding="utf-8")
            )
            self.assertEqual(latest_to_archive_link["latest_target"], "page.png")
            self.assertEqual(
                latest_to_archive_link["archive_target"],
                "immutable_iteration_archive/run_a/iter_002/page.png",
            )
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

