    def test_auto_main_run_region_grow_for_image_retries_until_results(self) -> None:
        tmp_dir = Path("tmp_test_run_region_grow")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            image_path = tmp_dir / "screen.png"
            image_path.write_bytes(b"png")
            json_path = auto_main.REGION_GROW_JSON_DIR / f"{image_path.stem}.json"
            original_exists = json_path.exists()
            original_text = json_path.read_text(encoding="utf-8") if original_exists else None
            try:
                json_path.parent.mkdir(parents=True, exist_ok=True)
                payloads = [
                    {"results": [], "fast_summary": {}},
                    {"results": [{"text": "Wybierz kolor"}], "fast_summary": {"total_elements": 1}},
                ]

                def _fake_run(*_args, **_kwargs):
                    current = payloads.pop(0)
                    json_path.write_text(json.dumps(current, ensure_ascii=False), encoding="utf-8")
                    return mock.Mock(returncode=0)

                with (
                    mock.patch.object(auto_main.subprocess, "run", side_effect=_fake_run) as run_mock,
                    mock.patch.object(auto_main.time, "sleep"),
                ):
                    payload = auto_main._run_region_grow_for_image(image_path)
                self.assertEqual(run_mock.call_count, 2)
                self.assertEqual(payload["results"][0]["text"], "Wybierz kolor")
            finally:
                if original_exists and original_text is not None:
                    json_path.write_text(original_text, encoding="utf-8")
                elif json_path.exists():
                    json_path.unlink()
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

