    def test_auto_main_apply_screen_actions_runs_executor_plan(self) -> None:
        tmp_dir = Path("tmp_test_apply_screen_actions")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            page = mock.Mock()
            page.viewport_size = {"width": 1200, "height": 1000}
            scroll_reads = iter([0.0, 120.0])

            def _eval(script, *args, **kwargs):
                text = str(script)
                if "window.scrollY" in text:
                    return next(scroll_reads)
                if "window.scrollTo" in text:
                    return None
                if "document.elementFromPoint" in text:
                    return {"tag": "BUTTON", "id": "", "className": "", "text": "A"}
                return None

            page.evaluate.side_effect = _eval
            page.wait_for_timeout = mock.Mock(return_value=None)
            page.mouse = mock.Mock()
            page.keyboard = mock.Mock()
            page.keyboard.press.return_value = None
            page.keyboard.type.return_value = None
            page.url = "https://quiz.example.com/q/1"
            with mock.patch.object(auto_main, "_save_action_debug", return_value={"screenshot": "a.png", "meta": "a.json"}):
                actions = auto_main._apply_screen_actions(
                    page,
                    [
                        {"kind": "screen_click", "reason": "click_answer:A", "bbox": [100, 200, 300, 260]},
                        {"kind": "key_press", "reason": "confirm", "combo": "enter"},
                        {"kind": "type_text", "reason": "type", "text": "abc"},
                        {"kind": "wait", "reason": "wait", "amount": 50},
                    ],
                    debug_dir=tmp_dir,
                    iteration=1,
                    content_column=[0, 0, 800, 0],
                )
            self.assertEqual(len(actions), 4)
            self.assertTrue(page.mouse.click.called)
            self.assertTrue(page.keyboard.press.called)
            self.assertTrue(page.keyboard.type.called)
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def test_auto_main_apply_screen_actions_retargets_answer_click_when_initial_hit_is_body(self) -> None:
        tmp_dir = Path("tmp_test_apply_screen_actions_retarget")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            page = mock.Mock()
            page.viewport_size = {"width": 1200, "height": 1000}
            scroll_reads = iter([0.0, 0.0])
            hit_reads = iter(
                [
                    {"tag": "BODY", "id": "", "className": "", "text": ""},
                    {"tag": "BUTTON", "id": "answer-b", "className": "opt", "text": "B"},
                ]
            )

            def _eval(script, *args, **kwargs):
                text = str(script)
                if "window.scrollY" in text:
                    return next(scroll_reads)
                if "window.scrollTo" in text:
                    return None
                if "document.elementFromPoint" in text:
                    return next(hit_reads)
                return None

            page.evaluate.side_effect = _eval
            page.wait_for_timeout = mock.Mock(return_value=None)
            page.mouse = mock.Mock()
            page.keyboard = mock.Mock()
            page.keyboard.press.return_value = None
            page.keyboard.type.return_value = None
            page.url = "https://quiz.example.com/q/1"
            with mock.patch.object(auto_main, "_save_action_debug", return_value={"screenshot": "a.png", "meta": "a.json"}):
                actions = auto_main._apply_screen_actions(
                    page,
                    [
                        {"kind": "screen_click", "reason": "click_answer:B", "bbox": [100, 200, 300, 260]},
                    ],
                    debug_dir=tmp_dir,
                    iteration=1,
                    content_column=[0, 0, 800, 0],
                )
            self.assertEqual(len(actions), 1)
            self.assertTrue(page.mouse.click.called)
            click_x, click_y = page.mouse.click.call_args.args
            self.assertNotEqual((click_x, click_y), (200.0, 230.0))
            self.assertTrue(actions[0]["bbox_debug"].get("retargeted"))
            self.assertEqual(actions[0]["bbox_debug"].get("hit_tag"), "BUTTON")
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

