    def test_validation_signal_policy_detects_validation_error_and_modal_overlay(self) -> None:
        validation_error = build_validation_signal_state(
            screen_state={"question_text": "Please fill required field", "options": []},
            page_data={"title": "Validation error"},
            region_payload={"results": [{"text": "This field is required"}]},
        )
        self.assertTrue(validation_error["is_validation_error"])
        self.assertTrue(validation_error["is_required_error"])
        self.assertEqual(validation_error["category"], "required_error")
        self.assertTrue(validation_error["is_blocking"])

        inline_error = build_validation_signal_state(
            screen_state={"question_text": "Invalid email address", "options": []},
            page_data={"title": "Error"},
            region_payload={"results": [{"text": "Email format is invalid"}]},
        )
        self.assertTrue(inline_error["is_inline_error"])
        self.assertTrue(inline_error["is_email_error"])
        self.assertEqual(inline_error["category"], "email_error")
        self.assertTrue(inline_error["is_blocking"])

        disabled_submit = build_validation_signal_state(
            screen_state={"question_text": "Review answers", "options": []},
            page_data={"title": "Submit disabled until all required fields are completed"},
            region_payload={"results": [{"text": "Submit button disabled"}]},
        )
        self.assertTrue(disabled_submit["is_disabled_submit"])
        self.assertEqual(disabled_submit["category"], "disabled_submit")
        self.assertTrue(disabled_submit["is_blocking"])

        toast_error = build_validation_signal_state(
            screen_state={"question_text": "Form", "options": []},
            page_data={"title": "Error"},
            region_payload={"results": [{"text": "Toast notification: invalid answer"}]},
        )
        self.assertTrue(toast_error["is_toast_error"])
        self.assertEqual(toast_error["category"], "toast_error")
        self.assertTrue(toast_error["is_blocking"])

        banner_error = build_validation_signal_state(
            screen_state={"question_text": "Form", "options": []},
            page_data={"title": "Warning banner"},
            region_payload={"results": [{"text": "Alert banner: incorrect field value"}]},
        )
        self.assertTrue(banner_error["is_banner_error"])
        self.assertEqual(banner_error["category"], "banner_error")
        self.assertTrue(banner_error["is_blocking"])

        modal_overlay = build_validation_signal_state(
            screen_state={"question_text": "Are you sure?", "options": []},
            page_data={"title": "Confirm"},
            region_payload={"results": [{"text": "Modal dialog"}, {"text": "Continue"}]},
        )
        self.assertTrue(modal_overlay["is_modal_overlay"])
        self.assertEqual(modal_overlay["category"], "modal_overlay")
        self.assertTrue(modal_overlay["is_blocking"])

