    def test_validation_outcome_checker_classifies_blocked_and_corrected(self) -> None:
        blocked = build_validation_outcome_state(
            validation_state={"category": "required_error", "is_blocking": True},
            terminal_state={"is_terminal": False, "terminal_screen": {"screen_kind": "question"}},
            submission_confirmation={"is_confirmed": False},
            action_progressed=False,
            previous_url="https://quiz.example.com/q/1",
            current_url="https://quiz.example.com/q/1",
        )
        self.assertEqual(blocked["outcome"], "blocked")

        corrected = build_validation_outcome_state(
            validation_state={"category": "none", "is_blocking": False},
            terminal_state={"is_terminal": False, "terminal_screen": {"screen_kind": "review"}},
            submission_confirmation={"is_confirmed": False},
            action_progressed=True,
            previous_url="https://quiz.example.com/q/1",
            current_url="https://quiz.example.com/review",
        )
        self.assertEqual(corrected["outcome"], "corrected")

        corrected_review_by_url = build_validation_outcome_state(
            validation_state={"category": "none", "is_blocking": False},
            terminal_state={"is_terminal": False, "terminal_screen": {"screen_kind": "review"}},
            submission_confirmation={"is_confirmed": False},
            action_progressed=False,
            previous_url="https://quiz.example.com/q/1",
            current_url="https://quiz.example.com/review",
        )
        self.assertEqual(corrected_review_by_url["outcome"], "corrected")
        self.assertEqual(corrected_review_by_url["reason"], "review_or_summary_transition")

        draft_saved = build_validation_outcome_state(
            validation_state={"category": "none", "is_blocking": False},
            terminal_state={"is_terminal": False, "terminal_screen": {"screen_kind": "question"}},
            submission_confirmation={"is_confirmed": False},
            draft_confirmation={"is_confirmed": True},
            action_progressed=True,
            previous_url="https://quiz.example.com/review",
            current_url="https://quiz.example.com/review?saved=1",
        )
        self.assertEqual(draft_saved["outcome"], "accepted")
        self.assertEqual(draft_saved["reason"], "draft_saved")

        back_navigated = build_validation_outcome_state(
            validation_state={"category": "none", "is_blocking": False},
            terminal_state={"is_terminal": False, "terminal_screen": {"screen_kind": "question"}},
            submission_confirmation={"is_confirmed": False},
            back_navigation_confirmation={"is_confirmed": True},
            action_progressed=True,
            previous_url="https://quiz.example.com/review",
            current_url="https://quiz.example.com/q/1",
        )
        self.assertEqual(back_navigated["outcome"], "accepted")
        self.assertEqual(back_navigated["reason"], "back_navigated")

