    def test_submit_guard_detects_captcha_and_business_rule_contract_detects_dependencies(self) -> None:
        guard = build_submit_guard_state(
            screen_state={"question_text": "Verify you are human", "options": []},
            page_data={"title": "reCAPTCHA challenge"},
            region_payload={"results": [{"text": "reCAPTCHA"}]},
        )
        self.assertTrue(guard["is_hard_stop"])
        self.assertEqual(guard["challenge_kind"], "recaptcha")

        contract = build_business_rule_contract(
            screen_state={
                "active_question_signature": "qsig-b",
                "active_block": {
                    "question_signature": "qsig-b",
                    "depends_on": [{"question_key": "qsig-a", "values": ["Tak"], "operator": "any"}],
                },
            },
            resolved_answer={"selected_values": ["Opcja B"]},
            page_data={"qid": "question-b"},
        )
        self.assertTrue(contract["has_conditional_branching"])
        self.assertEqual(contract["parent_rules"][0]["question_key"], "qsig-a")
        self.assertEqual(contract["parent_rules"][0]["required_values"], ["tak"])
        self.assertEqual(contract["visible_qid"], "question-b")
        self.assertEqual(contract["selected_values"], ["opcja b"])

        contract_with_defaults = build_business_rule_contract(
            screen_state={
                "active_question_signature": "qsig-c",
                "active_block": {
                    "question_signature": "qsig-c",
                    "depends_on": [{"qid": "question-a", "selected_values": [" Tak ", "tak", "NIE"]}],
                    "question_id": "screen-question-c",
                },
            },
            resolved_answer={"selected_values": [" Opcja C ", "opcja c"]},
            page_data={},
        )
        self.assertTrue(contract_with_defaults["has_conditional_branching"])
        self.assertEqual(contract_with_defaults["parent_rules"][0]["question_key"], "question-a")
        self.assertEqual(contract_with_defaults["parent_rules"][0]["required_values"], ["tak", "nie"])
        self.assertEqual(contract_with_defaults["parent_rules"][0]["operator"], "any")
        self.assertEqual(contract_with_defaults["visible_qid"], "screen-question-c")
        self.assertEqual(contract_with_defaults["selected_values"], ["opcja c"])

    def test_runtime_security_helpers_cover_allowlist_redaction_secrets_and_submit_confirmation(self) -> None:
        allow = evaluate_domain_allowlist(
            current_url="https://survey.example.com/q/1",
            allowed_hosts=["example.com"],
        )
        self.assertTrue(allow["is_allowed"])

        blocked = evaluate_domain_allowlist(
            current_url="https://evil.test/q/1",
            allowed_hosts=["example.com"],
        )
        self.assertFalse(blocked["is_allowed"])

        self.assertEqual(
            redact_text("mail me at john@example.com and id 12345678"),
            "mail me at [redacted-email] and id [redacted-number]",
        )

        env_path = Path("tmp_test_runtime_security.env")
        env_path.write_text("API_TOKEN=sekret\n# comment\n", encoding="utf-8")
        try:
            secrets = load_named_secrets(names=["API_TOKEN", "MISSING"], env={}, env_file=env_path)
            self.assertEqual(secrets["API_TOKEN"], "sekret")
            self.assertNotIn("MISSING", secrets)
        finally:
            if env_path.exists():
                env_path.unlink()

        submit_guard = build_submit_confirmation_guard_state(
            actions_plan=[{"kind": "screen_click", "reason": "submit_final_form"}],
            runtime_state={"state": "submit"},
            terminal_state={"terminal_screen": {"screen_kind": "review"}},
            validation_state={"is_blocking": False},
            submit_guard_state={"is_hard_stop": False},
            mission_mode="live",
            operator_confirmation={"confirmed": False},
        )
        self.assertFalse(submit_guard["is_allowed"])

        delayed_submit_guard = build_submit_confirmation_guard_state(
            actions_plan=[
                {"kind": "wait", "amount": 120, "reason": "wait_before_submit"},
                {"kind": "screen_click", "reason": "submit_final_form", "bbox": [1, 2, 3, 4]},
            ],
            runtime_state={"state": "submit"},
            terminal_state={"terminal_screen": {"screen_kind": "review"}},
            validation_state={"is_blocking": False},
            submit_guard_state={"is_hard_stop": False},
            mission_mode="live",
            operator_confirmation={"confirmed": False},
        )
        self.assertFalse(delayed_submit_guard["is_allowed"])
