    def test_persona_rotation_engine_selects_stable_profile_and_shifts_on_recovery(self) -> None:
        personas = [
            {"persona_id": "p1", "label": "fast", "locale": "pl"},
            {"persona_id": "p2", "label": "careful", "locale": "pl"},
            {"persona_id": "p3", "label": "balanced", "locale": "en"},
        ]
        first = rotate_persona_profiles(persona_profiles=personas, session_key="session-a", prefer_recovery=False)
        repeat = rotate_persona_profiles(persona_profiles=personas, session_key="session-a", prefer_recovery=False)
        recovery = rotate_persona_profiles(persona_profiles=personas, session_key="session-a", prefer_recovery=True)

        self.assertEqual(first["selected_index"], repeat["selected_index"])
        self.assertEqual(first["selected_persona_key"], repeat["selected_persona_key"])
        self.assertEqual(first["profile_count"], 3)
        self.assertEqual(recovery["reason"], "recovery_rotation")
        self.assertNotEqual(first["selected_index"], recovery["selected_index"])

        anti_modal = build_anti_modal_guard_state(
            screen_state={"question_text": "Subscribe to continue", "options": []},
            page_data={"title": "Paywall"},
            region_payload=None,
        )
        self.assertTrue(anti_modal["is_blocking"])

        tmp_dir = Path("tmp_test_takeover")
        takeover = build_manual_takeover_state(requested=True, reason="operator pause", session_dir=tmp_dir)
        self.assertTrue(Path(takeover["marker_path"]).exists())
        resume = build_resume_state(previous_runtime_state={"context": {"current_signature": "sig-1", "current_url": "https://quiz.example.com/q/1"}})
        self.assertTrue(resume["can_resume"])
        rotated = rotate_test_account(accounts=[{"login": "a"}, {"login": "b"}], session_index=3)
        self.assertEqual(rotated["login"], "b")
        mapped = map_environment_profile(environment="staging", profiles={"default": {"dataset": "safe"}, "staging": {"dataset": "stage"}})
        self.assertEqual(mapped["dataset"], "stage")
        shutil.rmtree(tmp_dir, ignore_errors=True)

