    def test_build_test_data_governance_packet_loads_secrets_profile_and_account_rotation(self) -> None:
        env_path = Path("tmp_test_data_governance.env")
        env_path.write_text("API_TOKEN=sekret\n", encoding="utf-8")
        try:
            packet = build_test_data_governance_packet(
                env={
                    "FULLBOT_ENVIRONMENT": "staging",
                    "FULLBOT_SECRET_NAMES": "API_TOKEN,MISSING",
                    "FULLBOT_ENV_FILE": str(env_path),
                    "FULLBOT_TEST_ACCOUNTS_JSON": json.dumps(
                        [
                            {"id": "qa-a", "login": "a@example.com"},
                            {"id": "qa-user-123456", "login": "b@example.com"},
                        ]
                    ),
                    "FULLBOT_ENV_PROFILES_JSON": json.dumps(
                        {
                            "default": {"dataset": "safe"},
                            "staging": {"dataset": "stage"},
                        }
                    ),
                    "FULLBOT_SESSION_INDEX": "3",
                }
            )
            self.assertEqual(packet["environment"], "staging")
            self.assertEqual(packet["environment_profile"]["dataset"], "stage")
            self.assertEqual(packet["loaded_secret_names"], ["API_TOKEN"])
            self.assertEqual(packet["secret_count"], 1)
            self.assertEqual(packet["test_account_rotation"]["selected_account_id"], "qa-user-123456")
            self.assertEqual(packet["test_account_rotation"]["account_count"], 2)
        finally:
            if env_path.exists():
                env_path.unlink()

