    def test_build_decision_diff_engine_reports_semantic_drift(self) -> None:
        diff = screen_contracts.build_decision_diff_engine(
            snapshot_current={"recommended_action": "scroll", "reason": "strong evidence", "outcome": "done", "score": 0.9},
            snapshot_previous={"recommended_action": "wait", "reason": "weak evidence", "outcome": "pending", "score": 0.4},
        )
        stable = screen_contracts.build_decision_diff_engine(
            snapshot_current={"action": "scroll", "reason": "strong evidence", "outcome": "done", "score": 0.9},
            snapshot_previous={"action": "scroll", "reason": "strong evidence", "outcome": "done", "score": 0.88},
        )
        self.assertEqual(diff["severity"], "high")
        self.assertIn("action", diff["drift_fields"])
        self.assertIn("reason", diff["drift_fields"])
        self.assertIn("outcome", diff["drift_fields"])
        self.assertEqual(stable["severity"], "stable")
        self.assertEqual(stable["drift_fields"], [])

