        self.assertTrue(timeout["is_expired"])
        self.assertTrue(timeout["has_timeout_business"])
        self.assertEqual(timeout["reason"], "timeout_detected")
        self.assertFalse(none["is_expired"])
        self.assertEqual(none["reason"], "no_expiry_detected")

