        self.assertFalse(countdown["is_time_limit"])

        self.assertEqual(deadline["signal_kind"], "deadline")
        self.assertTrue(deadline["has_deadline"])
        self.assertTrue(deadline["is_deadline"])

        self.assertEqual(time_limit["signal_kind"], "time_limit")
