    def test_build_time_sensitive_rule_guard_detects_question_time_dependency(self) -> None:
        deadline = screen_contracts.build_deadline_signal_parser(
            page_state={"message": "Submit before 17:00"},
            deadline_seconds=300.0,
        )
        sensitive = screen_contracts.build_time_sensitive_rule_guard(
            current_question={"question": "Which date should be used?" , "hint": "Choose today or tomorrow"},
            deadline_signal=deadline,
        )
        phrase_only = screen_contracts.build_time_sensitive_rule_guard(
            current_question={"question": "Select a time window for delivery"},
        )
        plain = screen_contracts.build_time_sensitive_rule_guard(
            current_question={"question": "What is your favorite color?"},
        )

        self.assertEqual(sensitive["guard_kind"], "time_sensitive_deadline")
        self.assertTrue(sensitive["is_time_sensitive"])
        self.assertTrue(sensitive["has_deadline_signal"])
        self.assertTrue(sensitive["has_question_time_hint"])

        self.assertEqual(phrase_only["guard_kind"], "time_phrase_sensitive")
        self.assertTrue(phrase_only["is_time_sensitive"])
        self.assertFalse(phrase_only["has_deadline_signal"])

        self.assertEqual(plain["guard_kind"], "not_time_sensitive")
        self.assertFalse(plain["is_time_sensitive"])

