    def test_build_time_shift_replay_policy_distinguishes_preserve_renormalize_and_reject(self) -> None:
        preserve = screen_contracts.build_time_shift_replay_policy(
            original_packet={"payload_class": "date", "value": "2026-04-05", "now_ts": 1_700_000_000.0},
            replay_packet={"payload_class": "date", "value": "2026-04-05", "now_ts": 1_700_000_000.0},
            shift_seconds=0.0,
            allow_renormalize=["date", "datetime"],
        )
        renormalize = screen_contracts.build_time_shift_replay_policy(
            original_packet={"payload_class": "date", "value": "2026-04-05", "now_ts": 1_700_000_000.0},
            replay_packet={"payload_class": "date", "value": "2026-04-06", "now_ts": 1_700_086_400.0},
            shift_seconds=86_400.0,
            allow_renormalize=["date", "datetime"],
        )
        reject = screen_contracts.build_time_shift_replay_policy(
            original_packet={"payload_class": "countdown", "value": "15m", "now_ts": 1_700_000_000.0},
            replay_packet={"payload_class": "countdown", "value": "2m", "now_ts": 1_700_600_000.0},
            shift_seconds=600_000.0,
            allow_renormalize=["date", "datetime"],
        )

        self.assertEqual(preserve["policy"], "preserve")
        self.assertTrue(preserve["is_preserve"])
        self.assertEqual(preserve["reason"], "replay_preserves_temporal_values")

        self.assertEqual(renormalize["policy"], "renormalize")
        self.assertTrue(renormalize["is_renormalize"])
        self.assertEqual(renormalize["reason"], "replay_can_be_renormalized")

        self.assertEqual(reject["policy"], "reject")
        self.assertTrue(reject["is_reject"])
        self.assertEqual(reject["reason"], "replay_temporal_drift_too_large")

    def test_build_temporal_regression_suite_tracks_profiles_across_latency_and_age(self) -> None:
        suite = screen_contracts.build_temporal_regression_suite(
            temporal_cases=[
                {
                    "case_id": "stable",
                    "profile_id": "stable",
                    "screen_ts": 1_700_000_000.0,
                    "session_ts": 1_700_000_000.0,
                    "browser_ts": 1_700_000_000.0,
                    "server_ts": 1_700_000_000.0,
                    "trace_ts": 1_700_000_000.0,
                    "now_ts": 1_700_000_000.0,
                    "elapsed_seconds": 1.0,
                    "original_packet": {"payload_class": "date", "value": "2026-04-05", "now_ts": 1_700_000_000.0},
                    "replay_packet": {"payload_class": "date", "value": "2026-04-05", "now_ts": 1_700_000_000.0},
                    "allow_renormalize": ["date"],
                    "expected_outcome": "stable",
                },
                {
                    "case_id": "wait",
                    "profile_id": "wait",
                    "screen_ts": 1_700_000_000.0,
                    "session_ts": 1_700_000_000.0,
                    "browser_ts": 1_700_000_000.0,
                    "server_ts": 1_700_000_000.0,
                    "trace_ts": 1_700_000_000.0,
                    "now_ts": 1_700_000_000.0,
                    "elapsed_seconds": 2.0,
                    "network_state": {"status": "background sync"},
                    "expected_outcome": "wait",
                },
                {
                    "case_id": "expired",
                    "profile_id": "expired",
                    "screen_ts": 1_699_999_000.0,
                    "session_ts": 1_699_999_000.0,
                    "browser_ts": 1_699_999_000.0,
                    "server_ts": 1_699_999_000.0,
                    "trace_ts": 1_699_999_000.0,
                    "now_ts": 1_700_000_000.0,
                    "elapsed_seconds": 15.0,
                    "banner_text": "Session expired. Please reauth.",
                    "auth_state": {"status": "expired"},
                    "original_packet": {"payload_class": "countdown", "value": "15m", "now_ts": 1_700_000_000.0},
                    "replay_packet": {"payload_class": "countdown", "value": "2m", "now_ts": 1_700_600_000.0},
                    "expected_outcome": "expired",
                },
            ]
        )

        self.assertEqual(suite["reason"], "regression_suite_passed")
        self.assertTrue(suite["is_passing"])
        self.assertEqual(suite["suite_size"], 3)
        self.assertEqual(suite["passed_cases"], 3)
        self.assertEqual(suite["failed_cases"], 0)
        self.assertEqual([row["actual_outcome"] for row in suite["rows"]], ["stable", "wait", "expired"])
        self.assertIn("stable", suite["profile_families"])
        self.assertIn("wait", suite["profile_families"])
        self.assertIn("expired", suite["profile_families"])

