    def test_decision_cost_model_prefers_cheaper_safe_choice(self) -> None:
        observe = screen_contracts.build_decision_cost_model(
            observation_cost_ms=120.0,
            action_cost_ms=300.0,
            risk_score=0.8,
            freshness_score=0.4,
            preferred_mode="observe",
        )
        act = screen_contracts.build_decision_cost_model(
            observation_cost_ms=300.0,
            action_cost_ms=120.0,
            risk_score=0.2,
            freshness_score=0.9,
            preferred_mode="act",
        )
        self.assertEqual(observe["decision"], "observe")
        self.assertEqual(observe["reason"], "observation_cheaper_or_safer")
        self.assertEqual(act["decision"], "act")
        self.assertEqual(act["reason"], "action_cheaper_than_observation")
        self.assertLess(observe["adjusted_observation_cost_ms"], observe["adjusted_action_cost_ms"])
        self.assertLess(act["adjusted_action_cost_ms"], act["adjusted_observation_cost_ms"])

