    def test_build_network_latency_classifier_distinguishes_backend_and_ui_failures(self) -> None:
        stable = screen_contracts.build_network_latency_classifier(
            response_event={"latency_ms": 120.0, "status_code": 200},
            screen_state={"screen_changed": True, "transition_latency_ms": 140.0},
        )
        backend_latency = screen_contracts.build_network_latency_classifier(
            response_event={"latency_ms": 920.0, "status_code": 200},
            screen_state={"screen_changed": False, "transition_latency_ms": 40.0},
        )
        ui_failure = screen_contracts.build_network_latency_classifier(
            response_event={"latency_ms": 90.0, "status_code": 200},
            screen_state={"screen_changed": False, "transition_latency_ms": 30.0},
        )

        self.assertEqual(stable["classification"], "stable")
        self.assertEqual(stable["reason"], "backend_and_ui_within_bounds")
        self.assertTrue(stable["is_stable"])
        self.assertFalse(stable["should_escalate"])

        self.assertEqual(backend_latency["classification"], "backend_latency")
        self.assertEqual(backend_latency["reason"], "backend_slow_with_no_transition")
        self.assertTrue(backend_latency["is_backend_bound"])
        self.assertTrue(backend_latency["should_escalate"])

        self.assertEqual(ui_failure["classification"], "ui_flow_failure")
        self.assertEqual(ui_failure["reason"], "ui_failed_to_transition")
        self.assertTrue(ui_failure["is_ui_bound"])
        self.assertTrue(ui_failure["should_escalate"])

    def test_build_retry_chain_tracker_distinguishes_immediate_and_retried_success(self) -> None:
        immediate = screen_contracts.build_retry_chain_tracker(
            attempts=[
                {"status": "success", "latency_ms": 180.0},
            ]
        )
        retried = screen_contracts.build_retry_chain_tracker(
            attempts=[
                {"status": "timeout", "latency_ms": 900.0, "retry_reason": "network"},
                {"status": "success", "latency_ms": 260.0, "is_retry": True},
            ],
            final_event={"status": "success"},
        )

        self.assertEqual(immediate["classification"], "immediate_success")
        self.assertEqual(immediate["reason"], "success_without_retry")
        self.assertFalse(immediate["has_retries"])
        self.assertFalse(immediate["silent_retry_detected"])
        self.assertTrue(immediate["is_terminal_success"])

        self.assertEqual(retried["classification"], "retried_success")
        self.assertEqual(retried["reason"], "success_after_retry")
        self.assertTrue(retried["has_retries"])
        self.assertTrue(retried["silent_retry_detected"])
        self.assertTrue(retried["final_success_after_retry"])
        self.assertEqual(retried["retry_indices"], [1])
        self.assertTrue(retried["is_terminal_success"])

