    def test_build_ui_vs_network_timeout_splitter_separates_ui_and_backend_timeouts(self) -> None:
        ui_timeout = screen_contracts.build_ui_vs_network_timeout_splitter(
            request_event={"ui_timed_out": True, "timeout_scope": "ui"},
            screen_state={"deadline_exceeded": True, "screen_changed_since_request": True},
        )
        network_timeout = screen_contracts.build_ui_vs_network_timeout_splitter(
            response_event={"status": "timeout", "status_code": 504},
            timeout_event={"timed_out": True, "scope": "network"},
        )
        mixed_timeout = screen_contracts.build_ui_vs_network_timeout_splitter(
            request_event={"action_timed_out": True},
            response_event={"status": "timeout", "status_code": 504},
            timeout_event={"timed_out": True, "scope": "network"},
            screen_state={"deadline_exceeded": True, "screen_changed_since_request": True},
        )

        self.assertEqual(ui_timeout["timeout_kind"], "ui_timeout")
        self.assertEqual(ui_timeout["reason"], "ui_state_timeout")
        self.assertTrue(ui_timeout["ui_timeout"])
        self.assertFalse(ui_timeout["network_timeout"])
        self.assertTrue(ui_timeout["should_retry_ui"])
        self.assertFalse(ui_timeout["should_retry_network"])

        self.assertEqual(network_timeout["timeout_kind"], "network_timeout")
        self.assertEqual(network_timeout["reason"], "backend_timeout")
        self.assertFalse(network_timeout["ui_timeout"])
        self.assertTrue(network_timeout["network_timeout"])
        self.assertFalse(network_timeout["should_retry_ui"])
        self.assertTrue(network_timeout["should_retry_network"])

        self.assertEqual(mixed_timeout["timeout_kind"], "mixed_timeout")
        self.assertEqual(mixed_timeout["reason"], "ui_and_network_timeouts_present")
        self.assertTrue(mixed_timeout["ui_timeout"])
        self.assertTrue(mixed_timeout["network_timeout"])
        self.assertTrue(mixed_timeout["should_retry_ui"])
        self.assertTrue(mixed_timeout["should_retry_network"])
        self.assertTrue(mixed_timeout["is_split"])

    def test_build_endpoint_regression_suite_tracks_payload_status_and_semantics(self) -> None:
        suite = screen_contracts.build_endpoint_regression_suite(
            endpoint_cases=[
                {
                    "case_id": "submit-ok",
                    "endpoint": "/api/submit",
                    "expected_role": "submit",
                    "expected_request_schema": {"role": "submit", "payload": {"field": "value"}},
                    "current_request": {"role": "submit", "payload": {"field": "value"}},
                    "expected_response_schema": {"role": "submit", "ok": True, "status_code": 200},
                    "current_response": {"role": "submit", "ok": True, "status_code": 200},
                    "expected_outcome_type": "success",
                    "expected_semantic": "success",
                    "expected_status_code": 200,
                },
                {
                    "case_id": "submit-retry",
                    "endpoint": "/api/submit",
                    "expected_role": "submit",
                    "expected_request_schema": {"role": "submit", "payload": {"field": "value"}},
                    "current_request": {"role": "submit", "payload": {"field": "value"}},
                    "expected_response_schema": {"role": "submit", "status_code": 500, "body": {"error": "server error"}},
                    "current_response": {"role": "submit", "status_code": 500, "body": {"error": "server error"}},
                    "expected_outcome_type": "retry",
                    "expected_semantic": "partial_failure",
                    "expected_status_code": 500,
                },
            ]
        )
        rows = {row["case_id"]: row for row in suite["rows"]}

        self.assertTrue(suite["is_passing"])
        self.assertEqual(suite["reason"], "regression_suite_passed")
        self.assertEqual(suite["suite_size"], 2)
        self.assertEqual(suite["passed_cases"], 2)
        self.assertEqual(suite["failed_cases"], 0)
        self.assertEqual(rows["submit-ok"]["actual_outcome_type"], "success")
        self.assertEqual(rows["submit-ok"]["actual_semantic"], "success")
        self.assertFalse(rows["submit-ok"]["is_drift"])
        self.assertEqual(rows["submit-retry"]["actual_outcome_type"], "retry")
        self.assertEqual(rows["submit-retry"]["actual_semantic"], "partial_failure")
        self.assertFalse(rows["submit-retry"]["is_drift"])

    def test_build_replayable_request_policy_distinguishes_safe_single_use_and_irreversible(self) -> None:
        safe = screen_contracts.build_replayable_request_policy(
            request_event={"method": "GET", "url": "https://example.test/api/status"},
        )
        single_use = screen_contracts.build_replayable_request_policy(
            request_event={"method": "POST", "url": "https://example.test/api/save_draft", "body": {"field": "value"}},
            action_record={"kind": "save_draft"},
        )
        irreversible = screen_contracts.build_replayable_request_policy(
            request_event={"method": "POST", "url": "https://example.test/api/submit", "body": {"field": "value"}},
            action_record={"kind": "submit"},
            response_event={"status_code": 200},
        )

        self.assertEqual(safe["classification"], "safe_replay")
        self.assertEqual(safe["reason"], "request_can_be_replayed_safely")
        self.assertTrue(safe["is_safe_to_replay"])
        self.assertEqual(safe["max_replays"], 3)

        self.assertEqual(single_use["classification"], "single_use")
        self.assertEqual(single_use["reason"], "request_should_not_be_replayed")
        self.assertTrue(single_use["is_single_use"])
        self.assertEqual(single_use["max_replays"], 1)

        self.assertEqual(irreversible["classification"], "irreversible")
        self.assertEqual(irreversible["reason"], "mutation_requires_single_terminal_execution")
        self.assertTrue(irreversible["is_irreversible"])
        self.assertEqual(irreversible["max_replays"], 0)
        self.assertFalse(irreversible["should_retry"])

    def test_build_submit_backend_two_phase_check_requires_request_response_and_terminal_screen(self) -> None:
        confirmed = screen_contracts.build_submit_backend_two_phase_check(
            request_event={"action": "submit", "method": "POST", "url": "https://example.test/api/submit"},
            response_event={"status_code": 200, "ok": True, "body": {"saved": True}},
            screen_state={"thank_you_screen": True, "server_acknowledged": True, "confirmation_number": "CN-42"},
        )
        pending = screen_contracts.build_submit_backend_two_phase_check(
            request_event={"action": "submit", "method": "POST", "url": "https://example.test/api/submit"},
            response_event={"status_code": 200, "ok": True, "body": {"saved": True}},
            screen_state={"review_screen": True},
        )
        blocked = screen_contracts.build_submit_backend_two_phase_check(
            request_event={"action": "submit", "method": "POST", "url": "https://example.test/api/submit"},
            response_event={"status_code": 503, "body": {"error": "service unavailable"}},
            screen_state={"review_screen": True},
        )

        self.assertEqual(confirmed["phase"], "confirmed")
        self.assertEqual(confirmed["reason"], "submit_confirmed_by_server_and_terminal_screen")
        self.assertTrue(confirmed["is_confirmed"])
        self.assertTrue(confirmed["terminal_ok"])
        self.assertTrue(confirmed["server_acknowledged"])
        self.assertEqual(confirmed["confirmation_number"], "CN-42")

        self.assertEqual(pending["phase"], "pending_confirmation")
        self.assertEqual(pending["reason"], "submit_request_completed_waiting_for_terminal_screen")
        self.assertTrue(pending["needs_terminal_confirmation"])
        self.assertFalse(pending["is_confirmed"])

        self.assertEqual(blocked["phase"], "blocked")
        self.assertEqual(blocked["reason"], "submit_backend_or_semantic_blocked")
        self.assertTrue(blocked["is_blocked"])
        self.assertFalse(blocked["is_confirmed"])

    def test_build_ui_backend_blame_router_assigns_ui_backend_and_mixed_blame(self) -> None:
        ui_blame = screen_contracts.build_ui_backend_blame_router(
            request_event={"action": "click_next"},
            response_event={"status_code": 200, "ok": True},
            screen_state={"screen_changed_since_request": True, "ui_error": True},
        )
        backend_blame = screen_contracts.build_ui_backend_blame_router(
            request_event={"action": "submit"},
            response_event={"status_code": 503, "body": {"error": "service unavailable"}, "network_timeout": True},
            screen_state={"review_screen": True, "server_acknowledged": False},
        )
        mixed_blame = screen_contracts.build_ui_backend_blame_router(
            request_event={"action": "submit"},
            response_event={"status_code": 504, "body": {"error": "gateway timeout"}, "network_timeout": True},
            screen_state={"screen_changed_since_request": True, "ui_error": True, "review_screen": True},
        )

        self.assertEqual(ui_blame["blame"], "ui")
        self.assertEqual(ui_blame["reason"], "ui_state_or_layout_caused_failure")
        self.assertGreater(ui_blame["ui_score"], 0)
        self.assertEqual(ui_blame["backend_score"], 0)
        self.assertFalse(ui_blame["should_escalate"])

        self.assertEqual(backend_blame["blame"], "backend")
        self.assertEqual(backend_blame["reason"], "backend_response_or_timeout_caused_failure")
        self.assertGreater(backend_blame["backend_score"], 0)
        self.assertTrue(backend_blame["should_escalate"])

        self.assertEqual(mixed_blame["blame"], "mixed")
        self.assertEqual(mixed_blame["reason"], "ui_and_backend_both_contributed")
        self.assertGreater(mixed_blame["ui_score"], 0)
        self.assertGreater(mixed_blame["backend_score"], 0)
        self.assertTrue(mixed_blame["should_escalate"])

