    def test_build_domain_regression_suite_tracks_respondent_state_and_branch_intent_drift(self) -> None:
        passing = screen_contracts.build_domain_regression_suite(
            regression_cases=[
                {
                    "case_id": "domain-1",
                    "expected_respondent_state": {"step": 1},
                    "actual_respondent_state": {"step": 1},
                    "expected_branch_intent": "branch-a",
                    "actual_branch_intent": "branch-a",
                },
                {
                    "case_id": "domain-2",
                    "expected_respondent_state": {"step": 2},
                    "actual_respondent_state": {"step": 2},
                    "expected_branch_intent": "branch-b",
                    "actual_branch_intent": "branch-b",
                },
            ],
            respondent_state_model={"respondent_id": "resp-1"},
            branch_intent_model={"branch_key": "survey_flow"},
            threshold=2,
        )
        failing = screen_contracts.build_domain_regression_suite(
            regression_cases=[
                {
                    "case_id": "domain-3",
                    "expected_respondent_state": {"step": 3},
                    "actual_respondent_state": {"step": 4},
                    "expected_branch_intent": "branch-c",
                    "actual_branch_intent": "branch-d",
                }
            ],
            domain_key_hint="survey_flow",
            threshold=1,
        )
        empty = screen_contracts.build_domain_regression_suite()

        self.assertEqual(passing["reason"], "regression_suite_passed")
        self.assertTrue(passing["is_passing"])
        self.assertEqual(passing["passed_cases"], 2)
        self.assertEqual(passing["branch_intent_drift_cases"], 0)

        self.assertEqual(failing["reason"], "regression_suite_failed")
        self.assertTrue(failing["should_block"])
        self.assertEqual(failing["respondent_state_drift_cases"], 1)
        self.assertEqual(failing["branch_intent_drift_cases"], 1)

        self.assertEqual(empty["reason"], "empty_regression_suite")
        self.assertFalse(empty["is_passing"])

