    def test_build_runtime_collision_guard_detects_port_lock_and_shared_dir_conflicts(self) -> None:
        clean = screen_contracts.build_runtime_collision_guard(
            port_allocations=[
                {"name": "api", "port": 8000},
                {"name": "worker", "port": 8001},
            ],
            lock_paths=["C:/tmp/api.lock", "C:/tmp/worker.lock"],
            shared_dirs=["C:/cache/api", "C:/cache/worker"],
            host_runtime_identity={"identity_id": "host-1"},
            runtime_session={"runtime_tag": "session-a"},
        )
        port_conflict = screen_contracts.build_runtime_collision_guard(
            port_allocations=[
                {"name": "api-a", "port": 8000},
                {"name": "api-b", "port": 8000},
            ],
            lock_paths=["C:/tmp/api-a.lock", "C:/tmp/api-b.lock"],
            shared_dirs=["C:/cache/api-a", "C:/cache/api-b"],
            host_runtime_identity={"identity_id": "host-1"},
            runtime_session={"runtime_tag": "session-a"},
        )
        mixed_conflict = screen_contracts.build_runtime_collision_guard(
            port_allocations=[
                {"name": "api", "port": 8000},
                {"name": "worker", "port": 8001},
            ],
            lock_paths=["C:/tmp/shared.lock", "C:\\tmp\\shared.lock"],
            shared_dirs=["C:/cache/shared", "C:\\cache\\shared"],
            host_runtime_identity={"identity_id": "host-1"},
            runtime_session={"runtime_tag": "session-a"},
        )

        self.assertEqual(clean["collision_kind"], "none")
        self.assertFalse(clean["has_collision"])
        self.assertFalse(clean["should_block_start"])
        self.assertEqual(clean["reason"], "runtime_collision_clear")

        self.assertEqual(port_conflict["collision_kind"], "port_conflict")
        self.assertTrue(port_conflict["has_port_collision"])
        self.assertTrue(port_conflict["should_block_start"])
        self.assertEqual(port_conflict["port_collision_count"], 1)
        self.assertEqual(port_conflict["reason"], "port_conflict_detected")

        self.assertEqual(mixed_conflict["collision_kind"], "mixed_conflict")
        self.assertTrue(mixed_conflict["has_lock_collision"])
        self.assertTrue(mixed_conflict["has_shared_dir_collision"])
        self.assertTrue(mixed_conflict["should_block_start"])
        self.assertEqual(mixed_conflict["collision_count"], 2)
        self.assertEqual(mixed_conflict["reason"], "mixed_runtime_collision_detected")

    def test_build_resource_aware_degradation_policy_shrinks_runtime_when_pressure_is_high(self) -> None:
        normal = screen_contracts.build_resource_aware_degradation_policy(
            candidate_backends=["cpu_fast", "gpu_fast"],
            requested_batch_size=8,
            requested_pipeline_depth=4,
        )
        degraded = screen_contracts.build_resource_aware_degradation_policy(
            resource_contention_monitor={"contention_kind": "soft_contention"},
            candidate_backends=["cpu_fast", "gpu_fast", "fallback"],
            requested_batch_size=8,
            requested_pipeline_depth=4,
        )
        minimal = screen_contracts.build_resource_aware_degradation_policy(
            host_degradation_classifier={"degradation_kind": "thermal_slowdown"},
            candidate_backends=["cpu_fast", "gpu_fast", "fallback"],
            requested_batch_size=8,
            requested_pipeline_depth=4,
        )

        self.assertEqual(normal["mode"], "normal")
        self.assertFalse(normal["is_degraded"])
        self.assertEqual(normal["allowed_backends"], ["cpu_fast", "gpu_fast"])
        self.assertEqual(normal["batch_size_limit"], 8)
        self.assertEqual(normal["pipeline_depth_limit"], 4)

        self.assertEqual(degraded["mode"], "degraded")
        self.assertTrue(degraded["is_degraded"])
        self.assertTrue(degraded["should_shrink_batch"])
        self.assertEqual(degraded["allowed_backends"], ["cpu_fast", "gpu_fast"])
        self.assertEqual(degraded["batch_size_limit"], 4)
        self.assertEqual(degraded["pipeline_depth_limit"], 3)

        self.assertEqual(minimal["mode"], "minimal")
        self.assertTrue(minimal["is_degraded"])
        self.assertTrue(minimal["should_limit_backends"])
        self.assertEqual(minimal["allowed_backends"], ["cpu_fast"])
        self.assertEqual(minimal["batch_size_limit"], 2)
        self.assertEqual(minimal["pipeline_depth_limit"], 2)

    def test_build_environment_regression_matrix_maps_scenarios_to_machine_classes(self) -> None:
        matrix = screen_contracts.build_environment_regression_matrix(
            scenarios=[
                {"name": "light_cpu", "min_cpu_cores": 2, "min_ram_gb": 4},
                {"name": "gpu_heavy", "min_cpu_cores": 4, "min_ram_gb": 8, "requires_gpu": True, "min_gpu_memory_gb": 8},
            ],
            machine_profiles=[
                {"name": "small_vm", "cpu_cores": 2, "ram_gb": 4, "gpu_name": "", "gpu_memory_gb": 0, "os_name": "linux"},
                {"name": "gpu_box", "cpu_cores": 8, "ram_gb": 16, "gpu_name": "RTX 4070", "gpu_memory_gb": 12, "os_name": "linux"},
            ],
        )
        matrix_map = {(row["scenario"], row["machine_profile"]): row for row in matrix["rows"]}
        summary_map = {row["scenario"]: row for row in matrix["scenarios"]}

        self.assertEqual(matrix["reason"], "environment_regression_matrix_complete")
        self.assertTrue(matrix["is_complete"])
        self.assertEqual(matrix["scenario_count"], 2)
        self.assertEqual(matrix["machine_profile_count"], 2)
        self.assertEqual(matrix_map[("light_cpu", "small_vm")]["supported"], True)
        self.assertEqual(matrix_map[("gpu_heavy", "small_vm")]["supported"], False)
        self.assertIn("gpu_missing_or_mismatch", matrix_map[("gpu_heavy", "small_vm")]["reasons"])
        self.assertTrue(matrix_map[("gpu_heavy", "gpu_box")]["supported"])
        self.assertEqual(summary_map["gpu_heavy"]["supported_classes"], ["gpu_box"])
        self.assertEqual(summary_map["light_cpu"]["supported_classes"], ["small_vm", "gpu_box"])
        self.assertEqual(matrix["unsupported_pair_count"], 1)
        self.assertEqual(matrix["coverage_rate"], 0.75)

