    def test_build_evidence_confidence_score_uses_completeness_freshness_and_consistency(self) -> None:
        identity = screen_contracts.build_evidence_identity_contract(
            iteration_id="iter-1",
            timestamp_ms=123456,
            evidence_items=[
                {"artifact_type": "screenshot", "artifact_id": "shot-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "capture"},
                {"artifact_type": "snapshot", "artifact_id": "snap-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "state"},
                {"artifact_type": "ocr", "artifact_id": "ocr-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "ocr"},
                {"artifact_type": "trace", "artifact_id": "trace-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "runtime"},
            ],
        )
        score = screen_contracts.build_evidence_confidence_score(
            evidence_identity_contract=identity,
            freshness_marker={"is_fresh": True, "stale_reasons": []},
            consistency_report={"consistency_score": 1.0},
        )
        stale = screen_contracts.build_evidence_confidence_score(
            evidence_identity_contract={
                **identity,
                "present_artifact_types": ["screenshot", "snapshot"],
                "is_complete": False,
                "is_consistent": False,
            },
            freshness_marker={"is_fresh": False, "stale_reasons": ["old_snapshot"]},
            consistency_report={"consistency_score": 0.4},
        )

        self.assertEqual(score["reason"], "high_confidence_evidence")
        self.assertTrue(score["is_confident"])
        self.assertAlmostEqual(score["confidence_score"], 1.0)
        self.assertEqual(score["confidence_tier"], "high")

        self.assertEqual(stale["reason"], "incomplete_evidence")
        self.assertTrue(stale["is_low_confidence"])
        self.assertLess(stale["confidence_score"], 0.6)
        self.assertEqual(stale["completeness_score"], 0.5)
        self.assertEqual(stale["freshness_score"], 0.5)
        self.assertEqual(stale["consistency_score"], 0.4)

