    def test_build_cross_artifact_sync_guard_detects_timestamp_and_version_drift(self) -> None:
        synced = screen_contracts.build_cross_artifact_sync_guard(
            evidence_items=[
                {"artifact_type": "screenshot", "timestamp_ms": 1000, "iteration_id": "iter-1", "version": "v1"},
                {"artifact_type": "snapshot", "timestamp_ms": 1000, "iteration_id": "iter-1", "version": "v1"},
                {"artifact_type": "ocr", "timestamp_ms": 1000, "iteration_id": "iter-1", "version": "v1"},
            ],
            max_timestamp_skew_ms=0,
        )
        drift = screen_contracts.build_cross_artifact_sync_guard(
            evidence_items=[
                {"artifact_type": "screenshot", "timestamp_ms": 1000, "iteration_id": "iter-1", "version": "v1"},
                {"artifact_type": "snapshot", "timestamp_ms": 1800, "iteration_id": "iter-2", "version": "v2"},
                {"artifact_type": "ocr", "timestamp_ms": 1000, "iteration_id": "iter-1", "version": "v1"},
            ],
            max_timestamp_skew_ms=100,
        )

        self.assertEqual(synced["reason"], "artifact_sync_ok")
        self.assertTrue(synced["is_synced"])
        self.assertFalse(synced["should_block_pipeline"])
        self.assertEqual(synced["timestamp_spread_ms"], 0.0)

        self.assertEqual(drift["reason"], "mixed_artifact_drift")
        self.assertFalse(drift["is_synced"])
        self.assertTrue(drift["should_block_pipeline"])
        self.assertEqual(drift["unique_iteration_ids"], ["iter-1", "iter-2"])
        self.assertEqual(drift["unique_version_ids"], ["v1", "v2"])

    def test_build_evidence_consistency_checker_detects_shared_state_and_outcome_disagreements(self) -> None:
        consistent = screen_contracts.build_evidence_consistency_checker(
            evidence_items=[
                {"artifact_type": "screenshot", "state_signature": "screen-a", "outcome": "success"},
                {"artifact_type": "snapshot", "state_signature": "screen-a", "outcome": "success"},
                {"artifact_type": "trace", "state_signature": "screen-a", "outcome": "success"},
            ],
            expected_state_signature="screen-a",
            expected_outcome="success",
        )
        inconsistent = screen_contracts.build_evidence_consistency_checker(
            evidence_items=[
                {"artifact_type": "screenshot", "state_signature": "screen-a", "outcome": "success"},
                {"artifact_type": "snapshot", "state_signature": "screen-b", "outcome": "failure"},
                {"artifact_type": "trace", "state_signature": "screen-a", "outcome": "success"},
            ],
            expected_state_signature="screen-a",
            expected_outcome="success",
        )

        self.assertEqual(consistent["reason"], "evidence_consistent")
        self.assertTrue(consistent["is_consistent"])
        self.assertFalse(consistent["should_block_pipeline"])
        self.assertEqual(consistent["observed_state_signatures"], ["screen-a"])

        self.assertEqual(inconsistent["reason"], "state_and_outcome_disagreement")
        self.assertFalse(inconsistent["is_consistent"])
        self.assertTrue(inconsistent["should_block_pipeline"])
        self.assertIn("snapshot", inconsistent["conflicting_artifact_types"])
        self.assertIn("snapshot", inconsistent["consistent_artifact_types"])

    def test_build_stale_artifact_detector_detects_cache_and_version_drift(self) -> None:
        fresh = screen_contracts.build_stale_artifact_detector(
            artifacts=[
                {"artifact_type": "screenshot", "session_id": "s1", "iteration_id": "iter-1", "version": "v1"},
                {"artifact_type": "snapshot", "session_id": "s1", "iteration_id": "iter-1", "version": "v1"},
            ],
            current_session_id="s1",
            current_iteration_id="iter-1",
            current_version="v1",
        )
        stale = screen_contracts.build_stale_artifact_detector(
            artifacts=[
                {"artifact_type": "screenshot", "session_id": "s2", "iteration_id": "iter-1", "version": "v1"},
                {"artifact_type": "snapshot", "session_id": "s1", "iteration_id": "iter-2", "version": "v2"},
            ],
            current_session_id="s1",
            current_iteration_id="iter-1",
            current_version="v1",
            freshness_marker={"is_stale": True},
        )

        self.assertEqual(fresh["reason"], "fresh_artifacts_only")
        self.assertFalse(fresh["is_stale"])
        self.assertFalse(fresh["should_reject"])
