        self.assertEqual(healthy["reason"], "evidence_quality_regression_clear")
        self.assertTrue(healthy["is_healthy"])
        self.assertFalse(healthy["should_block_pipeline"])
        self.assertEqual(healthy["passing_count"], 2)

