    def test_build_objective_scorecard_summarizes_coverage_risk_and_realization(self) -> None:
        green = screen_contracts.build_objective_scorecard(
            mission_identity={"mission_mode": "exploration", "objective": "discover failures in onboarding flow"},
            mission_success_contract={"is_successful": True, "success_score": 0.9},
            mission_outcome_interpreter={"is_mission_success": True},
            evidence_rows=[{"name": "trace", "kind": "evidence"}, {"name": "log", "kind": "evidence"}],
            observed_outcomes=[{"name": "discover trace", "result": "success"}],
        )
        amber = screen_contracts.build_objective_scorecard(
            mission_identity={"mission_mode": "exploration", "objective": "discover failures in onboarding flow"},
            mission_success_contract={"is_successful": False, "success_score": 0.2},
            mission_outcome_interpreter={"is_mission_success": False},
            evidence_rows=[{"name": "note", "kind": "misc"}],
            observed_outcomes=[{"name": "collect notes", "result": "neutral"}],
        )
        red = screen_contracts.build_objective_scorecard(
            mission_identity={"mission_mode": "verify", "objective": "finish sanity"},
            mission_success_contract={"is_successful": False, "success_score": 0.0},
            mission_outcome_interpreter={"is_mission_success": False},
            evidence_rows=[],
            observed_outcomes=[{"name": "broken", "result": "fail"}],
        )

        self.assertEqual(green["status"], "objective_scorecard_green")
        self.assertTrue(green["is_complete"])
        self.assertGreater(green["coverage"], 0.0)
        self.assertGreater(green["realization"], 0.0)

        self.assertEqual(amber["status"], "objective_scorecard_amber")
        self.assertTrue(amber["should_warn"])
        self.assertFalse(amber["should_block"])

        self.assertEqual(red["status"], "objective_scorecard_red")
        self.assertTrue(red["should_block"])
        self.assertGreaterEqual(red["coverage"], 0.0)

