    def test_build_mission_regression_suite_alignment_guard_and_drift_packet_track_mission_drift(self) -> None:
        suite = screen_contracts.build_mission_regression_suite(
            mission_identity={"mission_mode": "exploration", "objective": "discover failures in onboarding flow"},
            regression_cases=[
                {"case_id": "case_1", "mission_mode": "exploration", "expected_mission_mode": "exploration", "strategy": "explore_policy", "expected_strategy": "explore_policy", "report": "report_a", "expected_report": "report_a"},
                {"case_id": "case_2", "mission_mode": "exploration", "expected_mission_mode": "exploration", "strategy": "explore_policy", "expected_strategy": "explore_policy", "report": "report_b", "expected_report": "report_b"},
            ],
            threshold=2,
        )
        guard = screen_contracts.build_mission_alignment_guard(
            mission_identity={"mission_mode": "exploration", "objective": "discover failures in onboarding flow"},
            strategy_router={"selected_strategy": "explore_policy", "selected_data_profile": "smoke"},
            regression_suite=suite,
        )
        drift = screen_contracts.build_mission_drift_packet(
            mission_identity={"mission_mode": "exploration", "objective": "discover failures in onboarding flow"},
            mission_regression_suite=suite,
            mission_alignment_guard=guard,
            drift_events=[{"name": "late strategy change", "kind": "strategy", "severity": "medium"}],
        )

        self.assertEqual(suite["reason"], "mission_regression_suite_passed")
        self.assertTrue(suite["is_passing"])
        self.assertEqual(suite["passing_count"], 2)

        self.assertEqual(guard["reason"], "mission_alignment_guard_warn")
        self.assertTrue(guard["should_warn"])
        self.assertFalse(guard["should_block"])
        self.assertLess(guard["alignment_score"], 0.9)

        self.assertEqual(drift["reason"], "mission_drift_packet_drifted")
        self.assertTrue(drift["is_drifted"])
        self.assertTrue(drift["should_block"])
        self.assertGreaterEqual(drift["drift_count"], 1)

