    def test_build_forensic_replay_bundle_keeps_only_integrity_clean_evidence(self) -> None:
        identity = screen_contracts.build_evidence_identity_contract(
            iteration_id="iter-1",
            timestamp_ms=123456,
            evidence_items=[
                {"artifact_type": "screenshot", "artifact_id": "shot-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "capture"},
                {"artifact_type": "snapshot", "artifact_id": "snap-1", "iteration_id": "iter-1", "timestamp_ms": 123456, "source_lineage": "state"},
            ],
        )
        integrity = screen_contracts.build_artifact_integrity_verifier(
            artifacts=[
                {"name": "screenshot", "checksum": "a1", "expected_checksum": "a1", "size_bytes": 1024, "readability_score": 1.0},
                {"name": "snapshot", "checksum": "b1", "expected_checksum": "b1", "size_bytes": 1024, "readability_score": 1.0},
            ],
        )
        bundle = screen_contracts.build_forensic_replay_bundle(
            evidence_identity_contract=identity,
            artifact_integrity_verifier=integrity,
            evidence_consistency_checker={"is_consistent": True, "conflicting_artifact_types": []},
            stale_artifact_detector={"is_stale": False, "stale_artifacts": []},
        )
        blocked = screen_contracts.build_forensic_replay_bundle(
            evidence_identity_contract=identity,
            artifact_integrity_verifier={
                "rows": [{"name": "screenshot", "is_integrity_ok": True}, {"name": "snapshot", "is_integrity_ok": False}],
            },
            evidence_consistency_checker={"is_consistent": False, "conflicting_artifact_types": ["snapshot"]},
            stale_artifact_detector={"is_stale": True, "stale_artifacts": [{"artifact_type": "snapshot"}]},
        )

        self.assertEqual(bundle["reason"], "forensic_replay_bundle_ready")
        self.assertTrue(bundle["is_ready"])
        self.assertFalse(bundle["should_block_replay"])
        self.assertEqual(bundle["approved_artifact_types"], ["screenshot", "snapshot"])

        self.assertEqual(blocked["reason"], "forensic_replay_quarantined")
        self.assertFalse(blocked["is_ready"])
        self.assertTrue(blocked["should_block_replay"])
        self.assertEqual(blocked["blocked_artifact_types"], ["snapshot"])

    def test_build_worker_scaling_curve_matches_runtime_shape(self) -> None:
        curve = screen_contracts.build_worker_scaling_curve(
            requested_workers=4,
            logical_cores=8,
            ocr_scale_parallelism_cap=2,
            runtime_executor_cap=4,
        )
        default_curve = screen_contracts.build_worker_scaling_curve(
            requested_workers=0,
            logical_cores=8,
            ocr_scale_parallelism_cap=2,
            runtime_executor_cap=4,
        )
        self.assertEqual(curve["requested_workers"], 4)
        self.assertEqual(curve["plateau_after_workers"], 2)
        self.assertEqual(curve["requested_regime"], "contention")
