    def test_build_site_failure_priors_chooses_stop_reason_and_expectation(self) -> None:
        runtime_stopped = screen_contracts.build_site_failure_priors(
            site_identity_registry={"canonical_site_id": "site-2"},
            summary={
                "completed": False,
                "error": "runtime_stopped",
                "steps": [
                    {"operational_watchdog": {"decision": "fallback"}},
                    {"operational_watchdog": {"decision": "fallback"}},
                ],
                "live_site_safety_policy": {"is_blocking": False, "requires_review": False},
            },
        )
        hard_block = screen_contracts.build_site_failure_priors(
            site_identity_registry={"canonical_site_id": "site-2"},
            summary={
                "completed": False,
                "error": "Blocked by live_site_guard",
                "steps": [{"operational_watchdog": {"decision": "abort"}}],
                "failure_summary": {"what_failed": "blocked", "why_failed": "guard", "next_best_action": "review"},
            },
        )
        self.assertEqual(runtime_stopped["stop_reason"], "runtime_stopped")
        self.assertEqual(runtime_stopped["stop_reason_source"], "summary")
        self.assertEqual(runtime_stopped["next_session_expectation"], "expect_fallback_reuse")
        self.assertIn("runtime_stopped", runtime_stopped["risk_flags"])
        self.assertEqual(runtime_stopped["dominant_watchdog_decision"], "fallback")
        self.assertEqual(hard_block["stop_reason"], "Blocked by live_site_guard")
        self.assertEqual(hard_block["stop_reason_source"], "summary")
        self.assertEqual(hard_block["next_session_expectation"], "expect_guard_block")
        self.assertIn("hard_block", hard_block["risk_flags"])

