    def test_build_site_specific_forbidden_targets_collects_modal_and_cookie_tokens(self) -> None:
        forbidden = screen_contracts.build_site_specific_forbidden_targets(
            site_identity_registry={"canonical_site_id": "site-6"},
            summary={
                "steps": [
                    {
                        "plan_reason": "click:accept cookies",
                        "actions": [{"kind": "dom_click_button", "reason": "click:accept cookies"}],
                    }
                ],
                "anti_modal_guard": {"matched_tokens": ["Accept Cookies"], "reason": "unexpected_modal_overlay"},
                "consent_barrier_policy": {"reason": "cookie consent required"},
                "allowed_action_policy": {"reason": "forbidden_token:login"},
            },
        )
        labels = [row["label"] for row in forbidden["forbidden_targets"]]
        self.assertEqual(forbidden["canonical_site_id"], "site-6")
        self.assertIn("accept cookies", labels)
        self.assertIn("login", labels)
        self.assertTrue(forbidden["signals"]["has_cookie_overlay_risk"])
        accept_row = next(row for row in forbidden["forbidden_targets"] if row["label"] == "accept cookies")
        consent_row = next(row for row in forbidden["forbidden_targets"] if row["label"] == "cookie consent")
        self.assertIn("anti_modal_guard", accept_row["sources"])
        self.assertIn("step_actions", accept_row["sources"])
        self.assertIn("consent_barrier_policy", consent_row["sources"])
        self.assertEqual(forbidden["signals"]["forbidden_count"], len(forbidden["forbidden_targets"]))

