    def test_build_canonical_question_instance_stabilizes_question_identity(self) -> None:
        first = screen_contracts.build_canonical_question_instance(
            qid="q-12",
            bbox_group="group-a",
            question_text="Jaki jest kolor?",
        )
        second = screen_contracts.build_canonical_question_instance(
            qid="q-12",
            bbox_group="group-a",
            question_text="Jaki jest kolor?",
        )
        changed_text = screen_contracts.build_canonical_question_instance(
            qid="q-12",
            bbox_group="group-a",
            question_text="Jaki jest rozmiar?",
        )
        changed_group = screen_contracts.build_canonical_question_instance(
            qid="q-12",
            bbox_group="group-b",
            question_text="Jaki jest kolor?",
        )
        self.assertEqual(first["canonical_question_id"], second["canonical_question_id"])
        self.assertNotEqual(first["canonical_question_id"], changed_text["canonical_question_id"])
        self.assertNotEqual(first["canonical_question_id"], changed_group["canonical_question_id"])
        self.assertEqual(first["instance"]["qid"], "q-12")
        self.assertEqual(first["instance"]["bbox_group"], "group-a")
        self.assertTrue(first["is_canonical"])

