    def test_build_action_checkpoint_preserves_planned_target_and_pre_state_hash(self) -> None:
        first = screen_contracts.build_action_checkpoint(
            action_id="act-7",
            iteration_id="iter-3",
            planned_target={"action_id": "act-7", "target": "next"},
            pre_state={"screen_signature": "sig-a", "qid": "q-12"},
            expected_postcondition={"screen_signature": "sig-b", "status": "ready"},
        )
        second = screen_contracts.build_action_checkpoint(
            action_id="act-7",
            iteration_id="iter-3",
            planned_target={"action_id": "act-7", "target": "next"},
            pre_state={"screen_signature": "sig-a", "qid": "q-12"},
            expected_postcondition={"screen_signature": "sig-b", "status": "ready"},
        )
        incomplete = screen_contracts.build_action_checkpoint(
            planned_target={"target": "next"},
            pre_state={"screen_signature": "sig-a"},
            expected_postcondition={},
        )
        self.assertEqual(first["checkpoint"]["action_id"], "act-7")
        self.assertEqual(first["checkpoint"]["iteration_id"], "iter-3")
        self.assertEqual(first["checkpoint"]["planned_target"]["target"], "next")
        self.assertEqual(first["checkpoint"]["expected_postcondition"]["status"], "ready")
        self.assertEqual(first["checkpoint"]["pre_state_hash"], second["checkpoint"]["pre_state_hash"])
        self.assertEqual(first["checkpoint_hash"], second["checkpoint_hash"])
        self.assertTrue(first["is_complete"])
        self.assertFalse(incomplete["is_complete"])

    def test_build_resume_policy_engine_switches_between_replay_skip_and_reparse(self) -> None:
        checkpoint = screen_contracts.build_action_checkpoint(
            action_id="act-7",
            iteration_id="iter-3",
            planned_target={"target": "next"},
            pre_state={"screen_signature": "sig-a"},
            expected_postcondition={"status": "ready"},
        )
        replay = screen_contracts.build_resume_policy_engine(
            action_checkpoint=checkpoint["checkpoint"],
            freshness_marker={"is_fresh": True},
            current_state={"target": "next"},
        )
        skip = screen_contracts.build_resume_policy_engine(
            action_checkpoint=checkpoint["checkpoint"],
            freshness_marker={"is_fresh": True},
            current_state={"status": "ready"},
        )
        reparsed = screen_contracts.build_resume_policy_engine(
            action_checkpoint=checkpoint["checkpoint"],
            freshness_marker={"is_fresh": False, "stale_reasons": ["screen_age_s"]},
            current_state={"status": "blocked"},
        )
        self.assertEqual(replay["decision"], "replay")
        self.assertEqual(replay["reason"], "planned_target_still_valid")
        self.assertEqual(skip["decision"], "skip")
        self.assertEqual(skip["reason"], "current_state_matches_expected")
        self.assertEqual(reparsed["decision"], "re-parse")
        self.assertEqual(reparsed["reason"], "stale_checkpoint")

