    def test_build_iteration_time_budget_contract_tracks_total_and_overrun(self) -> None:
        within = screen_contracts.build_iteration_time_budget_contract(
            total_budget_s=10.0,
            capture_s=1.5,
            parse_s=2.0,
            execute_s=3.0,
            readback_s=1.0,
        )
        over = screen_contracts.build_iteration_time_budget_contract(
            total_budget_s=5.0,
            capture_s=1.5,
            parse_s=2.0,
            execute_s=3.0,
            readback_s=1.0,
        )
        missing = screen_contracts.build_iteration_time_budget_contract(
            total_budget_s=0.0,
            capture_s=1.0,
            parse_s=1.0,
            execute_s=1.0,
            readback_s=1.0,
        )
        self.assertFalse(within["is_over_budget"])
        self.assertEqual(within["reason"], "within_budget")
        self.assertTrue(over["is_over_budget"])
        self.assertEqual(over["reason"], "time_budget_exceeded")
        self.assertEqual(over["budget"]["used_s"], 7.5)
        self.assertEqual(missing["reason"], "missing_total_budget")

    def test_build_stage_budget_allocator_prioritizes_expensive_stage(self) -> None:
        allocator = screen_contracts.build_stage_budget_allocator(
            total_budget_s=12.0,
            stage_cost_hints={"capture": 1.0, "parse": 2.0, "execute": 6.0, "readback": 1.0},
        )
        missing = screen_contracts.build_stage_budget_allocator(total_budget_s=0.0)
        allocations = {row["stage"]: row["allocated_s"] for row in allocator["allocations"]}
        self.assertTrue(allocator["is_valid"])
        self.assertEqual(allocator["reason"], "budget_allocated")
        self.assertAlmostEqual(sum(allocations.values()), 12.0, places=3)
        self.assertEqual(allocator["preferred_stage"], "execute")
        self.assertGreater(allocations["execute"], allocations["parse"])
        self.assertGreater(allocations["parse"], allocations["capture"])
        self.assertEqual(missing["reason"], "missing_total_budget")
        self.assertFalse(missing["is_valid"])

