        groups = {row["role"]: row for row in registry["groups"]}

        self.assertTrue(registry["has_profiles"])
        self.assertFalse(registry["is_reusable"])
        self.assertEqual(registry["profile_count"], 4)
        self.assertEqual(registry["boundary_count"], 3)
        self.assertEqual(registry["negative_count"], 1)
        self.assertEqual(registry["duplicate_profile_ids"], ["p1"])
        self.assertEqual(rows["p2"]["case_kind"], "negative")
        self.assertEqual(groups["single"]["count"], 3)
        self.assertEqual(groups["single"]["boundary_count"], 2)
        self.assertEqual(groups["single"]["negative_count"], 1)
        self.assertEqual(groups["multi"]["count"], 1)
        self.assertTrue(registry["registry_id"])

