    def test_build_cross_answer_consistency_guard_detects_dependency_and_conflict_issues(self) -> None:
        consistent = screen_contracts.build_cross_answer_consistency_guard(
            answer_packets=[
                {"question_id": "q1", "answer_value": "yes"},
                {"question_id": "q2", "answer_value": "follow", "parent_question_id": "q1", "parent_answer": "yes", "trigger_answers": ["yes"]},
            ],
            dependency_map={"q2": {"parent_question_id": "q1", "trigger_answers": ["yes"]}},
        )
        inconsistent = screen_contracts.build_cross_answer_consistency_guard(
            answer_packets=[
                {"question_id": "q1", "answer_value": "no"},
                {"question_id": "q2", "answer_value": "follow", "parent_question_id": "q1", "parent_answer": "yes", "trigger_answers": ["yes"]},
                {"question_id": "q2", "answer_value": "alt"},
            ],
            dependency_map={"q2": {"parent_question_id": "q1", "trigger_answers": ["yes"]}},
        )

        self.assertTrue(consistent["is_consistent"])
        self.assertEqual(consistent["reason"], "cross_answer_consistent")
        self.assertEqual(consistent["inconsistent_count"], 0)

        self.assertFalse(inconsistent["is_consistent"])
        self.assertEqual(inconsistent["reason"], "cross_answer_inconsistent")
        self.assertGreaterEqual(inconsistent["inconsistent_count"], 1)
        reasons = {issue["reason"] for issue in inconsistent["issues"]}
        self.assertIn("duplicate_question_answer_conflict", reasons)
        self.assertIn("parent_answer_mismatch", reasons)

