    def test_build_parameter_tradeoff_model_summarizes_recall_precision_latency_and_risk(self) -> None:
        balanced = screen_contracts.build_parameter_tradeoff_model(
            focus_parameter="ocr_threshold",
            objective_metric="reduce parse failures",
            registry_contract={"registry_id": "reg-1"},
            tradeoff_rows=[
                {"parameter_name": "ocr_threshold", "recall_delta": 0.12, "precision_delta": 0.04, "latency_delta_ms": 18, "risk_delta": 0.08},
                {"parameter_name": "latency_budget_ms", "recall_delta": 0.01, "precision_delta": 0.0, "latency_delta_ms": -35, "risk_delta": 0.0},
            ],
        )
        risky = screen_contracts.build_parameter_tradeoff_model(
            focus_parameter="ocr_threshold",
            objective_metric="reduce parse failures",
            registry_contract={"registry_id": "reg-1"},
            tradeoff_rows=[
                {"parameter_name": "ocr_threshold", "recall_delta": 0.02, "precision_delta": -0.01, "latency_delta_ms": 220, "risk_delta": 0.31},
            ],
        )
        incomplete = screen_contracts.build_parameter_tradeoff_model(
            focus_parameter="",
            objective_metric="",
            registry_contract={},
            tradeoff_rows=[],
        )

        self.assertTrue(balanced["is_complete"])
        self.assertEqual(balanced["reason"], "parameter_tradeoff_model_balanced")
        self.assertEqual(balanced["dominant_axis"], "latency")
        self.assertFalse(risky["is_balanced"])
        self.assertTrue(risky["should_block"])
        self.assertEqual(risky["reason"], "parameter_tradeoff_model_risky")
        self.assertEqual(incomplete["reason"], "parameter_tradeoff_model_incomplete")
        self.assertFalse(incomplete["is_complete"])

    def test_build_tuning_guard_policy_limits_step_count_and_blast_radius(self) -> None:
        registry = screen_contracts.build_parameter_registry_contract(
            registry_name="experiment_parameters",
            registry_scope="canary",
            parameter_rows=[
                {"parameter_name": "ocr_threshold", "meaning": "Confidence threshold", "min_value": 0.2, "max_value": 0.95, "current_value": 0.6},
                {"parameter_name": "latency_budget_ms", "meaning": "Runtime budget", "min_value": 100, "max_value": 500, "current_value": 220},
            ],
        )
        allowed = screen_contracts.build_tuning_guard_policy(
            registry_contract=registry,
            max_step_size=0.2,
            max_changes_per_iteration=3,
            max_blast_radius=2,
            tuning_rows=[
                {"parameter_name": "ocr_threshold", "step_size": 0.08, "target_group": "ocr"},
                {"parameter_name": "latency_budget_ms", "step_size": 0.05, "target_group": "ocr"},
            ],
        )
        warned = screen_contracts.build_tuning_guard_policy(
            registry_contract=registry,
            max_step_size=0.2,
            max_changes_per_iteration=3,
            max_blast_radius=2,
            tuning_rows=[
                {"parameter_name": "ocr_threshold", "step_size": 0.17, "target_group": "ocr"},
                {"parameter_name": "latency_budget_ms", "step_size": 0.05, "target_group": "runtime"},
                {"parameter_name": "ocr_threshold", "step_size": 0.03, "target_group": "ocr"},
            ],
        )
        blocked = screen_contracts.build_tuning_guard_policy(
            registry_contract=registry,
            max_step_size=0.2,
            max_changes_per_iteration=2,
            max_blast_radius=1,
            tuning_rows=[
                {"parameter_name": "ocr_threshold", "step_size": 0.24, "target_group": "ocr"},
                {"parameter_name": "latency_budget_ms", "step_size": 0.05, "target_group": "runtime"},
            ],
        )

        self.assertTrue(allowed["is_allowed"])
        self.assertEqual(allowed["reason"], "tuning_guard_policy_allowed")
        self.assertTrue(warned["should_warn"])
        self.assertEqual(warned["reason"], "tuning_guard_policy_warn")
        self.assertFalse(blocked["is_allowed"])
        self.assertTrue(blocked["should_block"])
        self.assertEqual(blocked["reason"], "tuning_guard_policy_blocked")

