    def test_build_adoption_gate_contract_requires_main_metric_improvement_and_no_watchlist_harm(self) -> None:
        adoptable = screen_contracts.build_adoption_gate_contract(
            experiment_key="ocr_tuning",
            metric_rows=[
                {"metric_name": "recall", "baseline": 0.88, "candidate": 0.92, "higher_is_better": True},
                {"metric_name": "precision", "baseline": 0.85, "candidate": 0.87, "higher_is_better": True},
            ],
            watchlist_rows=[
                {"metric_name": "latency", "baseline": 220, "candidate": 215, "higher_is_better": False},
            ],
        )
        main_regression = screen_contracts.build_adoption_gate_contract(
            experiment_key="ocr_tuning",
            metric_rows=[
                {"metric_name": "recall", "baseline": 0.88, "candidate": 0.87, "higher_is_better": True},
            ],
            watchlist_rows=[],
        )
        watchlist_regression = screen_contracts.build_adoption_gate_contract(
            experiment_key="ocr_tuning",
            metric_rows=[
                {"metric_name": "recall", "baseline": 0.88, "candidate": 0.92, "higher_is_better": True},
            ],
            watchlist_rows=[
                {"metric_name": "latency", "baseline": 215, "candidate": 235, "higher_is_better": False},
            ],
        )

        self.assertTrue(adoptable["is_adoptable"])
        self.assertEqual(adoptable["reason"], "adoption_gate_contract_passed")
        self.assertFalse(main_regression["is_adoptable"])
        self.assertEqual(main_regression["reason"], "adoption_gate_contract_main_metric_regression")
        self.assertFalse(watchlist_regression["is_adoptable"])
