        regressed = screen_contracts.build_intervention_regression_suite(
            before_runs=[
                {"kind": "override"},
            ],
            after_runs=[
                {"kind": "override"},
                {"kind": "assisted"},
            ],
        )

        self.assertEqual(improved["status"], "improved")
