        self.assertTrue(improved["is_improved"])

        self.assertEqual(regressed["status"], "regressed")
        self.assertEqual(regressed["reason"], "intervention_count_increased")
        self.assertTrue(regressed["is_regressed"])
        self.assertGreater(regressed["after_manual_count"], regressed["before_manual_count"])

