        self.assertEqual(first["target_instance_id"], second["target_instance_id"])
        self.assertEqual(first["reason"], "target_instance_bound")
        self.assertTrue(first["is_stable"])
        self.assertNotEqual(first["target_instance_id"], changed["target_instance_id"])
        self.assertEqual(changed["reason"], "target_instance_bound")

