    def test_build_target_resolution_regression_suite_detects_drift(self) -> None:
        reference_identity = screen_contracts.build_target_identity_contract(
            role="button",
            text="Next",
            target_bbox=[10, 20, 120, 48],
            selector="button.next",
            frame_path="main>survey",
        )
        passing = screen_contracts.build_target_resolution_regression_suite(
            regression_cases=[
                {
                    "case_id": "case-1",
                    "snapshot": {
                        "role": "button",
                        "text": "Next",
                        "target_bbox": [10, 20, 120, 48],
                        "selector": "button.next",
                        "frame_path": "main>survey",
                    },
                    "expected": {"target_identity": reference_identity["target_identity"], "is_stable": True},
                }
            ]
        )
        failing = screen_contracts.build_target_resolution_regression_suite(
            regression_cases=[
                {
                    "case_id": "case-2",
                    "snapshot": {
                        "role": "button",
                        "text": "Continue",
                        "target_bbox": [10, 20, 120, 48],
                        "selector": "button.continue",
                        "frame_path": "main>survey",
                    },
                    "expected": {"target_identity": reference_identity["target_identity"], "is_stable": True},
                }
            ]
        )

        self.assertTrue(passing["is_passing"])
        self.assertEqual(passing["reason"], "regression_suite_passed")
        self.assertEqual(passing["passed_cases"], 1)
        self.assertFalse(failing["is_passing"])
        self.assertEqual(failing["reason"], "regression_suite_failed")
        self.assertEqual(failing["drift_cases"], 1)
        self.assertTrue(failing["rows"][0]["is_drift"])

