    def test_build_ambiguous_target_escalation_rule_routes_ambiguous_targets(self) -> None:
        observe = screen_contracts.build_ambiguous_target_escalation_rule(
            context_scope_guard={"is_allowed": False, "ambiguous": True},
            resilient_replay_target_policy={"is_stable": True, "strategy": "identity_bundle_frame"},
            parser_executor_target_alignment_check={"aligned": True, "confidence_gap": 0.08},
            ambiguity_threshold=0.7,
        )
        lead = screen_contracts.build_ambiguous_target_escalation_rule(
            context_scope_guard={"is_allowed": True, "ambiguous": True},
            resilient_replay_target_policy={"is_stable": False, "strategy": "re-parse"},
            parser_executor_target_alignment_check={"aligned": False, "confidence_gap": 0.32},
            ambiguity_threshold=0.9,
        )
        stable = screen_contracts.build_ambiguous_target_escalation_rule(
            context_scope_guard={"is_allowed": True, "ambiguous": False},
            resilient_replay_target_policy={"is_stable": True, "strategy": "identity_bundle_frame"},
            parser_executor_target_alignment_check={"aligned": True, "confidence_gap": 0.02},
            ambiguity_threshold=0.5,
        )

        self.assertEqual(observe["escalation"], "observe")
        self.assertEqual(observe["reason"], "context_not_allowed")
        self.assertEqual(observe["next_best_action"], "collect_more_evidence")
        self.assertTrue(observe["should_escalate"])

        self.assertEqual(lead["escalation"], "lead")
        self.assertEqual(lead["reason"], "parser_executor_mismatch")
        self.assertEqual(lead["next_best_action"], "ask_lead_for_target_resolution")
        self.assertTrue(lead["should_escalate"])

        self.assertEqual(stable["escalation"], "none")
        self.assertEqual(stable["reason"], "stable_resolution")
        self.assertEqual(stable["next_best_action"], "proceed")
        self.assertFalse(stable["should_escalate"])

