    def test_build_session_reset_policy_engine_distinguishes_reset_scope(self) -> None:
        clean_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-clean",
            browser_state={
                "cookies": [],
                "storage": {},
                "cache": [],
                "consent": {},
            },
        )
        dirty_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-dirty",
            cookies_state=[{"name": "sid", "value": "abc"}],
            storage_state={"localStorage": {"theme": "dark"}, "sessionStorage": {"step": "2"}},
            cache_state={"entries": ["page-cache"]},
            consent_state={"accepted": True},
        )
        clean_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=clean_identity,
            dirty_signals=[],
            strict_reset=False,
        )
        dirty_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=dirty_identity,
            dirty_signals=["cookies", "storage", "cache", "indexeddb", "service_worker_cache"],
            strict_reset=False,
        )
        strict_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=clean_identity,
            dirty_signals=[],
            strict_reset=True,
        )

        self.assertEqual(clean_policy["reset_scope"], "none")
        self.assertEqual(clean_policy["reason"], "fresh_session")
        self.assertFalse(clean_policy["should_reset"])
        self.assertTrue(clean_policy["is_safe_to_start"])

        self.assertEqual(dirty_policy["reset_scope"], "full")
        self.assertEqual(dirty_policy["reason"], "consent_or_state_drift")
        self.assertTrue(dirty_policy["should_reset"])
        self.assertIn("clear_cookies", dirty_policy["reset_actions"])
        self.assertIn("clear_storage", dirty_policy["reset_actions"])
        self.assertIn("clear_cache", dirty_policy["reset_actions"])

        self.assertEqual(strict_policy["reset_scope"], "full")
        self.assertEqual(strict_policy["reason"], "strict_reset")
        self.assertTrue(strict_policy["should_reset"])

    def test_build_pre_run_session_hygiene_check_blocks_dirty_sessions(self) -> None:
        clean_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-clean",
            browser_state={"cookies": [], "storage": {}, "cache": [], "consent": {}},
        )
        dirty_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-dirty",
            cookies_state=[{"name": "sid", "value": "abc"}],
            storage_state={"localStorage": {"theme": "dark"}},
            cache_state={"entries": ["page-cache"]},
            consent_state={"accepted": True},
        )
        clean_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=clean_identity,
            dirty_signals=[],
            strict_reset=False,
        )
        dirty_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=dirty_identity,
            dirty_signals=["cookies", "storage"],
            strict_reset=False,
        )
        clean_check = screen_contracts.build_pre_run_session_hygiene_check(
            browser_session_identity=clean_identity,
            session_reset_policy_engine=clean_policy,
            scenario_profile={"requires_clean_start": True},
        )
        dirty_check = screen_contracts.build_pre_run_session_hygiene_check(
            browser_session_identity=dirty_identity,
            session_reset_policy_engine=dirty_policy,
            scenario_profile={"requires_clean_start": True},
        )
        warn_check = screen_contracts.build_pre_run_session_hygiene_check(
            browser_session_identity=dirty_identity,
            session_reset_policy_engine={
                "reset_scope": "partial",
                "should_reset": True,
                "dirty_signals": ["cookies"],
            },
            scenario_profile={"requires_clean_start": False},
        )

        self.assertEqual(clean_check["hygiene_status"], "pass")
        self.assertEqual(clean_check["reason"], "fresh_session")
        self.assertFalse(clean_check["should_block_start"])

        self.assertEqual(dirty_check["hygiene_status"], "block")
        self.assertEqual(dirty_check["reason"], "dirty_session_requires_reset")
        self.assertTrue(dirty_check["should_block_start"])
        self.assertEqual(dirty_check["hygiene_score"], 0.0)

        self.assertEqual(warn_check["hygiene_status"], "warn")
        self.assertEqual(warn_check["reason"], "partial_reset_required")
        self.assertTrue(warn_check["should_warn"])

    def test_build_session_state_packet_includes_session_hygiene_context(self) -> None:
        dirty_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-dirty",
            cookies_state=[{"name": "sid", "value": "abc"}],
            storage_state={"localStorage": {"theme": "dark"}},
            cache_state={"entries": ["page-cache"]},
            consent_state={"accepted": True},
        )
        reset_policy = screen_contracts.build_session_reset_policy_engine(
            browser_session_identity=dirty_identity,
            dirty_signals=["cookies", "storage"],
            strict_reset=False,
        )
        hygiene = screen_contracts.build_pre_run_session_hygiene_check(
            browser_session_identity=dirty_identity,
            session_reset_policy_engine=reset_policy,
            scenario_profile={"requires_clean_start": True},
        )
        packet = screen_contracts.build_session_state_packet(
            browser_session_identity=dirty_identity,
            session_reset_policy_engine=reset_policy,
            pre_run_session_hygiene_check=hygiene,
            trace_id="trace-123",
            checkpoint_id="checkpoint-456",
        )
        second_packet = screen_contracts.build_session_state_packet(
            browser_session_identity=dirty_identity,
            session_reset_policy_engine=reset_policy,
            pre_run_session_hygiene_check=hygiene,
            trace_id="trace-123",
            checkpoint_id="checkpoint-456",
        )

        self.assertEqual(packet["session_id"], "sess-dirty")
        self.assertEqual(packet["trace_id"], "trace-123")
        self.assertEqual(packet["checkpoint_id"], "checkpoint-456")
        self.assertEqual(packet["hygiene_status"], "block")
        self.assertEqual(packet["worker_readiness"], "blocked")
        self.assertTrue(packet["replay_allowed"] is False)
        self.assertTrue(packet["should_block_start"])
        self.assertEqual(packet["browser_session_key"], dirty_identity["browser_session_key"])
        self.assertEqual(packet["packet_id"], second_packet["packet_id"])
        self.assertIn("clear_cookies", packet["reset_actions"])

