    def test_build_unknown_side_state_guard_blocks_missing_context_and_observes_ambiguity(self) -> None:
        known_identity = screen_contracts.build_browser_session_identity(
            session_id="sess-known",
            browser_state={"cookies": [], "storage": {}, "cache": [], "consent": {}},
        )
        known_snapshot = screen_contracts.build_client_state_snapshot(
            url="https://example.test/survey",
            cookies_state=[],
            storage_state={},
            service_worker_state={},
            browser_session_identity=known_identity,
        )
        known_consent = screen_contracts.build_consent_state_contract(
            consent_state={"accepted": True, "status": "accepted"},
            browser_session_identity=known_identity,
        )
        known_flags = screen_contracts.build_client_flag_fingerprint(
            feature_flags={"survey_v2": True},
            experiment_state={"survey_v2": "variant_b"},
            client_state_snapshot=known_snapshot,
            browser_session_identity=known_identity,
        )
        reset_guard = screen_contracts.build_unknown_side_state_guard(
            browser_session_identity={},
            client_state_snapshot={},
            consent_state_contract={},
            client_flag_fingerprint={},
        )
        observe_guard = screen_contracts.build_unknown_side_state_guard(
            browser_session_identity=known_identity,
            client_state_snapshot=known_snapshot,
            consent_state_contract=known_consent,
            client_flag_fingerprint={
                **known_flags,
                "unstable_flags": ["shadow_mode"],
            },
            allow_observe=True,
        )
        proceed_guard = screen_contracts.build_unknown_side_state_guard(
            browser_session_identity=known_identity,
            client_state_snapshot=known_snapshot,
            consent_state_contract=known_consent,
            client_flag_fingerprint=known_flags,
            allow_observe=True,
        )

        self.assertEqual(reset_guard["state"], "reset")
        self.assertEqual(reset_guard["reason"], "missing_session_context")
        self.assertTrue(reset_guard["should_block"])

        self.assertEqual(observe_guard["state"], "observe")
        self.assertEqual(observe_guard["reason"], "ambiguous_side_state")
        self.assertTrue(observe_guard["should_observe"])
        self.assertIn("shadow_mode", observe_guard["unstable_flags"])

        self.assertEqual(proceed_guard["state"], "proceed")
        self.assertEqual(proceed_guard["reason"], "known_side_state")
        self.assertTrue(proceed_guard["should_proceed"])

    def test_build_session_vs_logic_root_cause_splitter_separates_session_drift_from_logic_failure(self) -> None:
        identity = screen_contracts.build_browser_session_identity(
            session_id="sess-1",
            browser_state={"cookies": [], "storage": {}, "cache": [], "consent": {}},
        )
        snapshot = screen_contracts.build_client_state_snapshot(
            url="https://example.test/survey",
            cookies_state=[],
            storage_state={},
            service_worker_state={},
            browser_session_identity=identity,
        )
        drift = screen_contracts.build_state_side_effect_diff(
            state_before={"theme": "dark"},
            state_after={"theme": "dark", "consent_state": {"accepted": True}},
            browser_session_identity=identity,
        )
        guard = screen_contracts.build_unknown_side_state_guard(
            browser_session_identity=identity,
            client_state_snapshot=snapshot,
            consent_state_contract={"state": "blocked"},
            client_flag_fingerprint={"unstable_flags": ["shadow_mode"]},
        )
        session_case = screen_contracts.build_session_vs_logic_root_cause_splitter(
            browser_session_identity=identity,
            client_state_snapshot=snapshot,
            state_side_effect_diff=drift,
            unknown_side_state_guard=guard,
        )
        logic_case = screen_contracts.build_session_vs_logic_root_cause_splitter(
            browser_session_identity={"session_id": "sess-2"},
            client_state_snapshot={"snapshot_id": "snap-2", "is_ambient_state_dirty": False},
            state_side_effect_diff={"has_state_change": True, "impact_scope": "low", "reason": "state_delta_detected"},
            unknown_side_state_guard={"state": "proceed", "reason": "known_side_state"},
        )

        self.assertEqual(session_case["root_cause"], "session_state_drift")
        self.assertEqual(session_case["reason"], "side_state_drift")
        self.assertTrue(session_case["should_escalate_to_lead"])
        self.assertGreaterEqual(session_case["confidence"], 0.74)

        self.assertEqual(logic_case["root_cause"], "logic_failure")
        self.assertEqual(logic_case["reason"], "logic_failure_without_side_state")
        self.assertFalse(logic_case["should_escalate_to_lead"])
        self.assertGreaterEqual(logic_case["confidence"], 0.7)

