    def test_build_request_outcome_contract_normalizes_success_retry_timeout_and_cancel(self) -> None:
        success = screen_contracts.build_request_outcome_contract(
            request_event={"method": "POST", "url": "https://example.test/api/submit"},
            response_event={"status_code": 200, "body": {"ok": True}},
        )
        retry = screen_contracts.build_request_outcome_contract(
            request_event={"method": "GET", "url": "https://example.test/api/next"},
            response_event={"status_code": 503},
            retry_event={"retry_count": 1},
        )
        timeout = screen_contracts.build_request_outcome_contract(
            request_event={"method": "POST", "url": "https://example.test/api/submit"},
            response_event={"status": "timeout"},
            timeout_event={"timed_out": True},
        )
        cancel = screen_contracts.build_request_outcome_contract(
            request_event={"method": "POST", "url": "https://example.test/api/submit", "canceled": True},
            response_event={},
        )

        self.assertEqual(success["outcome_type"], "success")
        self.assertTrue(success["is_success"])
        self.assertTrue(success["is_terminal"])

        self.assertEqual(retry["outcome_type"], "retry")
        self.assertTrue(retry["should_retry"])
        self.assertFalse(retry["is_success"])

        self.assertEqual(timeout["outcome_type"], "timeout")
        self.assertTrue(timeout["timed_out"])
        self.assertFalse(timeout["is_terminal"])

        self.assertEqual(cancel["outcome_type"], "cancel")
        self.assertTrue(cancel["canceled"])
        self.assertTrue(cancel["is_terminal"])

