    def test_build_response_semantic_validator_classifies_success_warning_refusal_and_partial_failure(self) -> None:
        success = screen_contracts.build_response_semantic_validator(
            request_event={"action": "submit"},
            response_event={"status_code": 200, "ok": True, "body": {"saved": True}},
            screen_state={"screen_changed": True},
        )
        warning = screen_contracts.build_response_semantic_validator(
            request_event={"action": "submit"},
            response_event={"status_code": 200, "warning": True, "body": {"warning": "partial"}},
            screen_state={"screen_changed": False},
        )
        refusal = screen_contracts.build_response_semantic_validator(
            request_event={"action": "submit"},
            response_event={"status_code": 403, "body": "refused by policy"},
            screen_state={"screen_changed": False},
        )
        partial = screen_contracts.build_response_semantic_validator(
            request_event={"action": "save_draft"},
            response_event={"status_code": 500, "body": {"error": "server error"}},
            screen_state={"screen_changed": False},
        )

        self.assertEqual(success["semantic"], "success")
        self.assertTrue(success["is_success"])
        self.assertFalse(success["should_notify_planner"])

        self.assertEqual(warning["semantic"], "warning")
        self.assertTrue(warning["is_warning"])
        self.assertTrue(warning["should_notify_planner"])

        self.assertEqual(refusal["semantic"], "hidden_refusal")
        self.assertTrue(refusal["is_hidden_refusal"])
        self.assertTrue(refusal["should_notify_planner"])

        self.assertEqual(partial["semantic"], "partial_failure")
        self.assertTrue(partial["is_partial_failure"])
        self.assertTrue(partial["should_notify_planner"])

    def test_build_api_drift_guard_detects_schema_and_role_drift(self) -> None:
        stable = screen_contracts.build_api_drift_guard(
            expected_request_schema={"role": "validate", "payload": {"field": "value"}},
            expected_response_schema={"role": "validate", "ok": True},
            current_request={"role": "validate", "payload": {"field": "value"}},
            current_response={"role": "validate", "ok": True},
            endpoint_role_registry={"expected_role": "validate"},
        )
        drifted = screen_contracts.build_api_drift_guard(
            expected_request_schema={"role": "validate", "payload": {"field": "value"}},
            expected_response_schema={"role": "validate", "ok": True},
            current_request={"role": "validate", "payload": {"field": "value"}, "extra": 1},
            current_response={"role": "submit", "ok": "yes", "extra": True},
            endpoint_role_registry={"expected_role": "validate"},
        )

        self.assertEqual(stable["severity"], "none")
        self.assertEqual(stable["reason"], "api_stable")
        self.assertTrue(stable["is_stable"])
        self.assertFalse(stable["should_escalate"])
        self.assertFalse(stable["request_drift"])
        self.assertFalse(stable["response_drift"])

        self.assertEqual(drifted["severity"], "high")
        self.assertEqual(drifted["reason"], "api_role_and_schema_drift")
        self.assertTrue(drifted["should_escalate"])
        self.assertFalse(drifted["is_stable"])
        self.assertTrue(drifted["request_drift"])
        self.assertTrue(drifted["response_drift"])
        self.assertTrue(drifted["role_mismatch"])
        self.assertIn("extra", drifted["changed_request_keys"])
        self.assertIn("extra", drifted["changed_response_keys"])
        self.assertTrue(drifted["type_changes"])

