    def test_build_confidence_override_policy_requires_strong_evidence(self) -> None:
        keep = screen_contracts.build_confidence_override_policy(
            confidence=0.8,
            confidence_floor=0.65,
            evidence_strength=0.4,
            supporting_signals=0,
        )
