    def test_build_artifact_migration_verifier_detects_missing_and_version_mismatch_artifacts(self) -> None:
        verifier = screen_contracts.build_artifact_migration_verifier(
            artifacts={
                "snapshot": {"schema_version": screen_contracts.SCHEMA_VERSION, "content_hash": "abc"},
                "report": {"schema_version": "old.v1", "content_hash": "def"},
                "embeddings": {},
            },
            expected_versions={
                "snapshot": screen_contracts.SCHEMA_VERSION,
                "report": screen_contracts.SCHEMA_VERSION,
                "embeddings": screen_contracts.SCHEMA_VERSION,
            },
        )
        rows = {row["name"]: row for row in verifier["rows"]}
        self.assertFalse(verifier["all_readable"])
        self.assertEqual(rows["snapshot"]["status"], "readable")
