    def test_build_change_failure_abort_rule_triggers_on_latency_drift_and_side_effects(self) -> None:
        abort = screen_contracts.build_change_failure_abort_rule(
            latency_ms=1800,
            max_latency_ms=1200,
            drift_score=0.42,
            max_drift_score=0.3,
            error_taxonomy={"has_unknown_labels": True},
            side_effect_watchdog={"is_blocking": True, "reason": "request_spike_detected"},
        )
        safe = screen_contracts.build_change_failure_abort_rule(
            latency_ms=800,
            max_latency_ms=1200,
            drift_score=0.1,
            max_drift_score=0.3,
            error_taxonomy={"has_unknown_labels": False},
            side_effect_watchdog={"is_blocking": False, "reason": "no_unsafe_side_effects"},
        )
        self.assertTrue(abort["should_abort"])
        self.assertIn("latency_exceeded", abort["reasons"])
        self.assertIn("drift_exceeded", abort["reasons"])
        self.assertIn("unknown_error_taxonomy", abort["reasons"])
        self.assertIn("request_spike_detected", abort["reasons"])
        self.assertFalse(safe["should_abort"])
        self.assertEqual(safe["reasons"], ["within_abort_budget"])

    def test_slow_iteration_abort_rule_triggers_only_when_budget_is_exceeded_without_recovery(self) -> None:
        abort = screen_contracts.build_slow_iteration_abort_rule(
            iteration_duration_s=8.5,
            max_iteration_duration_s=6.0,
            recovery_chance=0.2,
            no_progress_count=3,
            max_no_progress_count=2,
        )
        recoverable = screen_contracts.build_slow_iteration_abort_rule(
            iteration_duration_s=8.5,
            max_iteration_duration_s=6.0,
            recovery_chance=0.8,
            no_progress_count=1,
            max_no_progress_count=2,
        )
        within = screen_contracts.build_slow_iteration_abort_rule(
            iteration_duration_s=4.0,
            max_iteration_duration_s=6.0,
            recovery_chance=0.1,
            no_progress_count=0,
            max_no_progress_count=2,
        )
        self.assertTrue(abort["should_abort"])
        self.assertEqual(abort["reason"], "slow_iteration_no_recovery")
        self.assertTrue(abort["signals"]["over_budget"])
        self.assertFalse(recoverable["should_abort"])
        self.assertEqual(recoverable["reason"], "slow_but_recoverable")
        self.assertFalse(within["should_abort"])
        self.assertEqual(within["reason"], "within_iteration_budget")

    def test_site_latency_profile_builds_host_and_family_baselines(self) -> None:
        profile = screen_contracts.build_site_latency_profile(
            site_records=[
                {"host": "survey.example.com", "survey_family": "family-a", "latency_ms": 1000},
                {"host": "survey.example.com", "survey_family": "family-a", "latency_ms": 1200},
                {"host": "survey.example.com", "survey_family": "family-a", "latency_ms": 1300},
                {"host": "shop.example.com", "survey_family": "family-b", "latency_ms": 1800},
            ],
            host_budget_s=1.4,
            family_budget_s=1.35,
        )
        host_rows = {row["host"]: row for row in profile["host_profiles"]}
        family_rows = {row["survey_family"]: row for row in profile["family_profiles"]}
        self.assertFalse(profile["is_stable"])
        self.assertAlmostEqual(host_rows["survey.example.com"]["median_ms"], 1200.0, places=2)
        self.assertAlmostEqual(host_rows["survey.example.com"]["p95_ms"], 1300.0, places=2)
        self.assertTrue(host_rows["survey.example.com"]["is_stable"])
        self.assertFalse(host_rows["shop.example.com"]["is_stable"])
        self.assertIn("shop.example.com", profile["unstable_hosts"])
        self.assertTrue(family_rows["family-a"]["is_stable"])
        self.assertFalse(family_rows["family-b"]["is_stable"])
        self.assertIn("family-b", profile["unstable_families"])

