    def test_execution_mode_switcher_prefers_inline_for_small_runs_and_daemon_for_heavy_runs(self) -> None:
        inline = screen_contracts.build_execution_mode_switcher(
            startup_cost_ms=120.0,
            task_volume=1,
            inline_cost_budget_ms=300.0,
            daemon_startup_threshold_ms=1000.0,
            daemon_task_threshold=5,
        )
        daemon_by_cost = screen_contracts.build_execution_mode_switcher(
            startup_cost_ms=1500.0,
            task_volume=1,
            inline_cost_budget_ms=300.0,
            daemon_startup_threshold_ms=1000.0,
            daemon_task_threshold=5,
        )
        daemon_by_volume = screen_contracts.build_execution_mode_switcher(
            startup_cost_ms=120.0,
            task_volume=7,
            inline_cost_budget_ms=300.0,
            daemon_startup_threshold_ms=1000.0,
            daemon_task_threshold=5,
        )
        self.assertEqual(inline["mode"], "inline")
