    def test_build_rollback_trigger_policy_triggers_on_runtime_degradation(self) -> None:
        stable = screen_contracts.build_rollback_trigger_policy(
            readback_fail_rate=0.08,
            blocked_rate=0.12,
            end_state_mismatch_rate=0.07,
            max_readback_fail_rate=0.2,
            max_blocked_rate=0.25,
            max_end_state_mismatch_rate=0.15,
        )
        degraded = screen_contracts.build_rollback_trigger_policy(
            readback_fail_rate=0.28,
            blocked_rate=0.31,
            end_state_mismatch_rate=0.19,
            max_readback_fail_rate=0.2,
            max_blocked_rate=0.25,
            max_end_state_mismatch_rate=0.15,
        )
        self.assertFalse(stable["should_rollback"])
        self.assertEqual(stable["reasons"], ["within_rollback_budget"])
        self.assertTrue(degraded["should_rollback"])
        self.assertIn("readback_fail_rate_exceeded", degraded["reasons"])
        self.assertIn("blocked_rate_exceeded", degraded["reasons"])
        self.assertIn("end_state_mismatch_rate_exceeded", degraded["reasons"])

