    def test_build_form_validation_runtime_engine_detects_required_and_format_violations(self) -> None:
        invalid = screen_contracts.build_form_validation_runtime_engine(
            field_specs=[
                {"field_id": "email", "field_kind": "email", "required": True},
                {"field_id": "age", "field_kind": "number", "min_value": 18, "max_value": 30},
                {"field_id": "tags", "field_kind": "multi", "max_selected": 2},
            ],
            runtime_values={"email": "bad-email", "age": "17", "tags": ["a", "b", "c"]},
        )
        valid = screen_contracts.build_form_validation_runtime_engine(
            field_specs=[
                {"field_id": "email", "field_kind": "email", "required": True},
                {"field_id": "age", "field_kind": "number", "min_value": 18, "max_value": 30},
                {"field_id": "tags", "field_kind": "multi", "max_selected": 2},
            ],
            runtime_values={"email": "user@example.com", "age": "22", "tags": ["a", "b"]},
        )

        self.assertFalse(invalid["is_valid"])
        self.assertEqual(invalid["reason"], "runtime_validation_failed")
        self.assertGreater(invalid["violation_total"], 0)
        self.assertGreater(invalid["violation_counts"]["format"], 0)
        self.assertGreater(invalid["violation_counts"]["range"], 0)
        self.assertGreater(invalid["violation_counts"]["selection"], 0)

        self.assertTrue(valid["is_valid"])
        self.assertEqual(valid["reason"], "runtime_validation_passed")
        self.assertEqual(valid["violation_total"], 0)

