    def test_build_secret_source_policy_distinguishes_allowed_review_and_block_states(self) -> None:
        allowed = build_secret_source_policy(
            test_data_governance_packet={
                "environment": "staging",
                "secret_source": "environment",
                "requested_secret_names": ["API_TOKEN"],
                "loaded_secret_names": ["API_TOKEN"],
            }
        )
        self.assertTrue(allowed["is_allowed"])
        self.assertEqual(allowed["reason"], "approved_secret_source")

        review = build_secret_source_policy(
            test_data_governance_packet={
                "environment": "production",
                "secret_source": "env_file",
                "requested_secret_names": ["API_TOKEN"],
                "loaded_secret_names": ["API_TOKEN"],
            },
            allow_review=False,
        )
        self.assertTrue(review["requires_review"])
        self.assertTrue(review["is_blocking"])
        self.assertEqual(review["reason"], "production_env_file_source")

        blocked = build_secret_source_policy(
            test_data_governance_packet={
                "environment": "staging",
                "secret_source": "inline_literal",
                "requested_secret_names": ["API_TOKEN"],
                "loaded_secret_names": ["API_TOKEN"],
            }
        )
        self.assertFalse(blocked["is_allowed"])
        self.assertEqual(blocked["reason"], "unknown_secret_source")

        allowed_review = build_secret_source_policy(
            test_data_governance_packet={
                "environment": "production",
                "secret_source": "env_file",
                "requested_secret_names": ["API_TOKEN"],
                "loaded_secret_names": ["API_TOKEN"],
            },
            allow_review=True,
        )
        self.assertTrue(allowed_review["requires_review"])
        self.assertFalse(allowed_review["is_blocking"])

