    def test_operational_watchdog_state_maps_retry_fallback_and_abort(self) -> None:
        retry = build_operational_watchdog_state(
            runtime_state={
                "stuck_detection": {"no_progress": True, "is_stuck": False, "attempt_count": 1, "consecutive_no_progress_count": 1},
                "recovery": {"level": 1, "action": "retry_same_action", "reason": "single_no_progress", "should_retry_same_action": True},
            },
            iteration=1,
            max_steps=5,
        )
        self.assertEqual(retry["decision"], "retry")

        fallback = build_operational_watchdog_state(
            runtime_state={
                "stuck_detection": {"no_progress": True, "is_stuck": True, "attempt_count": 2, "consecutive_no_progress_count": 2},
                "recovery": {"level": 2, "action": "dom_fallback", "reason": "repeat_no_progress", "should_use_dom_fallback": True},
            },
            iteration=2,
            max_steps=5,
        )
        self.assertEqual(fallback["decision"], "fallback")

        abort = build_operational_watchdog_state(
            runtime_state={
                "stuck_detection": {"no_progress": True, "is_stuck": True, "attempt_count": 3, "consecutive_no_progress_count": 3},
                "recovery": {"level": 3, "action": "abort_iteration", "reason": "max_retries_without_progress", "should_abort": True},
            },
            iteration=3,
            max_steps=5,
        )
        self.assertEqual(abort["decision"], "abort")

    def test_allowed_context_policy_blocks_login_and_allows_survey(self) -> None:
        survey = build_allowed_context_policy(
            screen_state={"question_text": "Question 1", "options": [{"text": "Blue"}]},
            page_data={"title": "Survey", "pageText": "Question 1\nNext"},
            allowlist_state={"is_allowed": True, "current_host": "quiz.example.com"},
            wrong_context_recovery_policy={"recommended_action": "continue"},
        )
        self.assertTrue(survey["is_allowed"])
        self.assertEqual(survey["page_intent"], "survey")

        login = build_allowed_context_policy(
            screen_state={"question_text": "Sign in to continue", "options": []},
            page_data={"title": "Login", "pageText": "Sign in to continue"},
            allowlist_state={"is_allowed": True, "current_host": "quiz.example.com"},
            wrong_context_recovery_policy={"recommended_action": "continue"},
        )
        self.assertFalse(login["is_allowed"])
        self.assertEqual(login["reason"], "page_intent:login")

    def test_frame_context_guard_blocks_foreign_frame(self) -> None:
        clear = build_frame_context_guard(
            page_data={"frames": [{"url": "https://quiz.example.com/frame", "name": "quiz"}]},
            current_url="https://quiz.example.com/q/1",
        )
        self.assertTrue(clear["is_allowed"])

        blocked = build_frame_context_guard(
            page_data={"frames": [{"url": "https://payments.example.org/checkout", "name": "pay"}]},
            current_url="https://quiz.example.com/q/1",
        )
        self.assertFalse(blocked["is_allowed"])
        self.assertEqual(blocked["reason"], "foreign_frame_requires_confirmation")

    def test_action_rate_limiter_returns_non_negative_delay(self) -> None:
        first = apply_action_rate_limit(action_kind="screen_click", reason="click", history=[], now_ts=100.0, min_interval_s=0.0)
        second = apply_action_rate_limit(
            action_kind="screen_click",
            reason="click",
            history=first["history"],
            now_ts=100.0,
            min_interval_s=0.1,
        )
        self.assertTrue(first["allowed"])
        self.assertFalse(second["allowed"])
        self.assertGreaterEqual(second["wait_ms"], 0)

