    def test_build_empty_signal_identity_distinguishes_blank_ocr_target_and_network_absence(self) -> None:
        blank = screen_contracts.build_empty_signal_identity(
            blank_screen_detection={"is_blank": True},
            ocr_rows=[],
            target_rows=[],
            network_rows=[],
        )
        no_ocr = screen_contracts.build_empty_signal_identity(
            blank_screen_detection={"is_blank": False},
            ocr_rows=[],
            target_rows=[{"id": "t1"}],
            network_rows=[{"id": "n1"}],
        )
        no_targets = screen_contracts.build_empty_signal_identity(
            blank_screen_detection={"is_blank": False},
            ocr_rows=[{"text": "Question"}],
            target_rows=[],
            network_rows=[{"id": "n1"}],
            screen_state={"question_text": "Question"},
        )
        no_network = screen_contracts.build_empty_signal_identity(
            blank_screen_detection={"is_blank": False},
            ocr_rows=[{"text": "Question"}],
            target_rows=[{"id": "t1"}],
            network_rows=[],
            screen_state={"question_text": "Question"},
        )

        self.assertEqual(blank["empty_kind"], "empty_screenshot")
        self.assertTrue(blank["should_block"])
        self.assertEqual(no_ocr["empty_kind"], "missing_ocr")
        self.assertTrue(no_ocr["should_block"])
        self.assertEqual(no_targets["empty_kind"], "missing_targets")
        self.assertEqual(no_network["empty_kind"], "missing_network_events")

    def test_build_evidence_absence_taxonomy_classifies_absence_rows_and_flags_blocking_patterns(self) -> None:
        taxonomy = screen_contracts.build_evidence_absence_taxonomy(
            absence_rows=[
                {"name": "missing evidence"},
                {"name": "sparse sample", "is_low": True},
                {"name": "garbled payload", "is_corrupted": True},
                {"name": "conflict report", "is_contradictory": True},
                {"name": "masked note", "is_hidden": True},
            ],
            evidence_identity={"evidence_identity_id": "evidence-123"},
            ignorance_packet={"unknown_items": ["unknown item"]},
        )
        empty = screen_contracts.build_evidence_absence_taxonomy(
            absence_rows=[],
            evidence_identity={},
            ignorance_packet={},
        )

        self.assertEqual(taxonomy["reason"], "evidence_absence_taxonomy_classified")
        self.assertTrue(taxonomy["is_classified"])
        self.assertTrue(taxonomy["should_warn"])
        self.assertTrue(taxonomy["should_block"])
        self.assertEqual(taxonomy["counts"]["no_data"], 1)
        self.assertEqual(taxonomy["counts"]["low_data"], 1)
        self.assertEqual(taxonomy["counts"]["corrupted_data"], 1)
        self.assertEqual(taxonomy["counts"]["contradictory_data"], 1)
        self.assertEqual(taxonomy["counts"]["hidden_data"], 1)
        self.assertEqual(taxonomy["unknown_rows"], ["unknown item"])
        self.assertEqual(taxonomy["evidence_identity_id"], "evidence-123")
        self.assertEqual(empty["reason"], "evidence_absence_taxonomy_incomplete")
        self.assertFalse(empty["is_classified"])
        self.assertFalse(empty["should_block"])

    def test_build_ignorance_contract_and_sparse_context_hint_allow_non_forced_outcomes(self) -> None:
        taxonomy = screen_contracts.build_evidence_absence_taxonomy(
            absence_rows=[
                {"name": "garbled payload", "is_corrupted": True},
            ],
            evidence_identity={"evidence_identity_id": "evidence-123"},
            ignorance_packet={"unknown_items": ["mystery"]},
        )
        allowed = screen_contracts.build_ignorance_contract(
            signal_rows=[],
            selected_outcome="defer",
            evidence_absence_taxonomy=taxonomy,
        )
        blocked = screen_contracts.build_ignorance_contract(
            signal_rows=[],
            selected_outcome="click_answer",
            evidence_absence_taxonomy=taxonomy,
        )
        hint = screen_contracts.build_sparse_context_hint(
            evidence_identity={"evidence_identity_id": "evidence-123"},
            evidence_absence_taxonomy=taxonomy,
            ignorance_contract=allowed,
        )

        self.assertTrue(allowed["zero_signal"])
        self.assertFalse(allowed["should_block"])
        self.assertEqual(allowed["reason"], "ignorance_contract_zero_signal_allowed")
        self.assertTrue(blocked["should_block"])
        self.assertEqual(blocked["reason"], "ignorance_contract_forced_action_blocked")
        self.assertEqual(hint["context_state"], "partial")
        self.assertTrue(hint["should_defer"])
        self.assertTrue(hint["should_observe_more"])
        self.assertTrue(hint["reason"].startswith("sparse_context_hint_"))

    def test_build_degenerate_merge_detector_and_silent_failure_classifier_separate_pathological_signals(self) -> None:
        clean_merge = screen_contracts.build_degenerate_merge_detector(
            merged_rows=[
                {"name": "row-a"},
                {"name": "row-b"},
            ],
            merge_identity={"merge_id": "merge-1"},
        )
        degenerate_merge = screen_contracts.build_degenerate_merge_detector(
            merged_rows=[
                {"name": "row-a"},
                {"name": "row-a"},
                {"name": "overlap between row-b and row-c"},
                {"name": "conflict row", "is_conflicting": True},
            ],
            merge_identity={"merge_id": "merge-2"},
        )
        idle_silent = screen_contracts.build_silent_failure_classifier(
            ui_events=[],
            network_events=[],
            heartbeat_events=[],
            is_hung=False,
        )
        hung_silent = screen_contracts.build_silent_failure_classifier(
            ui_events=[],
            network_events=[],
            heartbeat_events=[],
            is_hung=True,
        )

        self.assertEqual(clean_merge["reason"], "degenerate_merge_detector_clean")
        self.assertFalse(clean_merge["should_block"])
        self.assertEqual(degenerate_merge["reason"], "degenerate_merge_detector_degenerate")
        self.assertTrue(degenerate_merge["should_block"])
        self.assertEqual(degenerate_merge["counts"]["duplicate"], 1)
        self.assertEqual(degenerate_merge["counts"]["overlap"], 1)
        self.assertEqual(degenerate_merge["counts"]["conflict"], 1)
        self.assertEqual(idle_silent["failure_kind"], "quiet_idle")
        self.assertFalse(idle_silent["should_block"])
        self.assertEqual(hung_silent["failure_kind"], "pipeline_hang")
        self.assertTrue(hung_silent["should_block"])

    def test_build_low_evidence_action_cap_and_unknown_packet_splitters_limit_action_pressure(self) -> None:
        low_cap = screen_contracts.build_low_evidence_action_cap(
            evidence_rows=[],
            trust_tier="low",
            max_action_count=4,
            min_evidence_count=2,
        )
        healthy_cap = screen_contracts.build_low_evidence_action_cap(
            evidence_rows=[{"name": "signal"}],
            trust_tier="high",
            max_action_count=4,
            min_evidence_count=1,
        )
        budgeted = screen_contracts.build_observe_more_budget_policy(
            evidence_rows=[{"name": "signal"}],
            observe_count=1,
            max_observe_count=2,
        )
        exhausted = screen_contracts.build_observe_more_budget_policy(
            evidence_rows=[],
            observe_count=2,
            max_observe_count=2,
            has_refresh_signal=True,
        )
        splitter = screen_contracts.build_local_vs_global_unknown_splitter(
            unknown_state_packet={
                "rows": [
                    {"name": "local missing option", "is_local": True},
                    {"name": "global page drift", "is_global": True},
                    {"name": "global unknown mismatch"},
                ]
            },
            gap_key_hint="unknown_state",
        )
        packet = screen_contracts.build_unknown_state_packet(
            unknown_rows=[{"name": "missing evidence"}],
            attempts=[{"name": "fallback a"}],
            fallback_rows=[{"name": "fallback b"}],
            gap_key_hint="unknown_state",
        )

        self.assertTrue(low_cap["is_capped"])
        self.assertEqual(low_cap["action_cap"], 1)
        self.assertTrue(low_cap["should_block"])
        self.assertFalse(healthy_cap["is_capped"])
        self.assertGreaterEqual(healthy_cap["action_cap"], 4)
        self.assertEqual(budgeted["outcome"], "allow_observe_more")
        self.assertFalse(budgeted["should_force_defer"])
        self.assertEqual(exhausted["outcome"], "refresh_artifacts")
        self.assertTrue(exhausted["should_refresh"])
        self.assertEqual(splitter["selected_scope"], "global")
        self.assertTrue(splitter["should_promote_global"])
        self.assertEqual(packet["recommendation"], "defer")
        self.assertTrue(packet["should_defer"])

    def test_build_ignorance_regression_suite_unknown_vs_broken_app_splitter_and_sparse_replay_bundle(self) -> None:
        regression = screen_contracts.build_ignorance_regression_suite(
            failing_runs=[{"profile": "blank_capture", "reason": "no_signal"}],
            passing_runs=[{"profile": "stable_capture"}],
            min_failures=1,
        )
        stable = screen_contracts.build_ignorance_regression_suite(
            failing_runs=[],
            passing_runs=[{"profile": "stable_capture"}],
            min_failures=1,
        )
        broken = screen_contracts.build_unknown_vs_broken_app_splitter(
            evidence_absence_taxonomy={"rows": [{"name": "missing evidence"}]},
            silent_failure_classifier={"failure_kind": "pipeline_hang", "should_block": True},
            unknown_state_packet={"recommendation": "observe_more"},
        )
        unknown = screen_contracts.build_unknown_vs_broken_app_splitter(
            evidence_absence_taxonomy={"rows": [{"name": "missing evidence"}]},
            silent_failure_classifier={"failure_kind": "active", "should_block": False},
            unknown_state_packet={"recommendation": "observe_more"},
        )
        replay = screen_contracts.build_sparse_evidence_replay_bundle(
            probe_rows=[{"name": "probe_a"}],
            fallback_rows=[{"name": "fallback_a"}],
            failed_paths=[{"name": "failed_a"}],
        )

        self.assertTrue(regression["is_regressed"])
        self.assertEqual(regression["reason"], "ignorance_regression_suite_regressed")
        self.assertFalse(stable["is_regressed"])
        self.assertEqual(broken["split"], "mixed")
        self.assertTrue(broken["is_broken_app"])
        self.assertTrue(broken["is_unknown"])
        self.assertEqual(unknown["split"], "unknown_state")
        self.assertTrue(unknown["is_unknown"])
        self.assertFalse(unknown["is_broken_app"])
        self.assertEqual(replay["outcome"], "replay")
        self.assertTrue(replay["should_replay"])
        self.assertEqual(replay["failed_path_count"], 1)

