    def test_build_stale_context_detector_and_context_sync_helpers_detect_version_drift(self) -> None:
        stale = screen_contracts.build_stale_context_detector(
            current_context={"version": "ctx-v2", "age_s": 12.5},
            snapshot_context={"version": "ctx-v1"},
            max_age_s=10.0,
        )
        fresh = screen_contracts.build_stale_context_detector(
            current_context={"version": "ctx-v1", "age_s": 2.5},
            snapshot_context={"version": "ctx-v1"},
            max_age_s=10.0,
        )
        diff = screen_contracts.build_cross_agent_context_diff(
            agent_contexts=[
                {"agent": "lead", "version": "ctx-v1"},
                {"agent": "worker", "version": "ctx-v2"},
            ]
        )
        merge_guard = screen_contracts.build_context_merge_guard(
            report_packets=[
                {"name": "report-a", "snapshot_id": "snap-1"},
                {"name": "report-b", "snapshot_id": "snap-2"},
            ],
            knowledge_snapshot={"snapshot_id": "snap-1"},
        )
        anchor = screen_contracts.build_replay_context_anchor(
            replay_bundle={"bundle_id": "replay-1"},
            knowledge_snapshot={"snapshot_id": "snap-1"},
            session_id="session-1",
        )

        self.assertTrue(stale["is_stale"])
        self.assertFalse(fresh["is_stale"])
        self.assertTrue(diff["has_diff"])
        self.assertEqual(sorted(diff["mismatched_agents"]), ["lead", "worker"])
        self.assertFalse(merge_guard["is_safe_to_merge"])
        self.assertTrue(merge_guard["should_block"])
        self.assertTrue(anchor["is_anchored"])
        self.assertEqual(anchor["reason"], "replay_context_anchor_anchored")

    def test_build_context_refresh_policy_and_version_registry_track_staleness_and_compatibility(self) -> None:
        refresh = screen_contracts.build_context_refresh_policy(
            current_context={"version": "ctx-v2"},
            snapshot_context={"version": "ctx-v1"},
            open_tasks=[{"name": "worker_a"}],
        )
        hold = screen_contracts.build_context_refresh_policy(
            current_context={"version": "ctx-v1"},
            snapshot_context={"version": "ctx-v1"},
            open_tasks=[],
        )
        registry = screen_contracts.build_tree_version_registry(
            tree_versions=[{"version": "tree-v1"}, {"version": "tree-v2"}, {"version": "tree-v1"}]
        )
        compatibility = screen_contracts.build_evidence_context_compatibility_check(
            evidence_rows=[{"name": "evidence-a", "version": "ctx-v1"}],
            current_context={"version": "ctx-v1"},
        )
        decay = screen_contracts.build_context_trust_decay_model(
            age_s=12.0,
            evidence_context_compatibility_check=compatibility,
        )

        self.assertEqual(refresh["action"], "restart_worker")
        self.assertTrue(refresh["should_refresh"])
        self.assertEqual(hold["action"], "hold")
        self.assertFalse(hold["should_refresh"])
        self.assertEqual(registry["latest_version"], "tree-v2")
        self.assertEqual(registry["version_count"], 2)
        self.assertTrue(compatibility["is_compatible"])
        self.assertEqual(decay["tier"], "low")
        self.assertGreaterEqual(decay["trust"], 0.0)
        self.assertTrue(decay["should_warn"])

