    def test_side_effect_watchdog_allows_expected_request_spike_for_submit(self) -> None:
        expected = build_expected_side_effect_map(
            actions_plan=[{"kind": "screen_click", "reason": "submit_final_form", "bbox": [1, 2, 3, 4]}]
        )
        external = build_expected_side_effect_map(
            actions_plan=[{"kind": "screen_click", "reason": "open_external_help", "bbox": [1, 2, 3, 4]}]
        )
        watchdog = build_side_effect_watchdog(
            actions_plan=[{"kind": "screen_click", "reason": "submit_final_form", "bbox": [1, 2, 3, 4]}],
            previous_url="https://quiz.example.com/review",
            current_url="https://quiz.example.com/complete",
            domain_allowlist={"is_allowed": True, "current_host": "quiz.example.com"},
            request_count_before=4,
            request_count_after=32,
        )
        self.assertTrue(expected["allow_request_spike"])
        self.assertTrue(expected["allow_external_navigation"])
        self.assertFalse(expected["allow_popup"])
        self.assertFalse(expected["allow_download"])
        self.assertFalse(external["allow_external_navigation"])
        self.assertFalse(watchdog["is_blocking"])
        self.assertEqual(watchdog["reason"], "no_unsafe_side_effects")

    def test_privacy_reset_contract_clears_cookies_storage_and_reloads(self) -> None:
        page = mock.Mock()
        context = mock.Mock()
        page.context = context
        page.evaluate.return_value = {"cleared": True, "reason": "cleared"}
        page.goto.return_value = None
        page.wait_for_load_state.return_value = None

        contract = apply_privacy_reset_contract(page=page, start_url="https://quiz.example.com/t/1/1?reset=1")

        self.assertTrue(contract["is_applied"])
        self.assertTrue(contract["signals"]["cookies_cleared"])
        self.assertTrue(contract["signals"]["storage_cleared"])
        self.assertTrue(contract["signals"]["reloaded"])
        context.clear_cookies.assert_called_once()
        page.evaluate.assert_called_once()
        self.assertEqual(page.goto.call_count, 1)

