    def test_submit_two_phase_guard_requires_commit_after_confirmation(self) -> None:
        blocked = build_submit_two_phase_guard(
            actions_plan=[{"kind": "screen_click", "reason": "submit_final_form", "bbox": [1, 2, 3, 4]}],
            runtime_state={"state": "submit"},
            terminal_state={"terminal_screen": {"screen_kind": "review"}},
            validation_state={"is_blocking": False},
            submit_guard_state={"is_hard_stop": False},
            mission_mode="live",
            operator_confirmation={"confirmed": True, "confirmed_ts": time.time()},
            commit_requested=False,
        )
        allowed = build_submit_two_phase_guard(
            actions_plan=[{"kind": "screen_click", "reason": "submit_final_form", "bbox": [1, 2, 3, 4]}],
            runtime_state={"state": "submit"},
            terminal_state={"terminal_screen": {"screen_kind": "review"}},
            validation_state={"is_blocking": False},
            submit_guard_state={"is_hard_stop": False},
            mission_mode="live",
            operator_confirmation={"confirmed": True, "confirmed_ts": time.time()},
            commit_requested=True,
        )
        self.assertFalse(blocked["is_allowed"])
        self.assertEqual(blocked["phase"], "ready_to_submit")
        self.assertEqual(blocked["reason"], "commit_submit_required")
        self.assertTrue(allowed["is_allowed"])
        self.assertEqual(allowed["phase"], "commit_submit")

