    def test_escalation_threshold_policy_escalates_after_consecutive_risky_steps(self) -> None:
        policy = build_escalation_threshold_policy(
            previous_steps=[
                {
                    "validation_outcome": {"outcome": "blocked"},
                    "operational_watchdog": {"decision": "watch"},
                    "post_submit_verifier": {"is_required": False, "is_verified": False},
                    "live_site_safety_policy": {"is_blocking": False},
                }
            ],
            current_step={
                "validation_outcome": {"outcome": "silently_ignored"},
                "operational_watchdog": {"decision": "watch"},
                "post_submit_verifier": {"is_required": False, "is_verified": False},
                "live_site_safety_policy": {"is_blocking": False},
            },
        )
        self.assertTrue(policy["is_blocking"])
        self.assertEqual(policy["decision"], "escalate")
        self.assertEqual(policy["reason"], "consecutive_risky_steps")

    def test_autonomy_drop_rule_blocks_on_high_source_conflict(self) -> None:
        blocked = build_autonomy_drop_rule(
            screen_site_consistency=0.31,
            confidence_fusion_policy={"fused_confidence": 0.42},
            broken_screen_shape_guard={"is_broken": True},
            qid_alignment_contract={"aligned": False},
        )
        warned = build_autonomy_drop_rule(
            screen_site_consistency=0.7,
            confidence_fusion_policy={"fused_confidence": 0.59},
            broken_screen_shape_guard={"is_broken": False},
            qid_alignment_contract={"aligned": True},
        )
        self.assertTrue(blocked["is_blocking"])
        self.assertEqual(blocked["reason"], "high_source_conflict")
        self.assertFalse(warned["is_blocking"])
        self.assertTrue(warned["requires_review"])

    def test_consent_barrier_policy_blocks_captcha_and_cookie_accept(self) -> None:
        captcha = build_consent_barrier_policy(
            screen_state={"question_text": "Verify you are human"},
            page_data={"title": "reCAPTCHA challenge", "pageText": "Verify you are human"},
            region_payload={"results": [{"text": "reCAPTCHA"}]},
            anti_modal_guard={"is_blocking": False, "matched_tokens": []},
            submit_guard_state={"challenge_kind": "recaptcha"},
            recommended_action="",
        )
        consent = build_consent_barrier_policy(
            screen_state={"question_text": "We use cookies"},
            page_data={"title": "Cookie consent", "pageText": "Accept cookies to continue"},
            region_payload={"results": [{"text": "Accept cookies"}]},
            anti_modal_guard={"is_blocking": True, "matched_tokens": ["accept cookies"]},
            submit_guard_state={"challenge_kind": "none"},
            recommended_action="click_cookies_accept",
        )
        self.assertTrue(captcha["is_blocking"])
        self.assertEqual(captcha["barrier_kind"], "captcha")
        self.assertEqual(captcha["reason"], "challenge:recaptcha")
        self.assertTrue(consent["is_blocking"])
        self.assertEqual(consent["barrier_kind"], "consent")
        self.assertEqual(consent["reason"], "consent_accept_not_allowed")

