    def test_build_captcha_guard_matches_submit_guard_state(self) -> None:
        wrapper = screen_contracts.build_captcha_guard(
            screen_state={"question_text": "Verify you are human"},
            page_data={"title": "reCAPTCHA challenge", "pageText": "Verify you are human"},
            region_payload={"results": [{"text": "reCAPTCHA"}]},
        )
        reference = build_submit_guard_state(
            screen_state={"question_text": "Verify you are human"},
            page_data={"title": "reCAPTCHA challenge", "pageText": "Verify you are human"},
            region_payload={"results": [{"text": "reCAPTCHA"}]},
        )

        self.assertTrue(wrapper["is_blocking"])
