    def test_submission_confirmation_policy_detects_confirmation_text_and_url(self) -> None:
        confirmed = build_submission_confirmation_state(
            screen_state={"question_text": "Thank you", "options": []},
            page_data={"title": "Submission completed"},
            region_payload={"results": [{"text": "Your response was submitted"}]},
            previous_url="https://quiz.example.com/q/1",
            current_url="https://quiz.example.com/submission-confirmed",
        )
        self.assertTrue(confirmed["is_confirmed"])
        self.assertEqual(confirmed["confirmation_kind"], "text")
        self.assertTrue(confirmed["signals"]["confirmation_url"])

        url_only = build_submission_confirmation_state(
            screen_state={"question_text": "", "options": []},
            page_data={"title": "Quiz"},
            region_payload={"results": []},
            previous_url="https://quiz.example.com/q/1",
            current_url="https://quiz.example.com/done",
        )
        self.assertTrue(url_only["is_confirmed"])
        self.assertEqual(url_only["confirmation_kind"], "url")

