    def test_textarea_growth_policy_marks_multiline_growth_as_healthy(self) -> None:
        state = build_textarea_growth_state(
            previous_page_data={
                "qid": "q1",
                "question": "Opisz problem",
                "hasTextbox": True,
                "textboxValue": "",
                "textboxBbox": [100, 180, 360, 220],
                "textboxMultiline": True,
                "textboxFocused": True,
            },
            current_page_data={
                "qid": "q1",
                "question": "Opisz problem",
                "hasTextbox": True,
                "textboxValue": "To jest dluzsza odpowiedz",
                "textboxBbox": [100, 180, 360, 260],
                "textboxMultiline": True,
                "textboxFocused": False,
            },
            action_kind="key_press",
            action_reason="blur_textbox",
            expected_value="To jest dluzsza odpowiedz",
        )
        self.assertTrue(state["monitor_active"])
        self.assertTrue(state["is_healthy"])
        self.assertTrue(state["signals"]["value_preserved"])
        self.assertTrue(state["signals"]["focus_released"])
        self.assertGreater(state["signals"]["height_growth"], 0.0)
        self.assertFalse(state["signals"]["overlay_or_loss_suspected"])

