    def test_auto_main_run_quiz_treats_selection_only_progress_as_no_progress_when_question_change_expected(self) -> None:
        transition = evaluate_transition(
            prev_state={
                "last_screen_signature": "screen-1",
                "question_text": "Jakiego koloru jest trawa?",
                "objects": {"answers": [{"text": "Zielony"}]},
                "last_action": {
                    "kind": "answer",
                    "question_signature": "sig-1",
                    "page_signature": "page-1",
                    "expected_values": ["Zielony"],
                    "post_action_expectation": {"expect_question_change": True},
                },
            },
            current_screen_state={
                "screen_signature": "screen-1",
                "active_question_signature": "sig-1",
                "question_text": "Jakiego koloru jest trawa?",
                "options": [{"text": "Zielony"}],
                "page_signature": "page-1",
            },
            controls_data={"controls": [{"kind": "radio", "text": "Zielony", "checked": True}]},
            page_data={"url": "https://quiz.example.com/q/1", "page_signature": "page-1"},
        )
        self.assertEqual(transition["outcome_type"], "selection_persisted")
        self.assertFalse(transition["semantic_success"])

        runtime_state = build_quiz_runtime_fsm(
            screen_state={
                "screen_signature": "screen-1",
                "question_text": "Jakiego koloru jest trawa?",
            },
            page_data={"url": "https://quiz.example.com/q/1", "options": [{"text": "Zielony", "checked": True}]},
            previous_runtime_state={},
            previous_signature="screen-1",
            previous_url="https://quiz.example.com/q/1",
            previous_action={"kind": "answer"},
            expected_values=["Zielony"],
            attempt_count=1,
            action_progressed=False,
            home_screen_detected=False,
        )
        self.assertTrue(runtime_state["stuck_detection"]["no_progress"])
        self.assertEqual(runtime_state["recovery"]["action"], "retry_same_action")

    def test_auto_main_run_quiz_treats_compound_block_completion_as_progress(self) -> None:
        transition = evaluate_transition(
            prev_state={
                "last_screen_signature": "screen-mixed-1",
                "question_text": "Profil respondenta",
                "objects": {"answers": [{"text": "Miasto"}, {"text": "Kod"}]},
                "last_action": {
                    "kind": "answer",
                    "question_signature": "sig-mixed-1",
                    "page_signature": "page-mixed-1",
                    "expected_values": ["Warszawa", "00-001"],
                    "post_action_expectation": {
                        "expect_question_change": False,
                        "chain_type": "mixed_block:text",
                    },
                },
            },
            current_screen_state={
                "screen_signature": "screen-mixed-2",
                "active_question_signature": "sig-mixed-1",
                "question_text": "Profil respondenta",
                "options": [],
                "page_signature": "page-mixed-1",
            },
            controls_data={
                "controls": [
                    {"kind": "select", "value": "Warszawa"},
                    {"kind": "textbox", "value": "00-001"},
                ]
            },
            page_data={"url": "https://quiz.example.com/q/1", "page_signature": "page-mixed-1"},
        )
        self.assertEqual(transition["outcome_type"], "compound_block_completed")
        self.assertTrue(transition["semantic_success"])
        self.assertEqual(transition["semantic_scope"], "compound_block")
        self.assertTrue(transition["success_semantics_policy"]["compound_block_completed"])

        enforcement = auto_main.build_effective_action_progressed(
            action_result_packet=transition,
            raw_progressed=False,
        )
        self.assertTrue(enforcement["semantic_success"])
        self.assertTrue(enforcement["effective_action_progressed"])

