    def test_auto_main_main_runs_harness_and_persists_summary(self) -> None:
        tmp_dir = Path("tmp_test_auto_main_main_success")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        proc = mock.Mock()
        pw = mock.Mock()
        browser = mock.Mock()
        context = mock.Mock()
        page = mock.Mock()
        try:
            with (
                mock.patch.object(sys, "argv", ["auto_main.py", "--type-id", "2", "--question", "3", "--max-steps", "5"]),
                mock.patch.object(auto_main, "AUTO_DATA_DIR", tmp_dir / "auto_data"),
                mock.patch.object(auto_main, "CURRENT_RUN_DIR", tmp_dir / "auto_data" / "current_run"),
                mock.patch.object(auto_main, "RUNS_DIR", tmp_dir / "auto_data" / "runs"),
                mock.patch.object(auto_main, "AUTO_DEBUG_DIR", tmp_dir / "auto_debug"),
                mock.patch.object(auto_main, "_ensure_server", return_value=proc) as ensure_mock,
                mock.patch.object(auto_main, "_wait_for_server") as wait_mock,
                mock.patch.object(auto_main, "_load_qa_cache", return_value={"ok": True}) as cache_mock,
                mock.patch.object(auto_main, "_open_browser", return_value=(pw, browser, context, page)) as open_mock,
                mock.patch.object(
                    auto_main,
                    "_run_quiz",
                    return_value={
                        "completed": True,
                        "steps": [],
                        "final_url": "http://127.0.0.1:8000/done",
                        "global_seed": {"global_seed": 1337},
                        "deterministic_run_config": {"max_steps": 5},
                        "session_level_resource_budget": {"timeout_budget": {"max_steps": 5}},
                        "worker_scaling_curve": {"requested_regime": "sweet_spot"},
                        "site_identity_registry": {"canonical_site_id": "127.0.0.1|/t/:int/:int|test_quiz_type_2|sig"},
                        "layout_family_classifier": {"layout_family": "single"},
                        "page_truth_selector": {"primary_source": "screen_state"},
                        "url_canonicalizer": {"stable_site_key": "127.0.0.1/t/:int/:int"},
                        "site_strategy_memory": {"preferred_plan_source": "screen_only", "recommended_order": ["screen_only"]},
                        "site_failure_priors": {"stop_reason": "completed", "next_session_expectation": "normal_start"},
                        "known_target_template_cache": {"template_count": 1, "templates": [{"qid": "q-1"}]},
                        "survey_difficulty_memory": {"difficulty_band": "easy", "difficulty_score": 0.5},
                        "site_guard_profile": {"profile_level": "low", "guard_flags": []},
                        "site_specific_forbidden_targets": {"forbidden_targets": [{"label": "accept cookies"}]},
                        "site_noise_signature_db": {"noise_signatures": [{"screen_signature": "sig-noise-1"}]},
                        "site_wait_profile": {"preferred_wait_mode": "default", "stabilization_window_ms": 250},
                        "memory_promotion_gate": {"promotion_decision": "promote_selected", "promotable_contracts": ["site_wait_profile"]},
                        "memory_expiry_policy": {"expiry_band": "retain", "ttl_runs": 5},
                        "novelty_override_rule": {"should_override_memory": False, "override_strength": "none"},
                        "process_topology_snapshot": {"processes": [{"role": "quiz_server", "port": 8000}]},
                    },
                ) as run_mock,
                mock.patch.object(auto_main, "_json_dump") as dump_mock,
                mock.patch.object(auto_main, "_copy_current") as copy_mock,
                mock.patch.object(auto_main, "_terminate") as terminate_mock,
                mock.patch("builtins.print") as print_mock,
            ):
                auto_main.main()

            ensure_mock.assert_called_once_with("127.0.0.1", 8000)
            wait_mock.assert_called_once_with("127.0.0.1", 8000)
            cache_mock.assert_called_once()
            open_mock.assert_called_once()
            run_kwargs = run_mock.call_args.kwargs
            self.assertIs(run_kwargs["page"], page)
            self.assertEqual(run_kwargs["max_steps"], 5)
            self.assertEqual(run_kwargs["start_url"], "http://127.0.0.1:8000/t/2/3?reset=1")
            self.assertTrue(str(run_kwargs["run_dir"]).startswith(str(tmp_dir / "auto_data" / "runs")))
            self.assertTrue((tmp_dir / "auto_data" / "runs").exists())
            dumped_paths = [call.args[0] for call in dump_mock.call_args_list]
            copied_targets = [call.args[1] for call in copy_mock.call_args_list]
            self.assertEqual(len(dumped_paths), 2)
            self.assertIn(run_kwargs["run_dir"] / "session.json", dumped_paths)
            self.assertIn(run_kwargs["run_dir"] / "summary.json", dumped_paths)
            self.assertEqual(copied_targets, ["session.json", "summary.json"])
            session_payload = dump_mock.call_args_list[0].args[1]
            self.assertEqual(session_payload["session_level_resource_budget"]["timeout_budget"]["max_steps"], 5)
            self.assertEqual(session_payload["worker_scaling_curve"]["requested_regime"], "sweet_spot")
            self.assertEqual(session_payload["site_identity_registry"]["canonical_site_id"], "127.0.0.1|/t/:int/:int|test_quiz_type_2|sig")
            self.assertEqual(session_payload["layout_family_classifier"]["layout_family"], "single")
            self.assertEqual(session_payload["page_truth_selector"]["primary_source"], "screen_state")
            self.assertEqual(session_payload["url_canonicalizer"]["stable_site_key"], "127.0.0.1/t/:int/:int")
            self.assertEqual(session_payload["site_strategy_memory"]["preferred_plan_source"], "screen_only")
            self.assertEqual(session_payload["site_failure_priors"]["stop_reason"], "completed")
            self.assertEqual(session_payload["known_target_template_cache"]["template_count"], 1)
            self.assertEqual(session_payload["survey_difficulty_memory"]["difficulty_band"], "easy")
            self.assertEqual(session_payload["site_guard_profile"]["profile_level"], "low")
            self.assertEqual(session_payload["site_specific_forbidden_targets"]["forbidden_targets"][0]["label"], "accept cookies")
            self.assertEqual(session_payload["site_noise_signature_db"]["noise_signatures"][0]["screen_signature"], "sig-noise-1")
            self.assertEqual(session_payload["site_wait_profile"]["stabilization_window_ms"], 250)
            self.assertEqual(session_payload["memory_promotion_gate"]["promotion_decision"], "promote_selected")
            self.assertEqual(session_payload["memory_expiry_policy"]["expiry_band"], "retain")
            self.assertEqual(session_payload["novelty_override_rule"]["override_strength"], "none")
            self.assertEqual(session_payload["process_topology_snapshot"]["processes"][0]["role"], "quiz_server")
            self.assertTrue(session_payload["startup_feature_compat_check"]["is_compatible"])
            self.assertEqual(session_payload["answer_source_domain_contract"]["active_source"], "qa_cache")
            self.assertTrue(session_payload["answer_source_domain_contract"]["is_synthetic_host"])
            self.assertTrue(session_payload["answer_source_domain_contract"]["live_site_gap_present"])
            self.assertEqual(session_payload["session_release_stamp"]["release_family"], "runtime_session")
            self.assertEqual(session_payload["session_release_stamp"]["process_roles"][0], "quiz_server")
            context.close.assert_called_once()
            browser.close.assert_called_once()
            pw.stop.assert_called_once()
            terminate_mock.assert_called_once_with(proc)
            self.assertTrue(print_mock.called)
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def test_auto_main_build_process_topology_snapshot_records_roles_ports_and_pid(self) -> None:
        proc = mock.Mock()
        proc.pid = 4321
        with mock.patch.dict(os.environ, {"FULLBOT_REGION_GROW_EXEC_MODE": "daemon", "FULLBOT_REGION_GROW_DAEMON_PORT": "18765"}, clear=False):
            snapshot = auto_main.build_process_topology_snapshot(
                host="127.0.0.1",
                port=8000,
                server_proc=proc,
                headless=True,
                viewport={"width": 1440, "height": 1400},
            )
        self.assertEqual(snapshot["processes"][0]["role"], "quiz_server")
        self.assertEqual(snapshot["processes"][0]["pid"], 4321)
        self.assertEqual(snapshot["processes"][0]["port"], 8000)
        self.assertEqual(snapshot["processes"][1]["role"], "browser_runtime")
        self.assertEqual(snapshot["processes"][2]["role"], "region_grow_runtime")
        self.assertEqual(snapshot["processes"][2]["port"], 18765)

    def test_auto_main_build_session_release_stamp_records_model_and_process_contract(self) -> None:
        summary = {
            "runtime_contracts": {
                "model_fingerprint": "fp-123",
                "artifact_id": "iter_001",
            },
            "session_level_resource_budget": {
                "gpu_budget": {
                    "requested_exec_mode": "daemon",
                    "effective_exec_mode": "oneshot",
                }
            },
        }
        process_topology_snapshot = {
            "processes": [
                {"role": "quiz_server"},
                {"role": "browser_runtime"},
                {"role": "region_grow_runtime"},
            ]
        }
        with mock.patch.dict(
            os.environ,
            {
                "FULLBOT_QUIZ_TYPE_MODEL_PATH": "quiz_type.json",
                "FULLBOT_ELEMENT_ROLE_MODEL_PATH": "element_role_v2.json",
                "FULLBOT_ELEMENT_ROLE_MODEL_SELECTOR": "v2",
                "FULLBOT_REGION_GROW_EXEC_MODE": "daemon",
            },
            clear=False,
        ):
            stamp = auto_main.build_session_release_stamp(
                summary=summary,
                process_topology_snapshot=process_topology_snapshot,
            )
        self.assertEqual(stamp["model_fingerprint"], "fp-123")
        self.assertEqual(stamp["artifact_id"], "iter_001")
        self.assertEqual(stamp["models"]["element_role_model_selector"], "v2")
        self.assertEqual(stamp["models"]["control_kind_model_path"], "")
        self.assertEqual(stamp["model_release_manifest"]["models"]["quiz_type"]["selected_path"], str(Path("quiz_type.json").resolve()))
        self.assertEqual(stamp["model_release_manifest"]["models"]["element_role"]["selected_variant"], "v2")
        self.assertEqual(stamp["resource_profile"]["effective_exec_mode"], "oneshot")
        self.assertEqual(stamp["process_roles"], ["quiz_server", "browser_runtime", "region_grow_runtime"])

    def test_auto_main_build_model_release_manifest_tracks_rollout_and_runtime_paths(self) -> None:
        tmp_dir = Path("tmp_test_model_release_manifest")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            element_rollout_path = tmp_dir / "element_role_rollout.json"
            element_rollout_model_path = tmp_dir / "element_role_rollout_model.json"
            element_rollout_model_path.write_text("{}", encoding="utf-8")
            element_rollout_path.write_text(
                json.dumps(
                    {
                        "release_family": "element_role_rollout",
                        "selected_model_path": str(element_rollout_model_path),
                    },
                    ensure_ascii=False,
                ),
                encoding="utf-8",
            )
            control_rollout_path = tmp_dir / "control_kind_rollout.json"
            control_rollout_model_path = tmp_dir / "control_kind_rollout_model.json"
            control_rollout_model_path.write_text("{}", encoding="utf-8")
            control_rollout_path.write_text(
                json.dumps(
                    {
                        "release_family": "control_kind_rollout",
                        "selected_model_path": str(control_rollout_model_path),
                    },
                    ensure_ascii=False,
                ),
                encoding="utf-8",
            )
            with mock.patch.dict(
                os.environ,
                {
                    "FULLBOT_QUIZ_TYPE_MODEL_PATH": str((tmp_dir / "quiz_type.json").resolve()),
                    "FULLBOT_CONTROL_KIND_MODEL_SELECTOR": "rollout",
                    "FULLBOT_CONTROL_KIND_MODEL_ROLLOUT_PATH": str(control_rollout_path),
                    "FULLBOT_CONTROL_KIND_MODEL_PATH": "",
                    "FULLBOT_ELEMENT_ROLE_MODEL_SELECTOR": "rollout",
                    "FULLBOT_ELEMENT_ROLE_MODEL_ROLLOUT_PATH": str(element_rollout_path),
                    "FULLBOT_ELEMENT_ROLE_MODEL_PATH": "",
                },
                clear=False,
            ):
                manifest = auto_main.build_model_release_manifest()
            self.assertEqual(manifest["release_family"], "runtime_model_release_manifest")
            self.assertEqual(manifest["models"]["quiz_type"]["selected_path"], str((tmp_dir / "quiz_type.json").resolve()))
            self.assertEqual(manifest["models"]["control_kind"]["selected_variant"], "rollout")
            self.assertEqual(Path(manifest["models"]["control_kind"]["selected_path"]).resolve(), control_rollout_model_path.resolve())
            self.assertEqual(manifest["models"]["element_role"]["selected_variant"], "rollout")
            self.assertEqual(Path(manifest["models"]["element_role"]["selected_path"]).resolve(), element_rollout_model_path.resolve())
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

