    def test_auto_main_build_operator_explanation_packet_records_candidates_choice_and_rejections(self) -> None:
        packet = auto_main.build_operator_explanation_packet(
            screen_state={
                "question_text": "Wybierz kolor",
                "options": [
                    {"text": "Czerwony", "bbox": [10, 10, 60, 30]},
                    {"text": "Niebieski", "bbox": [10, 40, 60, 60]},
                ],
            },
            actions_plan=[
                {"kind": "screen_click", "text": "Niebieski", "reason": "click_answer:Niebieski", "bbox": [10, 40, 60, 60]}
            ],
            resolved_answer={"question_type": "single", "correct_answers": ["Niebieski"]},
            trace={"stage": "answer", "plan_source": "screen_only", "post_action_expectation": {"expected_values": ["Niebieski"]}},
        )
        self.assertEqual(packet["active_question"], "Wybierz kolor")
        self.assertEqual(packet["chosen_target"]["label"], "Niebieski")
        self.assertEqual(packet["candidate_targets"][1]["matches_expected"], True)
        self.assertEqual(packet["rejected_alternatives"][0]["label"], "Czerwony")

    def test_auto_main_build_text_to_bbox_consistency_check_detects_bbox_text_mismatch(self) -> None:
        check = auto_main.build_text_to_bbox_consistency_check(
            screen_state={
                "options": [
                    {"text": "Czerwony", "bbox": [10, 10, 60, 30]},
                    {"text": "Niebieski", "bbox": [10, 40, 60, 60]},
                ]
            },
            actions_plan=[{"kind": "screen_click", "reason": "click_answer:Niebieski", "bbox": [10, 10, 60, 30]}],
            expected_values=["Niebieski"],
        )
        self.assertTrue(check["applies"])
        self.assertFalse(check["is_consistent"])
        self.assertEqual(check["reason"], "bbox_text_mismatch")
        self.assertEqual(check["matched_text"], "Czerwony")

