    def test_readback_evaluate_transition_detects_same_question_answered(self) -> None:
        transition = evaluate_transition(
            prev_state={
                "last_screen_signature": "screen-1",
                "question_text": "Wybierz kolor",
                "objects": {"answers": [{"text": "Czerwony"}, {"text": "Niebieski"}]},
                "last_action": {
                    "kind": "answer",
                    "action_id": "act_123",
                    "target_instance_id": "target_123",
                    "question_signature": "sig-1",
                    "page_signature": "page-1",
                    "target_text": "Niebieski",
                    "target_bbox": [10, 20, 30, 40],
                    "expected_values": ["Niebieski"],
                    "post_action_expectation": {"expectation_id": "exp_123"},
                },
            },
            current_screen_state={
                "screen_signature": "screen-1",
                "active_question_signature": "sig-1",
                "question_text": "Wybierz kolor",
                "options": [{"text": "Czerwony"}, {"text": "Niebieski"}],
                "page_signature": "page-1",
            },
            controls_data={
                "controls": [
                    {"kind": "radio", "text": "Niebieski", "checked": True},
                ]
            },
            page_data={"page_signature": "page-1"},
        )

        self.assertEqual(transition["transition_kind"], "same_question_answered")
        self.assertTrue(transition["success"])
        self.assertTrue(transition["values_match"])
        self.assertEqual(transition["action_id"], "act_123")
        self.assertEqual(transition["target_instance_id"], "target_123")
        self.assertEqual(transition["expectation_id"], "exp_123")
        self.assertEqual(transition["target_text"], "Niebieski")
        self.assertEqual(transition["target_bbox"], [10, 20, 30, 40])
        self.assertEqual(transition["before_state"]["screen_signature"], "screen-1")
        self.assertEqual(transition["before_state"]["selected_values"], ["Niebieski"])
        self.assertEqual(transition["after_state"]["question_signature"], "sig-1")
        self.assertEqual(transition["after_state"]["selected_values"], ["Niebieski"])
        self.assertFalse(transition["target_scope_guard"]["has_scope"])
        self.assertEqual(transition["outcome_type"], "selection_persisted")
        self.assertFalse(transition["semantic_success"])
        self.assertEqual(transition["semantic_scope"], "selection_only")
        self.assertEqual(transition["success_semantics_policy"]["outcome_type"], "selection_persisted")
        self.assertFalse(transition["success_semantics_policy"]["semantic_success"])
        self.assertEqual(transition["success_semantics_policy"]["scope"], "selection_only")

