    def test_confidence_fusion_policy_builds_fused_confidence(self) -> None:
        policy = build_confidence_fusion_policy(
            screen_confidence=0.6,
            type_confidence=0.8,
            decision_margin=0.4,
            control_model={"conf": 0.7},
            has_dom_context=True,
        )
        self.assertEqual(policy["mode"], "screen_primary")
        self.assertGreater(policy["fused_confidence"], 0.6)
        self.assertIn("weights", policy)

    def test_build_confidence_fusion_policy_prefers_alignment_with_high_agreement(self) -> None:
        aligned = screen_contracts.build_confidence_fusion_policy(
            model_confidence=0.9,
            heuristic_confidence=0.85,
            source_agreement=0.9,
        )
        disagreement = screen_contracts.build_confidence_fusion_policy(
            model_confidence=0.4,
            heuristic_confidence=0.8,
            source_agreement=0.2,
        )

        self.assertEqual(aligned["mode"], "aligned")
        self.assertEqual(aligned["reason"], "high_agreement")
        self.assertGreaterEqual(aligned["decision_confidence"], aligned["fused_confidence"])
        self.assertEqual(aligned["weights"]["model"], 0.55)

        self.assertEqual(disagreement["mode"], "heuristic_primary")
        self.assertEqual(disagreement["reason"], "heuristic_signal_stronger")
        self.assertAlmostEqual(disagreement["confidence_gap"], 0.4, places=4)
        self.assertLessEqual(disagreement["decision_confidence"], disagreement["fused_confidence"])

    def test_signal_vs_decision_confidence_contract_separates_signal_from_execution(self) -> None:
        contract = screen_contracts.build_signal_vs_decision_confidence_contract(
            signal_confidence=0.41,
            decision_confidence=0.89,
            max_gap=0.2,
        )
        self.assertEqual(contract["signal_confidence"], 0.41)
        self.assertEqual(contract["decision_confidence"], 0.89)
        self.assertAlmostEqual(contract["confidence_gap"], 0.48, places=2)
        self.assertFalse(contract["is_aligned"])
        self.assertTrue(contract["should_defer"])
        self.assertEqual(contract["reason"], "decision_confidence_exceeds_signal")
        self.assertEqual(contract["signal_sources"], ["explicit_signal_confidence"])
        self.assertEqual(contract["decision_sources"], ["explicit_decision_confidence"])

