    def test_indecision_budget_limit_forces_decision_after_budget_is_exhausted(self) -> None:
        exhausted = screen_contracts.build_indecision_budget_limit(
            defer_count=3,
            max_defer_count=2,
            has_new_evidence=False,
        )
        reset = screen_contracts.build_indecision_budget_limit(
            defer_count=3,
            max_defer_count=2,
            has_new_evidence=True,
        )
        available = screen_contracts.build_indecision_budget_limit(
            defer_count=1,
            max_defer_count=2,
            has_new_evidence=False,
        )
        self.assertEqual(exhausted["outcome"], "force_decision")
        self.assertEqual(exhausted["reason"], "defer_budget_exhausted")
        self.assertTrue(exhausted["should_force_decision"])
        self.assertEqual(reset["outcome"], "allow_defer")
        self.assertEqual(reset["reason"], "new_evidence_resets_budget_pressure")
        self.assertFalse(reset["should_force_decision"])
        self.assertEqual(available["outcome"], "allow_defer")
        self.assertEqual(available["budget_remaining"], 1)

