    def test_runtime_deferred_debug_worker_processes_scheduled_job_and_stops(self) -> None:
        tmp_dir = Path("tmp_test_deferred_debug_worker")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            json_path = tmp_dir / "region.json"
            json_path.write_text(json.dumps({"results": []}), encoding="utf-8")
            screenshot_path = tmp_dir / "screen.png"
            Image.new("RGB", (8, 8), color=(0, 0, 0)).save(screenshot_path)
            logs = []
            run_region_annotation = mock.Mock(return_value=None)
            with mock.patch.dict(os.environ, {"FULLBOT_OCR_BOXES_DEBUG": "0"}, clear=False):
                worker = runtime_deferred_debug.DeferredDebugRenderWorker(
                    root=tmp_dir,
                    run_region_annotation=run_region_annotation,
                    log=logs.append,
                    enabled=True,
                )
                worker.start()
                self.assertTrue(worker.schedule(json_path, screenshot_path, 7))
                deadline = time.time() + 3.0
                while run_region_annotation.call_count == 0 and time.time() < deadline:
                    time.sleep(0.05)
                worker.stop(drain=True, timeout=2.0)
            run_region_annotation.assert_called_once_with(json_path, screenshot_path)
            self.assertTrue(any("Deferred debug worker started" in line for line in logs))
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

