    def test_train_quiz_type_model_augment_batch_flips_binary_features_without_noise(self) -> None:
        from popelina_github.quiz import train_quiz_type_model

        X = np.zeros((2, len(train_quiz_type_model.FEATURE_NAMES)), dtype=np.float64)
        if train_quiz_type_model._BINARY_FEATURE_INDICES:
            X[:, train_quiz_type_model._BINARY_FEATURE_INDICES] = 1.0

        X_aug = train_quiz_type_model._augment_batch(
            X,
            np.random.default_rng(123),
            dropout=0.0,
            noise_std=0.0,
            flip_prob=1.0,
        )

        self.assertEqual(X_aug.shape, X.shape)
        for idx in train_quiz_type_model._BINARY_FEATURE_INDICES:
            self.assertTrue(np.allclose(X_aug[:, idx], 0.0))
        non_binary = [i for i in range(X.shape[1]) if i not in train_quiz_type_model._BINARY_FEATURE_INDICES]
        self.assertTrue(np.allclose(X_aug[:, non_binary], X[:, non_binary]))

    def test_train_element_role_classifier_v2_dedupe_qc_and_temperature_selection_are_stable(self) -> None:
        fake_torch = types.ModuleType("torch")
        fake_nn = types.ModuleType("torch.nn")
        fake_F = types.ModuleType("torch.nn.functional")

        class FakeModule:
            def parameters(self):
                return []

            def state_dict(self):
                return {"weight": np.array([1.0], dtype=np.float32)}

            def __call__(self, *args, **kwargs):
                forward = getattr(self, "forward", None)
                if callable(forward):
                    return forward(*args, **kwargs)
                return None

            def train(self):
                return None

            def eval(self):
                return None

        class FakeLinear:
            def __init__(self, _in_dim: int, out_dim: int):
                self.out_dim = int(out_dim)

            def __call__(self, x):
                arr = np.asarray(x)
                return np.zeros((arr.shape[0], self.out_dim), dtype=np.float32)

        class FakeLoss:
            def backward(self):
                return None

        class FakeAdamW:
            def __init__(self, *args, **kwargs):
                return None

            def zero_grad(self, set_to_none: bool = True):
                return None

            def step(self):
                return None

        fake_nn.Module = FakeModule
        fake_nn.Linear = FakeLinear
        fake_F.relu = lambda x: np.maximum(np.asarray(x), 0.0)
        fake_F.cross_entropy = lambda *args, **kwargs: FakeLoss()
        fake_torch.manual_seed = lambda seed: None
        fake_torch.tensor = lambda data, dtype=None: FakeTensor(data)
        fake_torch.float32 = np.float32
        fake_torch.long = np.int64
        fake_torch.no_grad = contextlib.nullcontext
        fake_torch.optim = types.SimpleNamespace(AdamW=FakeAdamW)

        module_path = PACKAGE_ROOT / "scripts" / "brain" / "runtime" / "train_element_role_classifier_v2.py"
        spec = importlib.util.spec_from_file_location("test_train_elem_v2_fake", module_path)
        self.assertIsNotNone(spec)
        assert spec is not None and spec.loader is not None
        with mock.patch.dict(
            sys.modules,
            {
                "torch": fake_torch,
                "torch.nn": fake_nn,
                "torch.nn.functional": fake_F,
            },
        ):
            train_elem_v2 = importlib.util.module_from_spec(spec)
            sys.modules[spec.name] = train_elem_v2
            spec.loader.exec_module(train_elem_v2)

        base_sample = train_elem_v2.Sample(
            view_id="view-1",
            role=train_elem_v2.ROLES[0],
            text="Hello",
            bbox=[10, 10, 30, 30],
            attrs={},
            viewport={"width": 100, "height": 100},
        )
        duplicate_sample = train_elem_v2.Sample(
            view_id="view-1",
            role=train_elem_v2.ROLES[0],
            text="Hello",
            bbox=[10, 10, 30, 30],
            attrs={},
            viewport={"width": 100, "height": 100},
        )
        outlier_sample = train_elem_v2.Sample(
            view_id="view-2",
            role=train_elem_v2.ROLES[1],
            text="Outlier",
            bbox=[0, 0, 0, 5],
            attrs={},
            viewport={"width": 100, "height": 100},
        )

        clean, counters = train_elem_v2._dedupe_and_qc([base_sample, duplicate_sample, outlier_sample])
        self.assertEqual(len(clean), 1)
        self.assertEqual(counters["dropped_duplicates"], 1)
        self.assertEqual(counters["dropped_outliers"], 1)

        logits = np.array([[4.0, 1.0], [1.0, 4.0]], dtype=np.float64)
        y_true = np.array([0, 1], dtype=np.int64)
        temp = train_elem_v2._select_temperature(logits, y_true)
        self.assertIn(temp, {0.6, 0.75, 0.9, 1.0, 1.15, 1.3, 1.5})

    def test_train_element_role_classifier_v2_fit_one_returns_best_metrics_and_state(self) -> None:
        fake_torch = types.ModuleType("torch")
        fake_nn = types.ModuleType("torch.nn")
        fake_F = types.ModuleType("torch.nn.functional")

        class FakeTensor:
            def __init__(self, array):
                self.array = np.asarray(array)

            def argmax(self, dim=None):
                return FakeTensor(np.argmax(self.array, axis=dim))

            def detach(self):
                return self

            def cpu(self):
                return self

            def clone(self):
                return FakeTensor(np.array(self.array, copy=True))

            def numpy(self):
                return np.asarray(self.array)

            def __array__(self, dtype=None):
                return np.asarray(self.array, dtype=dtype)

        class FakeModule:
            def parameters(self):
                return []

            def state_dict(self):
                return {"weight": FakeTensor(np.array([1.0], dtype=np.float32))}

            def __call__(self, *args, **kwargs):
                forward = getattr(self, "forward", None)
                if callable(forward):
                    return forward(*args, **kwargs)
                return None

            def train(self):
                return None

            def eval(self):
                return None

        class FakeLinear:
            def __init__(self, _in_dim: int, out_dim: int):
                self.out_dim = int(out_dim)

            def __call__(self, x):
                arr = np.asarray(x)
                return FakeTensor(np.zeros((arr.shape[0], self.out_dim), dtype=np.float32))

        class FakeLoss:
            def backward(self):
                return None

        class FakeAdamW:
            def __init__(self, *args, **kwargs):
                return None

            def zero_grad(self, set_to_none: bool = True):
                return None

            def step(self):
                return None

        fake_nn.Module = FakeModule
        fake_nn.Linear = FakeLinear
        fake_F.relu = lambda x: FakeTensor(np.maximum(np.asarray(x), 0.0))
        fake_F.cross_entropy = lambda *args, **kwargs: FakeLoss()
        fake_torch.manual_seed = lambda seed: None
        fake_torch.tensor = lambda data, dtype=None: FakeTensor(data)
        fake_torch.float32 = np.float32
        fake_torch.long = np.int64
        fake_torch.no_grad = contextlib.nullcontext
        fake_torch.optim = types.SimpleNamespace(AdamW=FakeAdamW)

        module_path = PACKAGE_ROOT / "scripts" / "brain" / "runtime" / "train_element_role_classifier_v2.py"
        spec = importlib.util.spec_from_file_location("test_train_elem_v2_fake_fit", module_path)
        self.assertIsNotNone(spec)
        assert spec is not None and spec.loader is not None
        with mock.patch.dict(
            sys.modules,
            {
                "torch": fake_torch,
                "torch.nn": fake_nn,
                "torch.nn.functional": fake_F,
            },
        ):
            train_elem_v2 = importlib.util.module_from_spec(spec)
            sys.modules[spec.name] = train_elem_v2
            spec.loader.exec_module(train_elem_v2)

        d = len(train_elem_v2.FEATURE_NAMES_V2)
        x_train = np.zeros((6, d), dtype=np.float32)
        x_val = np.zeros((4, d), dtype=np.float32)
        next_id = train_elem_v2.ROLE_TO_ID.get("next", 0)
        question_id = train_elem_v2.ROLE_TO_ID.get("question", 1 if len(train_elem_v2.ROLES) > 1 else 0)
        answer_id = train_elem_v2.ROLE_TO_ID.get("answer", 0)
        y_train = np.array([next_id, question_id, answer_id, next_id, answer_id, question_id], dtype=np.int64)
        y_val = np.array([next_id, question_id, next_id, answer_id], dtype=np.int64)

        best, best_state = train_elem_v2._fit_one(
            x_train,
            y_train,
            x_val,
            y_val,
            hidden1=4,
            hidden2=2,
            lr=0.01,
            weight_decay=0.0,
            epochs=1,
            seed=0,
        )

        self.assertIn("score", best)
        self.assertIsNotNone(best["metrics"])
        self.assertTrue(best_state)
        self.assertIn("weight", best_state)

