    def test_build_quiz_type_screen_benchmark_process_row_uses_cached_artifacts_when_present(self) -> None:
        import popelina_github.quiz.build_quiz_type_screen_benchmark as bench_mod

        tmp_dir = Path("tmp_test_build_quiz_type_screen_benchmark")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            manifest_path = tmp_dir / "manifest.json"
            manifest_path.write_text(json.dumps({"rows": []}), encoding="utf-8")
            manifest_dir = tmp_dir / "dataset"
            manifest_dir.mkdir(parents=True)
            image_path = (manifest_dir / "sample.png").resolve()
            image_path.write_bytes(b"png")
            out_dir = tmp_dir / "out"
            copied_image = out_dir / "images" / "sample.png"
            copied_region = out_dir / "region" / "sample.json"
            copied_rated = out_dir / "rated" / "sample.json"
            copied_summary = out_dir / "summary" / "sample.json"
            for path, content in [
                (copied_image, b"img"),
                (copied_region, b"{}"),
                (copied_rated, b"{}"),
                (copied_summary, b"{}"),
            ]:
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_bytes(content)

            result = bench_mod._process_row(
                row={"view_id": "sample", "image_path": str(image_path), "expected_global_type": "single", "expected_block_types": ["single"]},
                manifest_path=manifest_path,
                manifest_dir=manifest_dir,
                out_dir=out_dir,
                root=tmp_dir,
                py="C:/python.exe",
                region_grow_script=Path("region_grow.py"),
                rating_script=Path("rating.py"),
                env={"A": "B"},
                region_grow_timeout_s=1.0,
                rating_timeout_s=1.0,
                daemon_port=0,
            )
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

        self.assertTrue(result["ok"])
        self.assertEqual(result["row"]["id"], "sample")
        self.assertEqual(result["row"]["build_latency_ms"], 0.0)
        self.assertNotIn("cache_hit", result["row"])  # early cached-hit path is not used here

