    def test_hotkeys_start_hotkey_listener_maps_keys_to_commands(self) -> None:
        class _FakeListener:
            def __init__(self, on_press=None, on_release=None):
                self.on_press = on_press
                self.on_release = on_release
                self.daemon = False
                self.started = False

            def start(self):
                self.started = True

        fake_keyboard = types.SimpleNamespace(Listener=_FakeListener)
        trigger_event = threading.Event()
        command_q = queue.Queue()
        overlay = []
        globals_state = {"_hover_fallback_allowed": False, "_iteration_in_progress": False}
        with mock.patch.dict(sys.modules, {"pynput": types.SimpleNamespace(keyboard=fake_keyboard)}, clear=False):
            listener = hotkeys.start_hotkey_listener(
                trigger_event,
                command_q,
                log=mock.Mock(),
                debug=mock.Mock(),
                update_overlay_status=overlay.append,
                globals_fn=lambda: globals_state,
                is_debug_mode=lambda: False,
            )
        self.assertIsNotNone(listener)
        self.assertTrue(listener.started)
        listener.on_press(types.SimpleNamespace(char="p"))
        self.assertTrue(trigger_event.is_set())
        self.assertTrue(globals_state["_hover_fallback_allowed"])
        listener.on_release(types.SimpleNamespace(char="p"))
        listener.on_press(types.SimpleNamespace(char="o"))
        listener.on_press(types.SimpleNamespace(char="l"))
        listener.on_press(types.SimpleNamespace(char="i"))
        listener.on_press(types.SimpleNamespace(char="k"))
        self.assertEqual([command_q.get_nowait() for _ in range(4)], ["region", "recorder", "rating", "control"])

