    def test_main_start_cdp_browser_for_recorder_handles_disabled_already_running_missing_and_launch(self) -> None:
        import popelina_github.main as main_runtime

        fake_proc = types.SimpleNamespace(pid=4321)
        with mock.patch.dict(os.environ, {"FULLBOT_START_CDP_BROWSER": "0"}, clear=False):
            proc, ready = main_runtime.start_cdp_browser_for_recorder()
        self.assertIsNone(proc)
        self.assertFalse(ready)

        with (
            mock.patch.dict(os.environ, {"FULLBOT_START_CDP_BROWSER": "1"}, clear=False),
            mock.patch.object(main_runtime, "_probe_cdp_endpoint", return_value=True) as probe_mock,
            mock.patch.object(main_runtime, "log") as log_mock,
        ):
            proc, ready = main_runtime.start_cdp_browser_for_recorder()
        self.assertIsNone(proc)
        self.assertTrue(ready)
        probe_mock.assert_called_once()
        self.assertTrue(any("already running" in str(call.args[0]) for call in log_mock.call_args_list))

        with (
            mock.patch.dict(os.environ, {"FULLBOT_START_CDP_BROWSER": "1"}, clear=False),
            mock.patch.object(main_runtime, "_probe_cdp_endpoint", return_value=False),
            mock.patch.object(main_runtime, "_find_chrome_exe", return_value=None),
            mock.patch.object(main_runtime, "log") as log_mock,
        ):
            proc, ready = main_runtime.start_cdp_browser_for_recorder()
        self.assertIsNone(proc)
        self.assertFalse(ready)
        self.assertTrue(any("not found" in str(call.args[0]) for call in log_mock.call_args_list))

        with (
            mock.patch.dict(os.environ, {"FULLBOT_START_CDP_BROWSER": "1"}, clear=False),
            mock.patch.object(main_runtime, "_probe_cdp_endpoint", return_value=False),
            mock.patch.object(main_runtime, "_find_chrome_exe", return_value=Path("C:/Chrome/chrome.exe")),
            mock.patch.object(main_runtime.subprocess, "Popen", return_value=fake_proc) as popen_mock,
            mock.patch.object(main_runtime, "log") as log_mock,
        ):
            proc, ready = main_runtime.start_cdp_browser_for_recorder()
        self.assertIs(proc, fake_proc)
        self.assertTrue(ready)
        popen_mock.assert_called_once()
        args = popen_mock.call_args.args[0]
        self.assertEqual(args[0], str(Path("C:/Chrome/chrome.exe")))
        self.assertIn(f"--remote-debugging-port={main_runtime.RECORDER_CDP_PORT}", args)
        self.assertEqual(popen_mock.call_args.kwargs["cwd"], str(main_runtime.ROOT))
        self.assertTrue(any("CDP browser launched" in str(call.args[0]) for call in log_mock.call_args_list))

