    def test_build_recorder_cdp_bootstrap_contract_distinguishes_launch_states(self) -> None:
        disabled = screen_contracts.build_recorder_cdp_bootstrap_contract(start_enabled=False)
        already_running = screen_contracts.build_recorder_cdp_bootstrap_contract(endpoint_probe=True)
        missing_browser = screen_contracts.build_recorder_cdp_bootstrap_contract(browser_executable_available=False)
        ready = screen_contracts.build_recorder_cdp_bootstrap_contract()

        self.assertFalse(disabled["can_launch"])
        self.assertEqual(disabled["reason"], "cdp_browser_disabled")
        self.assertFalse(already_running["can_launch"])
        self.assertEqual(already_running["reason"], "cdp_browser_already_running")
        self.assertFalse(missing_browser["can_launch"])
        self.assertEqual(missing_browser["reason"], "browser_executable_missing")
        self.assertTrue(ready["can_launch"])
        self.assertEqual(ready["reason"], "cdp_browser_launch_ready")
        self.assertEqual(ready["endpoint"], "http://127.0.0.1:9222")

