    def test_pipeline_brain_agent_decide_routes_by_quiz_mode(self) -> None:
        tmp_dir = Path("tmp_test_brain_decide_route")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            summary_path = tmp_dir / "summary.json"
            summary_path.write_text("{}", encoding="utf-8")
            question_path = tmp_dir / "question.json"
            question_path.write_text("{}", encoding="utf-8")
            state_path = tmp_dir / "brain_state.json"
            state_path.write_text("{}", encoding="utf-8")
            brain = PipelineBrainAgent(question_path=question_path, state_path=state_path, current_run_dir=tmp_dir)

            with (
                mock.patch.dict("os.environ", {"FULLBOT_QUIZ_MODE": "0"}, clear=False),
                mock.patch.object(brain, "_decide_legacy", return_value=mock.Mock(recommended_action="legacy")) as legacy,
                mock.patch.object(brain, "_decide_quiz", return_value=mock.Mock(recommended_action="quiz")) as quiz,
            ):
                decision = brain.decide(summary_path)
            self.assertEqual(decision.recommended_action, "legacy")
            self.assertTrue(legacy.called)
            self.assertFalse(quiz.called)

            with (
                mock.patch.dict("os.environ", {"FULLBOT_QUIZ_MODE": "1"}, clear=False),
                mock.patch.object(brain, "_decide_legacy", return_value=mock.Mock(recommended_action="legacy")) as legacy,
                mock.patch.object(brain, "_decide_quiz", return_value=mock.Mock(recommended_action="quiz")) as quiz,
            ):
                decision = brain.decide(summary_path, region_json_path=summary_path, screenshot_path=summary_path)
            self.assertEqual(decision.recommended_action, "quiz")
            self.assertTrue(quiz.called)
            self.assertFalse(legacy.called)
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

