    def test_collect_and_dispatch_to_brain_returns_dispatch_result(self) -> None:
        tmp_dir = Path("tmp_test_collect_dispatch")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            screenshot_path = tmp_dir / "screen.png"
            screenshot_path.write_bytes(b"png")
            json_path = tmp_dir / "screen_rg_small.json"
            json_path.write_text("{}", encoding="utf-8")
            rate_results_dir = tmp_dir / "rate_results"
            rate_results_debug_dir = tmp_dir / "rate_results_debug"
            rate_results_current_dir = tmp_dir / "current_rate_results"
            rate_results_debug_current_dir = tmp_dir / "current_rate_results_debug"
            rate_summary_dir = tmp_dir / "rate_summary"
            rate_summary_current_dir = tmp_dir / "current_rate_summary"
            for path in [
                rate_results_dir,
                rate_results_debug_dir,
                rate_results_current_dir,
                rate_results_debug_current_dir,
                rate_summary_dir,
                rate_summary_current_dir,
            ]:
                path.mkdir(parents=True, exist_ok=True)
            summary_path = rate_summary_dir / f"{json_path.stem}_summary.json"
            summary_path.write_text("{}", encoding="utf-8")

            writes = []

            def _write_current_artifact(src, dst, name):
                writes.append((Path(src).name, Path(dst).name, name))
                return Path(dst) / (name or Path(src).name)

            decision = mock.Mock(
                recommended_action="click_answer",
                answer_source="cache_exact",
                screen_state={
                    "question_text": "Wybierz kolor",
                    "active_question_signature": "sig-1",
                    "detected_quiz_type": "single",
                    "detected_operational_type": "choice",
                    "type_confidence": 0.9,
                    "decision_margin": 0.5,
                    "type_source": "screen",
                    "type_signals": {"question_count": 1},
                    "next_bbox": [1, 2, 3, 4],
                    "options": [{"text": "Niebieski"}],
                },
                trace={"resolved": {"source": "cache_exact"}},
                brain_state={"question_changed": True},
            )
            brain_agent = mock.Mock(
                decide=mock.Mock(return_value=decision),
                current_run_dir=tmp_dir / "current_run",
                question_path=tmp_dir / "question.json",
                controls_path=tmp_dir / "controls.json",
                page_path=tmp_dir / "page.json",
            )
            brain_agent.current_run_dir.mkdir(parents=True, exist_ok=True)
            log_lines = []
            result = collect_and_dispatch_to_brain(
                screenshot_path=screenshot_path,
                json_path=json_path,
                rate_results_dir=rate_results_dir,
                rate_results_debug_dir=rate_results_debug_dir,
                rate_results_current_dir=rate_results_current_dir,
                rate_results_debug_current_dir=rate_results_debug_current_dir,
                rate_summary_dir=rate_summary_dir,
                rate_summary_current_dir=rate_summary_current_dir,
                write_current_artifact=_write_current_artifact,
                brain_agent=brain_agent,
                log=log_lines.append,
            )

            self.assertIsNotNone(result)
            self.assertEqual(result.summary_path, summary_path)
            self.assertTrue(result.is_new_question)
            self.assertEqual(result.decision.recommended_action, "click_answer")
            self.assertTrue(any(item[0] == summary_path.name for item in writes))
            self.assertTrue(any("Brain quiz parse" in line for line in log_lines))
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

