        rg._prepare_rapid_image = mock.Mock(return_value=(rg.np.zeros((10, 10, 3), dtype=rg.np.uint8), 0.5))
        rapid_engine = mock.Mock(return_value=[{"boxes": [(2, 4), (6, 4), (6, 8), (2, 8)], "text": "Rapid", "score": 0.8}])

        rows = rg.read_ocr_rapid(img, rapid_engine=rapid_engine)

        self.assertEqual(len(rows), 1)
