    def test_region_grow_server_loop_ping_shutdown_and_request(self) -> None:
        rg = _load_region_grow_module()
        rg.preload_ocr_models = mock.Mock()
        rg._run_runtime_single = mock.Mock(return_value={"ok": True, "json_path": "x.json", "results": 3})
        responses = []

        class _FakeConn:
            def __init__(self, line):
                self._line = line.encode("utf-8")
                self.sent = b""
            def settimeout(self, _timeout):
                return None
            def recv(self, _n):
                if self._line:
                    chunk, self._line = self._line, b""
                    return chunk
                return b""
            def sendall(self, data):
                self.sent += data
                responses.append(data.decode("utf-8", errors="ignore"))
            def close(self):
                return None

        class _FakeSocket:
            def __init__(self):
                self._items = [
                    (_FakeConn('{"cmd":"ping"}\n'), ("127.0.0.1", 1)),
                    (_FakeConn('{"image_path":"img.png","target_side":777}\n'), ("127.0.0.1", 1)),
                    (_FakeConn('{"cmd":"shutdown"}\n'), ("127.0.0.1", 1)),
                ]
            def setsockopt(self, *_a, **_k):
                return None
            def bind(self, _addr):
                return None
            def listen(self, _n):
                return None
            def accept(self):
                return self._items.pop(0)
            def close(self):
                return None

        fake_socket_mod = types.SimpleNamespace(AF_INET=1, SOCK_STREAM=1, SO_REUSEADDR=1, socket=lambda *_a, **_k: _FakeSocket())
        with mock.patch.dict(sys.modules, {"socket": fake_socket_mod}, clear=False):
            rg.server_loop(18765)
        self.assertTrue(any('"pong": true' in item.lower() for item in responses))
        self.assertTrue(any('"results": 3' in item.lower() for item in responses))
        self.assertTrue(any('"bye": true' in item.lower() for item in responses))

