    def test_region_grow_laser_box_check_gpu_counts_hits_from_four_casts(self) -> None:
        rg = _load_region_grow_module()
        img = rg.np.zeros((8, 8, 3), dtype=rg.np.uint8)
        lab = rg.np.zeros((8, 8, 3), dtype=rg.np.uint8)
        region_mask = rg.np.zeros((8, 8), dtype=bool)
        region_mask[2:6, 2:6] = True
        text_mask = rg.np.zeros((8, 8), dtype=bool)

        class _FakeCp:
            float32 = rg.np.float32

            @staticmethod
            def asarray(value, dtype=None):
                arr = rg.np.asarray(value)
                if dtype is not None:
                    arr = arr.astype(dtype)
                return arr

            @staticmethod
            def sqrt(value):
                return rg.np.sqrt(value)

        cast_results = iter(
            [
                (True, (5, 3)),
                (False, (1, 3)),
                (True, (3, 1)),
                (True, (3, 5)),
            ]
        )

        with (
            mock.patch.object(rg, "GPU_ARRAY_AVAILABLE", True),
            mock.patch.object(rg, "cp", _FakeCp),
            mock.patch.object(rg, "region_ref_lab", return_value=rg.np.array([0, 0, 0], dtype=rg.np.uint8)),
            mock.patch.object(rg, "_laser_cast_gpu", side_effect=lambda *args, **kwargs: next(cast_results)) as cast_mock,
        ):
            hits, pts = rg._laser_box_check_gpu(
                img,
                lab,
                (2, 2, 4, 4),
                region_mask,
                None,
                text_mask,
                6,
            )

        self.assertEqual(hits, 3)
        self.assertEqual(pts, [(5, 3), (1, 3), (3, 1), (3, 5)])
        self.assertEqual(cast_mock.call_count, 4)

