    def test_live_recorder_capture_do_ocr_async_updates_state_and_match(self) -> None:
        from concurrent.futures import ThreadPoolExecutor
        from popelina_github.scripts.dom.dom_renderer import ai_recorder_capture as capture_mod
        from popelina_github.scripts.dom.dom_renderer.ai_recorder_common import OcrLine, WindowInfo

        class _UIA:
            @staticmethod
            def get_active_window_info():
                return WindowInfo(
                    hwnd=1,
                    pid=11,
                    process_name="chrome.exe",
                    title="Ankietka Survey",
                    rect=(0, 0, 200, 120),
                )

        class _Recorder(capture_mod.LiveRecorderCaptureMixin):
            async def get_active_area(self):
                return {"x": 0, "y": 0, "width": 120, "height": 80}

        recorder = _Recorder()
        recorder.ocr_in_progress = False
        recorder.ocr_executor = ThreadPoolExecutor(max_workers=1)
        recorder.ocr_lines_raw = []
        recorder.ocr_lines_filtered = []
        recorder.stats = {"ocr_runs": 0}
        recorder.uia = _UIA()
        recorder._last_ocr_poll = 0.0

        fake_lines = [OcrLine(text="ankietka", conf=0.92, bbox={"x": 10, "y": 10, "w": 30, "h": 12})]
        try:
            with (
                mock.patch.object(capture_mod.sys, "platform", "win32"),
                mock.patch.object(recorder, "_ocr_sync", return_value=(fake_lines, fake_lines)),
            ):
                asyncio.run(recorder._do_ocr_async(b"shot-bytes"))
        finally:
            recorder.ocr_executor.shutdown(wait=True)

        self.assertEqual(recorder.stats["ocr_runs"], 1)
        self.assertEqual(len(recorder.ocr_lines_filtered), 1)
        self.assertTrue(recorder._last_ocr_poll > 0.0)
        self.assertEqual(recorder._last_tab_ocr_match.get("process"), "chrome.exe")
        self.assertGreaterEqual(recorder._last_tab_ocr_match.get("match_score", 0.0), 0.0)

