    def test_region_grow_gpu_binary_helpers_delegate_to_cupy_ndimage(self) -> None:
        rg = _load_region_grow_module()

        class _FakeCp:
            uint8 = rg.np.uint8

            @staticmethod
            def asarray(value, dtype=None):
                arr = rg.np.asarray(value)
                if dtype is not None:
                    arr = arr.astype(dtype)
                return arr

            @staticmethod
            def asnumpy(value):
                return rg.np.asarray(value)

        closed_expected = rg.np.array([[0, 1], [1, 1]], dtype=rg.np.uint8)
        dilated_expected = rg.np.array([[1, 1], [1, 1]], dtype=rg.np.uint8)

        with (
            mock.patch.object(rg, "GPU_FLOOD_AVAILABLE", True),
            mock.patch.object(rg, "cp", _FakeCp),
            mock.patch.object(
                rg,
                "cupy_ndimage",
                types.SimpleNamespace(
                    binary_closing=mock.Mock(return_value=closed_expected),
                    binary_dilation=mock.Mock(return_value=dilated_expected),
                ),
            ),
        ):
            closed = rg._gpu_binary_closing(rg.np.array([[0, 1], [1, 0]], dtype=rg.np.uint8), rg.np.ones((2, 2), dtype=rg.np.uint8))
            dilated = rg._gpu_binary_dilate(rg.np.array([[0, 1], [1, 0]], dtype=rg.np.uint8), rg.np.ones((2, 2), dtype=rg.np.uint8))

        self.assertTrue((closed == closed_expected).all())
        self.assertTrue((dilated == dilated_expected).all())

