    def test_region_grow_boundary_colors_from_region_fast_returns_rim_colors(self) -> None:
        rg = _load_region_grow_module()
        img = rg.np.zeros((10, 10, 3), dtype=rg.np.uint8)
        img[:] = [0, 0, 0]
        region = rg.np.zeros((10, 10), dtype=bool)
        region[3:7, 3:7] = True
        img[2:8, 2:8] = [255, 0, 0]
        img[3:7, 3:7] = [0, 255, 0]
        text_mask = rg.np.zeros((10, 10), dtype=bool)

        def _manual_dilate(arr, _kernel, iterations=1):
            out = rg.np.asarray(arr).astype(bool)
            for _ in range(max(1, int(iterations))):
                h_, w_ = out.shape
                pad = rg.np.pad(out, 1, mode="constant", constant_values=False)
                neigh = [
                    pad[1 + dy : 1 + dy + h_, 1 + dx : 1 + dx + w_]
                    for dy in (-1, 0, 1)
                    for dx in (-1, 0, 1)
                ]
                out = rg.np.logical_or.reduce(neigh)
            return out.astype(rg.np.uint8)

        with (
            mock.patch.object(rg.cv2, "dilate", side_effect=_manual_dilate, create=True),
            mock.patch.object(rg, "_boundary_colors_gpu", return_value=None),
            mock.patch.object(rg, "_cluster_boundary_colors_gpu", return_value=None),
        ):
            colors = rg.boundary_colors_from_region_fast(img, region, text_mask, tol_rgb=4)

        self.assertIn("255,0,0", colors)
        self.assertGreaterEqual(int(colors["255,0,0"]["count"]), 1)

