    def test_rating_evaluate_keeps_predictions_consistent_with_thresholds(self) -> None:
        output = rating_mod.evaluate(
            {
                "image": None,
                "image_width": 480,
                "image_height": 320,
                "results": [
                    {"text_box": [40, 40, 180, 80], "text": "Dalej", "is_button": True, "kind": "button", "conf": 0.92}
                ],
                "buttons": [],
                "triangles": [],
            }
        )
        self.assertEqual(output.get("total_elements"), 1)
        element = (output.get("elements") or [{}])[0]
        thresholds = output.get("thresholds") or {}
        for label, score in (element.get("scores") or {}).items():
            self.assertEqual(
                bool((element.get("predictions") or {}).get(label)),
                bool(float(score) >= float(thresholds.get(label, 1.0))),
            )

