    def test_runtime_region_rating_daemon_and_worker_request_helpers_round_trip(self) -> None:
        class _FakeSocket:
            def __init__(self, payload: str) -> None:
                self.payload = payload.encode("utf-8")
                self.sent: list[bytes] = []
                self.timeout = None

            def settimeout(self, timeout: float) -> None:
                self.timeout = timeout

            def sendall(self, data: bytes) -> None:
                self.sent.append(data)

            def recv(self, size: int) -> bytes:
                data, self.payload = self.payload[:size], self.payload[size:]
                return data

            def __enter__(self) -> "_FakeSocket":
                return self

            def __exit__(self, exc_type, exc, tb) -> None:
                return None

        class _FakeStdout:
            def __init__(self, lines: list[str]) -> None:
                self.lines = lines

            def readline(self) -> str:
                return self.lines.pop(0) if self.lines else ""

        class _FakeStdin:
            def __init__(self) -> None:
                self.writes: list[str] = []

            def write(self, data: str) -> None:
                self.writes.append(data)

            def flush(self) -> None:
                return None

        fake_socket = _FakeSocket('{"ok": true}\n')
        fake_proc_worker = types.SimpleNamespace(stdout=_FakeStdout(["worker ready\n"]), poll=lambda: None)
        fake_proc_request = types.SimpleNamespace(stdin=_FakeStdin(), stdout=_FakeStdout(['{"ok": true, "results": []}\n']), poll=lambda: None)
        with (
            mock.patch.object(runtime_region_rating.socket, "create_connection", return_value=fake_socket),
            mock.patch.object(runtime_region_rating, "_region_grow_daemon_port", return_value=18765),
        ):
            payload = runtime_region_rating._rg_daemon_request(req={"cmd": "ping"}, timeout_s=1.0)
        self.assertEqual(payload, {"ok": True})
        self.assertTrue(fake_socket.sent and b'"cmd": "ping"' in fake_socket.sent[0])

        with (
            mock.patch.object(runtime_region_rating, "_rg_daemon_request", return_value={"ok": True}),
            mock.patch.object(runtime_region_rating.subprocess, "Popen") as popen_mock,
        ):
            ok = runtime_region_rating._ensure_region_grow_daemon(
                python_path=Path("C:/python.exe"),
                region_grow_script=Path("region_grow.py"),
                root=Path("."),
                env={"A": "1"},
                subprocess_kw={},
                log=mock.Mock(),
            )
        self.assertTrue(ok)
        popen_mock.assert_not_called()

        with (
            mock.patch.object(runtime_region_rating.subprocess, "Popen", return_value=fake_proc_worker) as popen_mock,
            mock.patch.object(runtime_region_rating, "lower_process_to_normal"),
            mock.patch.object(runtime_region_rating.time, "perf_counter", side_effect=[0.0, 0.0, 0.5, 0.5]),
        ):
            proc = runtime_region_rating._ensure_region_grow_worker(
                python_path=Path("C:/python.exe"),
                region_grow_script=Path("region_grow.py"),
                root=Path("."),
                env={"A": "1"},
                subprocess_kw={},
                region_grow_timeout=1.0,
                advanced_debug=False,
                log=mock.Mock(),
            )
        self.assertIs(proc, fake_proc_worker)
        popen_mock.assert_called_once()

        with mock.patch.object(runtime_region_rating.time, "perf_counter", side_effect=[0.0, 0.0, 0.1]):
            payload = runtime_region_rating._run_region_grow_worker_request(
                proc=fake_proc_request,
                image_path=Path("screen.png"),
                region_grow_timeout=1.0,
                advanced_debug=False,
                target_side=1280,
                log=mock.Mock(),
            )
        self.assertEqual(payload, {"ok": True, "results": []})
        self.assertTrue(fake_proc_request.stdin.writes and '"target_side": 1280' in fake_proc_request.stdin.writes[0])

