    def test_rating_cookie_context_and_scores_distinguish_accept_and_reject(self) -> None:
        cookie_banner = {"bbox": [0, 0, 320, 80], "text": "We use cookies to improve the site"}
        accept = {"bbox": [18, 18, 88, 42], "text": "Accept cookies", "is_button": True}
        reject = {"bbox": [98, 18, 178, 42], "text": "Reject cookies", "is_button": True}
        with mock.patch.object(rating_mod, "combine_scores", side_effect=lambda vals: max(vals) if vals else 0.0):
            self.assertTrue(rating_mod.find_cookie_context_nearby(accept, [accept, cookie_banner]))
            self.assertTrue(rating_mod.find_cookie_context_nearby(reject, [reject, cookie_banner]))
            accept_score = rating_mod.score_cookie_accept(accept, [accept, reject, cookie_banner], [])
            reject_score = rating_mod.score_cookie_reject(reject, [accept, reject, cookie_banner], [])
        self.assertGreater(accept_score, 0.0)
        self.assertGreater(reject_score, 0.0)
        self.assertGreaterEqual(accept_score, reject_score)

