    def test_quiz_ai_inputs_prompt_signals_and_structural_tokens(self) -> None:
        signals = build_prompt_artifact_signals(
            region_payload={"results": [{"text": "Pick one of 3 options"}]},
            summary_data={"question_candidate": {"text": "Choose one"}},
            rated_data={"elements": [{"text": "Mix and match"}]},
            questions=[{"question_text": "Select all that apply"}],
            active={"prompt_text": "Use the slider below"},
            prompt_triple=("pick one",),
            prompt_mix=("mix",),
            prompt_slider=("slider",),
            prompt_scroll=("scroll",),
            prompt_multi=("select all",),
        )
        self.assertTrue(signals["triple_hint"])
        self.assertGreaterEqual(signals["triple_token_count"], 1)
        self.assertTrue(signals["mix_hint"])
        self.assertTrue(signals["slider_hint"])
        self.assertTrue(signals["multi_hint"])
        self.assertTrue(has_structural_prompt_tokens("1. choose one", prompt_triple=("1.",), prompt_mix=("mix",)))
        self.assertFalse(has_structural_prompt_tokens("", prompt_triple=("1.",), prompt_mix=("mix",)))
        self.assertTrue(
            items_have_structural_tokens(
                [{"text": "A. first"}],
                summary_data={"question_candidate": {"text": "B. second"}},
                prompt_triple=("a.", "b."),
                prompt_mix=("mix",),
            )
        )

