        self.assertEqual(quiz_type_features_mod.infer_block_type(
            block={"control_kind": "slider", "prompt_text": "Use the slider"},
            global_marker_stats=marker_stats,
            prompt_multi=("select all",),
            prompt_scroll=("scroll",),
            prompt_triple=("triple",),
            prompt_mix=("mix",),
            prompt_text=("type",),
            prompt_slider=("slider",),
        ), "slider")
        logits, evidence, feature_values, block_types = quiz_type_features_mod.build_heuristic_quiz_features(
            active={"control_kind": "dropdown", "prompt_text": "Select one", "select_bbox": [0, 0, 10, 10]},
            questions=[{"control_kind": "dropdown", "prompt_text": "Select one", "select_bbox": [0, 0, 10, 10]}],
            marker_stats=marker_stats,
            quiz_types=("single", "multi", "dropdown", "dropdown_scroll", "text", "slider", "triple", "mixed"),
            prompt_multi=("select all",),
            prompt_scroll=("scroll",),
            prompt_triple=("triple",),
            prompt_mix=("mix",),
            prompt_text=("type",),
            prompt_slider=("slider",),
        )
        self.assertIn("dropdown", logits)
        self.assertIn("question_count", feature_values)
        self.assertIn("control_kind", evidence)
        self.assertEqual(block_types, ["dropdown"])

