    def test_runtime_region_rating_build_fast_summary_preserves_background_and_core_candidates(self) -> None:
        tmp_dir = Path("tmp_test_runtime_fast_summary_contract")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            image_path = tmp_dir / "screen.png"
            auto_main.Image.new("RGB", (800, 600), color="white").save(image_path)
            payload = {
                "background_layout": {
                    "main_cluster_id": 1,
                    "clusters": [{"id": 1, "mean_rgb": [245, 245, 245]}],
                },
                "results": [
                    {"id": "q1", "text": "Wybierz kolor", "conf": 0.92, "bbox": [100, 80, 420, 128]},
                    {"id": "a1", "text": "Zielony", "conf": 0.88, "bbox": [120, 170, 280, 214]},
                    {"id": "dd1", "text": "Wybierz z listy", "conf": 0.79, "dropdown_box": [110, 250, 420, 304]},
                    {"id": "n1", "text": "Dalej", "conf": 0.91, "bbox": [540, 470, 700, 520]},
                ],
            }

            summary = runtime_region_rating._build_fast_summary(payload, image_path)

            self.assertEqual(summary["background_layout"]["main_cluster_id"], 1)
            self.assertIsNotNone(summary.get("question_candidate"))
            self.assertEqual(summary["question_candidate"]["text"], "Wybierz kolor")
            self.assertGreaterEqual(len(summary.get("answer_candidate_boxes") or []), 1)
            self.assertGreaterEqual(len(summary.get("dropdown_candidate_boxes") or []), 1)
            self.assertGreaterEqual(len(summary.get("next_candidate_boxes") or []), 1)
            self.assertFalse(summary["summary_truth_suspicion_flag"]["is_suspicious"])
            self.assertEqual(summary["summary_truth_suspicion_flag"]["reason"], "summary_semantics_ok")
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def test_runtime_region_rating_build_fast_summary_marks_summary_truth_suspicion_for_empty_top_labels(self) -> None:
        tmp_dir = Path("tmp_test_runtime_fast_summary_suspicion")
        if tmp_dir.exists():
            shutil.rmtree(tmp_dir)
        tmp_dir.mkdir(parents=True)
        try:
            image_path = tmp_dir / "screen.png"
            auto_main.Image.new("RGB", (800, 600), color="white").save(image_path)
            payload = {
                "background_layout": {},
                "results": [
                    {"id": "noise1", "text": "Home", "conf": 0.52, "bbox": [100, 20, 220, 48]},
                    {"id": "noise2", "text": "Docs", "conf": 0.49, "bbox": [250, 22, 340, 46]},
                ],
            }

            summary = runtime_region_rating._build_fast_summary(payload, image_path)

            self.assertTrue(summary["summary_truth_suspicion_flag"]["is_suspicious"])
            self.assertEqual(summary["summary_truth_suspicion_flag"]["reason"], "empty_top_labels")
            self.assertFalse(summary["summary_truth_suspicion_flag"]["signals"]["has_top_labels"])
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)


